  ensureColumn(db, "portal_training_attendance", "contact_id", "INTEGER");
  ensureColumn(db, "portal_training_attendance", "contact_uid", "TEXT");
  ensureColumn(db, "portal_training_attendance", "role_at_time", "TEXT");
