      id: number;
      slug: string;
      title: string;
      description: string;
      grade: PortalResourceRecord["grade"];
      skill: PortalResourceRecord["skill"];
      type: PortalResourceRecord["type"];
      section: PortalResourceSection;
      fileName: string | null;
      storedPath: string | null;
