export function createPortalUserAccount(
  input: {
    fullName: string;
    email: string;
    phone?: string;
    role: PortalUserRole;
    password: string;
    isSupervisor?: boolean;
    isME?: boolean;
    isAdmin?: boolean;
    isSuperAdmin?: boolean;
  },
  currentUser: PortalUser,
) {
  if (!canManagePortalUsers(currentUser)) {
    throw new Error("Unauthorized");
  }

  const normalizedEmail = input.email.trim().toLowerCase();
  const fullName = input.fullName.trim();
  if (!normalizedEmail || !fullName) {
    throw new Error("Full name and email are required.");
  }
  const isVolunteer = input.role === "Volunteer";

  const result = getDb()
    .prepare(
      `
      INSERT INTO portal_users (
        full_name,
        email,
        phone,
        role,
        password_hash,
        is_supervisor,
        is_me,
        is_admin,
        is_superadmin
      ) VALUES (
        @fullName,
        @email,
        @phone,
        @role,
        @passwordHash,
        @isSupervisor,
        @isME,
        @isAdmin,
        @isSuperAdmin
      )
    `,
    )
    .run({
      fullName,
      email: normalizedEmail,
      phone: input.phone?.trim() ? input.phone.trim() : null,
      role: input.role,
      passwordHash: hashPassword(input.password),
      isSupervisor: !isVolunteer && input.isSupervisor ? 1 : 0,
      isME: !isVolunteer && input.isME ? 1 : 0,
      isAdmin: !isVolunteer && input.isAdmin ? 1 : 0,
      isSuperAdmin: !isVolunteer && input.isSuperAdmin ? 1 : 0,
    });

  return Number(result.lastInsertRowid);
}

export function updatePortalUserPermissions(
  userId: number,
  input: {
    fullName?: string;
    phone?: string | null;
    role?: PortalUserRole;
    isSupervisor?: boolean;
    isME?: boolean;
    isAdmin?: boolean;
    isSuperAdmin?: boolean;
    password?: string;
  },
  currentUser: PortalUser,
) {
  if (!canManagePortalUsers(currentUser)) {
    throw new Error("Unauthorized");
  }

  const target = getDb()
    .prepare(
      `
      SELECT
        id,
        role,
        is_superadmin AS isSuperAdmin
      FROM portal_users
      WHERE id = @userId
      LIMIT 1
    `,
    )
    .get({ userId }) as { id: number; role: PortalUserRole; isSuperAdmin: number } | undefined;

  if (!target) {
    throw new Error("User not found.");
  }

  if (
    target.id === currentUser.id &&
    (input.isSuperAdmin === false || input.role === "Volunteer")
  ) {
    throw new Error("You cannot remove your own super admin access.");
  }

  const updates: string[] = [];
  const params: Record<string, unknown> = { userId };
  const nextRole = input.role ?? target.role;
  const forceVolunteerPermissions = input.role === "Volunteer";

  if (typeof input.fullName === "string") {
    updates.push("full_name = @fullName");
    params.fullName = input.fullName.trim();
  }
  if (input.phone !== undefined) {
    updates.push("phone = @phone");
    params.phone = input.phone?.trim() ? input.phone.trim() : null;
  }
  if (input.role) {
    updates.push("role = @role");
    params.role = input.role;
  }
  if (input.isSupervisor !== undefined) {
    updates.push("is_supervisor = @isSupervisor");
    params.isSupervisor = forceVolunteerPermissions ? 0 : input.isSupervisor ? 1 : 0;
  }
  if (input.isME !== undefined) {
    updates.push("is_me = @isME");
    params.isME = forceVolunteerPermissions ? 0 : input.isME ? 1 : 0;
  }
  if (input.isAdmin !== undefined) {
    updates.push("is_admin = @isAdmin");
    params.isAdmin = forceVolunteerPermissions ? 0 : input.isAdmin ? 1 : 0;
  }
  if (input.isSuperAdmin !== undefined) {
    updates.push("is_superadmin = @isSuperAdmin");
    params.isSuperAdmin = forceVolunteerPermissions ? 0 : input.isSuperAdmin ? 1 : 0;
  }
  if (input.password) {
    updates.push("password_hash = @passwordHash");
    params.passwordHash = hashPassword(input.password);
  }

  if (nextRole === "Volunteer") {
    if (!updates.includes("is_supervisor = @isSupervisor")) {
      updates.push("is_supervisor = @isSupervisor");
      params.isSupervisor = 0;
    }
    if (!updates.includes("is_me = @isME")) {
      updates.push("is_me = @isME");
      params.isME = 0;
    }
    if (!updates.includes("is_admin = @isAdmin")) {
      updates.push("is_admin = @isAdmin");
      params.isAdmin = 0;
    }
    if (!updates.includes("is_superadmin = @isSuperAdmin")) {
      updates.push("is_superadmin = @isSuperAdmin");
      params.isSuperAdmin = 0;
    }
  }

  if (updates.length === 0) {
    return;
  }

  getDb()
    .prepare(
      `
      UPDATE portal_users
      SET ${updates.join(", ")}
      WHERE id = @userId
    `,
    )
    .run(params);
}

function tableExists(tableName: string) {
  const row = getDb()
    .prepare(
      `
      SELECT name
      FROM sqlite_master
      WHERE type = 'table'
        AND name = @tableName
      LIMIT 1
    `,
    )
    .get({ tableName }) as { name?: string } | undefined;

  return Boolean(row?.name);
}

export function deletePortalUserAccount(userId: number, currentUser: PortalUser) {
  if (!canManagePortalUsers(currentUser)) {
    throw new Error("Unauthorized");
  }

  const db = getDb();
  const target = db
    .prepare(
      `
      SELECT
        id,
        full_name AS fullName,
        is_superadmin AS isSuperAdmin
      FROM portal_users
      WHERE id = @userId
      LIMIT 1
    `,
    )
    .get({ userId }) as { id: number; fullName: string; isSuperAdmin: number } | undefined;

  if (!target) {
    throw new Error("User not found.");
  }

  if (target.id === currentUser.id) {
    throw new Error("You cannot delete your own account.");
  }

  if (target.isSuperAdmin) {
    const remainingSuperAdmins = db
      .prepare(
        `
        SELECT COUNT(*) AS total
        FROM portal_users
        WHERE is_superadmin = 1
          AND id != @userId
      `,
      )
      .get({ userId }) as { total: number };

    if (Number(remainingSuperAdmins.total ?? 0) <= 0) {
      throw new Error("At least one super admin account must remain.");
    }
  }

  const dependencyChecks: Array<{ label: string; query: string }> = [
    {
      label: "portal records",
      query:
        "SELECT COUNT(*) AS total FROM portal_records WHERE created_by_user_id = @userId OR updated_by_user_id = @userId",
    },
    {
      label: "evidence uploads",
      query: "SELECT COUNT(*) AS total FROM portal_evidence WHERE uploaded_by_user_id = @userId",
    },
    {
      label: "training sessions",
      query: "SELECT COUNT(*) AS total FROM training_sessions WHERE created_by_user_id = @userId",
    },
    {
      label: "assessment records",
      query: "SELECT COUNT(*) AS total FROM assessment_records WHERE created_by_user_id = @userId",
    },
    {
      label: "online trainings",
      query: "SELECT COUNT(*) AS total FROM online_training_events WHERE created_by_user_id = @userId",
    },
    {
      label: "testimonials",
      query: "SELECT COUNT(*) AS total FROM portal_testimonials WHERE created_by_user_id = @userId",
    },
    {
      label: "resources",
      query: "SELECT COUNT(*) AS total FROM portal_resources WHERE created_by_user_id = @userId",
    },

    {
      label: "impact reports",
      query: "SELECT COUNT(*) AS total FROM impact_reports WHERE created_by_user_id = @userId",
    },
  ];

  const linkedData: string[] = [];
  for (const check of dependencyChecks) {
    const tableName = check.query.match(/FROM\s+([a-zA-Z0-9_]+)/i)?.[1];
    if (tableName && !tableExists(tableName)) {
      continue;
    }
    const row = db.prepare(check.query).get({ userId }) as { total: number } | undefined;
    if (Number(row?.total ?? 0) > 0) {
      linkedData.push(check.label);
    }
  }

  if (linkedData.length > 0) {
    throw new Error(
      `Cannot delete this account because it has linked data (${linkedData.join(", ")}).`,
    );
  }

  const transaction = db.transaction(() => {
    db.prepare("DELETE FROM portal_sessions WHERE user_id = @userId").run({ userId });
    db.prepare("DELETE FROM portal_users WHERE id = @userId").run({ userId });
  });

  transaction();
}

export function authenticatePortalUser(identifier: string, password: string): PortalUser | null {
  const normalizedIdentifier = identifier.trim();
  const normalizedEmail = normalizedIdentifier.toLowerCase();
  const row = getDb()
    .prepare(
      `
      SELECT
        id,
        full_name AS fullName,
        email,
        phone,
        role,
        geography_scope AS geographyScope,
        is_supervisor AS isSupervisor,
        is_me AS isME,
        is_admin AS isAdmin,
        is_superadmin AS isSuperAdmin,
        password_hash AS passwordHash
      FROM portal_users
      WHERE lower(email) = @email
         OR phone = @phone
      LIMIT 1
    `,
    )
    .get({ email: normalizedEmail, phone: normalizedIdentifier }) as
    | {
      id: number;
      fullName: string;
      email: string;
      phone: string | null;
      role: PortalUserRole;
      geographyScope: string | null;
      isSupervisor: number;
      isME: number;
      isAdmin: number;
      isSuperAdmin: number;
      passwordHash: string;
    }
    | undefined;

  if (!row) {
    return null;
  }

  if (row.passwordHash !== hashPassword(password)) {
    return null;
  }

  return parsePortalUserRow(row);
}

export function createPortalSession(userId: number) {
  const token = crypto.randomBytes(32).toString("hex");
  const expiresAt = new Date(Date.now() + SESSION_MAX_AGE_SECONDS * 1000).toISOString();

  getDb()
    .prepare(
      `
      INSERT INTO portal_sessions (
        user_id,
        token,
        expires_at
      ) VALUES (
        @userId,
        @token,
        @expiresAt
      )
    `,
    )
    .run({ userId, token, expiresAt });

  return {
    token,
    expiresAt,
    maxAge: SESSION_MAX_AGE_SECONDS,
  };
}

export function getPortalUserFromSession(token: string): PortalUser | null {
  const db = getDb();

  db.prepare("DELETE FROM portal_sessions WHERE datetime(expires_at) <= datetime('now')").run();

  const row = db
    .prepare(
      `
      SELECT
        u.id,
        u.full_name AS fullName,
        u.email,
        u.phone,
        u.role,
        u.geography_scope AS geographyScope,
        u.is_supervisor AS isSupervisor,
        u.is_me AS isME,
        u.is_admin AS isAdmin,
        u.is_superadmin AS isSuperAdmin
      FROM portal_sessions s
      JOIN portal_users u ON u.id = s.user_id
      WHERE s.token = @token
        AND datetime(s.expires_at) > datetime('now')
      LIMIT 1
    `,
    )
    .get({ token }) as
    | {
      id: number;
      fullName: string;
      email: string;
      phone: string | null;
      role: PortalUserRole;
      geographyScope: string | null;
      isSupervisor: number;
      isME: number;
      isAdmin: number;
      isSuperAdmin: number;
    }
    | undefined;

  if (!row) {
    return null;
  }

  return parsePortalUserRow(row);
}

export function deletePortalSession(token: string) {
  getDb().prepare("DELETE FROM portal_sessions WHERE token = @token").run({ token });
}

function normalizePersonName(value: string) {
  return value.trim().replace(/\s+/g, " ");
}

function findTeacherRosterByName(
  db: Database.Database,
  schoolId: number,
  fullName: string,
): TeacherRosterRecord | null {
  const row = db
    .prepare(
      `
      SELECT
        teacher_uid AS teacherUid,
        school_id AS schoolId,
        full_name AS fullName,
        gender,
        is_reading_teacher AS isReadingTeacher,
        phone,
        status,
        created_at AS createdAt,
        updated_at AS updatedAt
      FROM teacher_roster
      WHERE school_id = @schoolId
        AND lower(trim(full_name)) = lower(trim(@fullName))
      LIMIT 1
    `,
    )
    .get({ schoolId, fullName }) as
    | {
      teacherUid: string;
      schoolId: number;
      fullName: string;
      gender: "Male" | "Female";
      isReadingTeacher: number;
      phone: string | null;
      status: "active" | "inactive";
      createdAt: string;
      updatedAt: string;
    }
    | undefined;

  if (!row) {
    return null;
  }

  return {
    teacherUid: row.teacherUid,
    schoolId: Number(row.schoolId),
    fullName: row.fullName,
    gender: row.gender,
    isReadingTeacher: Boolean(row.isReadingTeacher),
    phone: row.phone ?? undefined,
    status: row.status,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
  };
}

function ensureSchoolContactForTeacher(db: Database.Database, teacher: TeacherRosterRecord) {
  const existing = db
    .prepare(
      `
        SELECT contact_id AS contactId
        FROM school_contacts
        WHERE teacher_uid = @teacherUid
        LIMIT 1
      `,
    )
    .get({ teacherUid: teacher.teacherUid }) as { contactId: number } | undefined;

  if (existing?.contactId) {
    db.prepare(
      `
        UPDATE school_contacts
        SET
          school_id = @schoolId,
          full_name = @fullName,
          gender = @gender,
          phone = @phone,
          category = 'Teacher',
          role_title = @roleTitle,
          class_taught = COALESCE(NULLIF(class_taught, ''), 'Not assigned'),
          subject_taught = COALESCE(NULLIF(subject_taught, ''), 'Not assigned'),
          updated_at = datetime('now')
        WHERE contact_id = @contactId
      `,
    ).run({
      contactId: existing.contactId,
      schoolId: teacher.schoolId,
      fullName: teacher.fullName,
      gender: teacher.gender,
      phone: teacher.phone?.trim() ? teacher.phone.trim() : null,
      roleTitle: teacher.isReadingTeacher ? "Reading Teacher" : "Teacher",
    });
    return;
  }

  db.prepare(
    `
      INSERT INTO school_contacts (
        contact_uid,
        school_id,
        full_name,
        gender,
        phone,
        email,
        whatsapp,
        category,
        role_title,
        is_primary_contact,
        class_taught,
        subject_taught,
        teacher_uid,
        created_at,
        updated_at
      ) VALUES (
        @contactUid,
        @schoolId,
        @fullName,
        @gender,
        @phone,
        NULL,
        NULL,
        'Teacher',
        @roleTitle,
        0,
        'Not assigned',
        'Not assigned',
        @teacherUid,
        datetime('now'),
        datetime('now')
      )
    `,
  ).run({
    contactUid: teacher.teacherUid,
    schoolId: teacher.schoolId,
    fullName: teacher.fullName,
    gender: teacher.gender,
    phone: teacher.phone?.trim() ? teacher.phone.trim() : null,
    roleTitle: teacher.isReadingTeacher ? "Reading Teacher" : "Teacher",
    teacherUid: teacher.teacherUid,
  });
}

export function createTeacherRosterRecord(input: TeacherRosterInput): TeacherRosterRecord {
  const db = getDb();
  const fullName = normalizePersonName(input.fullName);
  if (!fullName) {
    throw new Error("Teacher full name is required.");
  }

  const existing = findTeacherRosterByName(db, input.schoolId, fullName);
  if (existing) {
    db.prepare(
      `
      UPDATE teacher_roster
      SET
        gender = @gender,
        is_reading_teacher = @isReadingTeacher,
        phone = @phone,
        updated_at = datetime('now')
      WHERE teacher_uid = @teacherUid
    `,
    ).run({
      teacherUid: existing.teacherUid,
      gender: input.gender,
      isReadingTeacher: input.isReadingTeacher ? 1 : 0,
      phone: input.phone?.trim() ? input.phone.trim() : null,
    });

    const updated = findTeacherRosterByName(db, input.schoolId, fullName);
    if (!updated) {
      throw new Error("Could not load teacher record.");
    }
    ensureSchoolContactForTeacher(db, updated);
    return updated;
  }

  const teacherUid = nextShortCode(db, "teacher_roster", "teacher_uid", "TR-", 4);
  db.prepare(
    `
    INSERT INTO teacher_roster (
      teacher_uid,
      school_id,
      full_name,
      gender,
      is_reading_teacher,
      phone,
      status
    ) VALUES (
      @teacherUid,
      @schoolId,
      @fullName,
      @gender,
      @isReadingTeacher,
      @phone,
      'active'
    )
  `,
  ).run({
    teacherUid,
    schoolId: input.schoolId,
    fullName,
    gender: input.gender,
    isReadingTeacher: input.isReadingTeacher ? 1 : 0,
    phone: input.phone?.trim() ? input.phone.trim() : null,
  });

  const created = findTeacherRosterByName(db, input.schoolId, fullName);
  if (!created) {
    throw new Error("Could not load teacher record.");
  }
  ensureSchoolContactForTeacher(db, created);
  return created;
}

function findLearnerRosterRecord(
  db: Database.Database,
  input: LearnerRosterInput,
): LearnerRosterRecord | null {
  const normalizedName = normalizePersonName(input.fullName);
  const row = db
    .prepare(
      `
      SELECT
        learner_uid AS learnerUid,
        school_id AS schoolId,
        full_name AS fullName,
        internal_child_id AS internalChildId,
        gender,
        age,
        class_grade AS classGrade,
        consent_flag AS consentFlag,
        created_at AS createdAt,
        updated_at AS updatedAt
      FROM learner_roster
      WHERE school_id = @schoolId
        AND class_grade = @classGrade
        AND lower(trim(full_name)) = lower(trim(@fullName))
      LIMIT 1
    `,
    )
    .get({
      schoolId: input.schoolId,
      classGrade: input.classGrade,
      fullName: normalizedName,
    }) as
    | {
      learnerUid: string;
      schoolId: number;
      fullName: string;
      internalChildId: string | null;
      gender: "Boy" | "Girl" | "Other";
      age: number;
      classGrade: string;
      consentFlag: number;
      createdAt: string;
      updatedAt: string;
    }
    | undefined;

  if (!row) {
    return null;
  }

  return {
    learnerUid: row.learnerUid,
    schoolId: Number(row.schoolId),
    fullName: row.fullName,
    internalChildId: row.internalChildId ?? undefined,
    gender: row.gender,
    age: Number(row.age),
    classGrade: row.classGrade,
    consentFlag: Boolean(row.consentFlag),
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
  };
}

function ensureSchoolLearnerMirror(db: Database.Database, learner: LearnerRosterRecord) {
  const existing = db
    .prepare(
      `
        SELECT learner_id AS learnerId
        FROM school_learners
        WHERE learner_uid = @learnerUid
        LIMIT 1
      `,
    )
    .get({ learnerUid: learner.learnerUid }) as { learnerId: number } | undefined;

  if (existing?.learnerId) {
    db.prepare(
      `
        UPDATE school_learners
        SET
          school_id = @schoolId,
          learner_name = @learnerName,
          class_grade = @classGrade,
          age = @age,
          gender = @gender,
          internal_child_id = @internalChildId,
          updated_at = datetime('now')
        WHERE learner_id = @learnerId
      `,
    ).run({
      learnerId: existing.learnerId,
      schoolId: learner.schoolId,
      learnerName: learner.fullName,
      classGrade: learner.classGrade,
      age: learner.age,
      gender: learner.gender,
      internalChildId: learner.internalChildId?.trim() || null,
    });
    return;
  }

  db.prepare(
    `
      INSERT INTO school_learners (
        learner_uid,
        school_id,
        learner_name,
        class_grade,
        age,
        gender,
        internal_child_id,
        created_at,
        updated_at
      ) VALUES (
        @learnerUid,
        @schoolId,
        @learnerName,
        @classGrade,
        @age,
        @gender,
        @internalChildId,
        datetime('now'),
        datetime('now')
      )
    `,
  ).run({
    learnerUid: learner.learnerUid,
    schoolId: learner.schoolId,
    learnerName: learner.fullName,
    classGrade: learner.classGrade,
    age: learner.age,
    gender: learner.gender,
    internalChildId: learner.internalChildId?.trim() || null,
  });
}

export function createOrUpdateLearnerRosterRecord(input: LearnerRosterInput): LearnerRosterRecord {
  const db = getDb();
  const normalizedName = normalizePersonName(input.fullName);
  if (!normalizedName) {
    throw new Error("Learner name is required.");
  }

  const existing = findLearnerRosterRecord(db, { ...input, fullName: normalizedName });
  if (existing) {
    db.prepare(
      `
      UPDATE learner_roster
      SET
        internal_child_id = @internalChildId,
        gender = @gender,
        age = @age,
        class_grade = @classGrade,
        consent_flag = @consentFlag,
        updated_at = datetime('now')
      WHERE learner_uid = @learnerUid
    `,
    ).run({
      learnerUid: existing.learnerUid,
      internalChildId: input.internalChildId?.trim() ? input.internalChildId.trim() : null,
      gender: input.gender,
      age: Math.max(3, Math.min(25, Math.floor(Number(input.age)))),
      classGrade: input.classGrade,
      consentFlag: input.consentFlag ? 1 : 0,
    });
    const updated = findLearnerRosterRecord(db, { ...input, fullName: normalizedName });
    if (!updated) {
      throw new Error("Could not load learner record.");
    }
    ensureSchoolLearnerMirror(db, updated);
    return updated;
  }

  const learnerUid = nextShortCode(db, "learner_roster", "learner_uid", "LR-", 4);
  db.prepare(
    `
    INSERT INTO learner_roster (
      learner_uid,
      school_id,
      full_name,
      internal_child_id,
      gender,
      age,
      class_grade,
      consent_flag
    ) VALUES (
      @learnerUid,
      @schoolId,
      @fullName,
      @internalChildId,
      @gender,
      @age,
      @classGrade,
      @consentFlag
    )
  `,
  ).run({
    learnerUid,
    schoolId: input.schoolId,
    fullName: normalizedName,
    internalChildId: input.internalChildId?.trim() ? input.internalChildId.trim() : null,
    gender: input.gender,
    age: Math.max(3, Math.min(25, Math.floor(Number(input.age)))),
    classGrade: input.classGrade,
    consentFlag: input.consentFlag ? 1 : 0,
  });

  const created = findLearnerRosterRecord(db, { ...input, fullName: normalizedName });
  if (!created) {
    throw new Error("Could not load learner record.");
  }
  ensureSchoolLearnerMirror(db, created);
  return created;
}

export function saveTrainingSession(payload: TrainingSessionInput, createdByUserId: number) {
  const db = getDb();

  const linkedSchool = db
    .prepare(
      `
      SELECT id
      FROM schools_directory
      WHERE lower(trim(name)) = lower(trim(@schoolName))
        AND lower(trim(district)) = lower(trim(@district))
      LIMIT 1
    `,
    )
    .get({
      schoolName: payload.schoolName,
      district: payload.district,
    }) as { id: number } | undefined;

  const insertSession = db.prepare(`
    INSERT INTO training_sessions (
      school_name,
      district,
      sub_county,
      parish,
      village,
      session_date,
      created_by_user_id
    ) VALUES (
      @schoolName,
      @district,
      @subCounty,
      @parish,
      @village,
      @sessionDate,
      @createdByUserId
    )
  `);

  const insertParticipant = db.prepare(`
    INSERT INTO training_participants (
      session_id,
      participant_name,
      participant_role,
      phone,
      email,
      school_id,
      teacher_uid,
      gender
    ) VALUES (
      @sessionId,
      @name,
      @role,
      @phone,
      @email,
      @schoolId,
      @teacherUid,
      @gender
    )
  `);

  const transaction = db.transaction((input: TrainingSessionInput, userId: number) => {
    const sessionInsert = insertSession.run({
      schoolName: input.schoolName,
      district: input.district,
      subCounty: input.subCounty,
      parish: input.parish,
      village: input.village?.trim() ? input.village : null,
      sessionDate: input.sessionDate,
      createdByUserId: userId,
    });

    const sessionId = Number(sessionInsert.lastInsertRowid);

    input.participants.forEach((participant) => {
      const participantSchoolId =
        participant.schoolId && participant.schoolId > 0
          ? participant.schoolId
          : linkedSchool?.id ?? null;
      let teacherUid: string | null = null;
      if (
        participantSchoolId &&
        participant.role === "Classroom teacher" &&
        (participant.gender === "Male" || participant.gender === "Female")
      ) {
        const teacher = createTeacherRosterRecord({
          schoolId: participantSchoolId,
          fullName: participant.name,
          gender: participant.gender,
          isReadingTeacher: true,
          phone: participant.phone,
        });
        teacherUid = teacher.teacherUid;
      }

      insertParticipant.run({
        sessionId,
        name: participant.name,
        role: participant.role,
        phone: participant.phone,
        email: participant.email,
        schoolId: participantSchoolId,
        teacherUid,
        gender: participant.gender ?? null,
      });
    });

    return sessionId;
  });

  const sessionId = transaction(payload, createdByUserId);

  const row = db
    .prepare(
      `
      SELECT
        ts.id,
        ts.school_name AS schoolName,
        ts.district,
        ts.sub_county AS subCounty,
        ts.parish,
        ts.village,
        ts.session_date AS sessionDate,
        ts.created_at AS createdAt,
        COUNT(tp.id) AS participantCount,
        SUM(CASE WHEN tp.participant_role = 'Classroom teacher' THEN 1 ELSE 0 END) AS classroomTeachers,
        SUM(CASE WHEN tp.participant_role = 'School Leader' THEN 1 ELSE 0 END) AS schoolLeaders
      FROM training_sessions ts
      LEFT JOIN training_participants tp ON tp.session_id = ts.id
      WHERE ts.id = @sessionId
      GROUP BY ts.id
      LIMIT 1
    `,
    )
    .get({ sessionId }) as TrainingSessionRecord | undefined;

  if (!row) {
    throw new Error("Could not load saved training session.");
  }

  return {
    ...row,
    participantCount: Number(row.participantCount ?? 0),
    classroomTeachers: Number(row.classroomTeachers ?? 0),
    schoolLeaders: Number(row.schoolLeaders ?? 0),
  };
}

export function listTrainingSessions(limit = 20): TrainingSessionRecord[] {
  const rows = getDb()
    .prepare(
      `
      SELECT
        ts.id,
        ts.school_name AS schoolName,
        ts.district,
        ts.sub_county AS subCounty,
        ts.parish,
        ts.village,
        ts.session_date AS sessionDate,
        ts.created_at AS createdAt,
        COUNT(tp.id) AS participantCount,
        SUM(CASE WHEN tp.participant_role = 'Classroom teacher' THEN 1 ELSE 0 END) AS classroomTeachers,
        SUM(CASE WHEN tp.participant_role = 'School Leader' THEN 1 ELSE 0 END) AS schoolLeaders
      FROM training_sessions ts
      LEFT JOIN training_participants tp ON tp.session_id = ts.id
      GROUP BY ts.id
      ORDER BY ts.session_date DESC, ts.id DESC
      LIMIT @limit
    `,
    )
    .all({ limit }) as TrainingSessionRecord[];

  return rows.map((row) => ({
    ...row,
    participantCount: Number(row.participantCount ?? 0),
    classroomTeachers: Number(row.classroomTeachers ?? 0),
    schoolLeaders: Number(row.schoolLeaders ?? 0),
  }));
}

export function saveAssessmentRecord(payload: AssessmentRecordInput, createdByUserId: number) {
  const db = getDb();

  const learnerRecord =
    payload.learnerUid && payload.learnerUid.trim()
      ? (db
        .prepare(
          `
            SELECT learner_uid AS learnerUid, school_id AS schoolId, full_name AS fullName,
                   internal_child_id AS internalChildId, gender, age, class_grade AS classGrade,
                   consent_flag AS consentFlag, created_at AS createdAt, updated_at AS updatedAt
            FROM learner_roster
            WHERE learner_uid = @learnerUid
            LIMIT 1
          `,
        )
        .get({ learnerUid: payload.learnerUid.trim() }) as LearnerRosterRecord | undefined) ?? null
      : createOrUpdateLearnerRosterRecord({
        schoolId: payload.schoolId,
        fullName: payload.childName,
        internalChildId: payload.childId?.trim() || undefined,
        gender: payload.gender,
        age: payload.age,
        classGrade: payload.classGrade,
        consentFlag: false,
      });

  if (!learnerRecord) {
    throw new Error("Could not resolve learner roster record.");
  }
  const masterySettings = getOneTestMasterySettings(db);
  const resolvedModelVersion = ASSESSMENT_MODEL_VERSION_UG_MASTERY_ONETEST_STYLE_V1;
  const isOneTestModel = isOneTestStyleModelVersion(resolvedModelVersion);
  const resolvedBenchmarkVersion = String(payload.benchmarkVersion ?? "").trim();
  const resolvedScoringProfileVersion = String(payload.scoringProfileVersion ?? "").trim();
  const domainInputs = parseDomainInputsFromUnknown(payload.masteryDomainInputs);
  const itemResponses = parseItemResponsesFromUnknown(payload.masteryItemResponses);

  const masteryComputation = isOneTestModel
    ? computeOneTestStyleMasteryAssessment({
      grade: payload.learnerExpectedGrade ?? payload.classGrade,
      age: payload.age,
      domainInputs,
      itemResponses,
      legacyScores: {
        letterIdentificationScore: payload.letterIdentificationScore,
        soundIdentificationScore: payload.soundIdentificationScore,
        decodableWordsScore: payload.decodableWordsScore,
        undecodableWordsScore: payload.undecodableWordsScore,
        madeUpWordsScore: payload.madeUpWordsScore,
        storyReadingScore: payload.storyReadingScore,
        readingComprehensionScore: payload.readingComprehensionScore,
        fluencyAccuracyScore: payload.fluencyAccuracyScore ?? null,
      },
      settings: masterySettings,
      modelVersion: resolvedModelVersion,
      benchmarkVersion: resolvedBenchmarkVersion || masterySettings.benchmarkVersion,
      scoringProfileVersion:
        resolvedScoringProfileVersion || masterySettings.scoringProfileVersion,
    })
    : null;

  const readingRuleSettings = getAssessmentReadingRuleSettings(db, {
    grade: payload.classGrade,
    language: "English",
    atDate: payload.assessmentDate,
  });
  const computedReading = computeAssessmentReadingLevel(
    {
      fluencyCwpm: payload.storyReadingScore,
      fluencyAccuracy: payload.fluencyAccuracyScore ?? null,
      comprehensionScore: payload.readingComprehensionScore,
    },
    readingRuleSettings,
  );
  const computedAt = new Date().toISOString();
  const computedReadingLevelForInsert = masteryComputation
    ? toLegacyReadingLabelFromStage(
      masteryComputation.readingStageOrder,
      masteryComputation.readingStageLabel,
    )
    : computedReading.computedReadingLevel;
  const computedLevelBandForInsert = masteryComputation
    ? stageBandFromOrder(masteryComputation.readingStageOrder)
    : computedReading.computedLevelBand;
  const readingRulesVersionForInsert = masteryComputation
    ? masteryComputation.modelVersion
    : computedReading.rulesVersion;

  const insertResult = db
    .prepare(
      `
      INSERT INTO assessment_records (
        learner_uid,
        child_name,
        child_id,
        gender,
        age,
        school_id,
        class_grade,
        assessment_date,
        assessment_type,
        letter_identification_score,
        sound_identification_score,
        decodable_words_score,
        undecodable_words_score,
        made_up_words_score,
        story_reading_score,
        fluency_accuracy_score,
        reading_comprehension_score,
        computed_reading_level,
        computed_level_band,
        reading_rules_version,
        reading_level_computed_at,
        notes,
        created_by_user_id
      ) VALUES (
        @learnerUid,
        @childName,
        @childId,
        @gender,
        @age,
        @schoolId,
        @classGrade,
        @assessmentDate,
        @assessmentType,
        @letterIdentificationScore,
        @soundIdentificationScore,
        @decodableWordsScore,
        @undecodableWordsScore,
        @madeUpWordsScore,
        @storyReadingScore,
        @fluencyAccuracyScore,
        @readingComprehensionScore,
        @computedReadingLevel,
        @computedLevelBand,
        @readingRulesVersion,
        @readingLevelComputedAt,
        @notes,
        @createdByUserId
      )
    `,
    )
    .run({
      learnerUid: learnerRecord.learnerUid,
      childName: learnerRecord.fullName,
      childId:
        payload.childId?.trim() ||
        learnerRecord.internalChildId ||
        `${learnerRecord.schoolId}-${learnerRecord.learnerUid.slice(-6)}`,
      gender: learnerRecord.gender,
      age: learnerRecord.age,
      schoolId: learnerRecord.schoolId,
      classGrade: learnerRecord.classGrade,
      assessmentDate: payload.assessmentDate,
      assessmentType: payload.assessmentType,
      letterIdentificationScore: payload.letterIdentificationScore,
      soundIdentificationScore: payload.soundIdentificationScore,
      decodableWordsScore: payload.decodableWordsScore,
      undecodableWordsScore: payload.undecodableWordsScore,
      madeUpWordsScore: payload.madeUpWordsScore,
      storyReadingScore: payload.storyReadingScore,
      fluencyAccuracyScore: payload.fluencyAccuracyScore ?? null,
      readingComprehensionScore: payload.readingComprehensionScore,
      computedReadingLevel: computedReadingLevelForInsert,
      computedLevelBand: computedLevelBandForInsert,
      readingRulesVersion: readingRulesVersionForInsert,
      readingLevelComputedAt: computedAt,
      notes: payload.notes?.trim() ? payload.notes : null,
      createdByUserId,
    });

  const assessmentId = Number(insertResult.lastInsertRowid);
  if (masteryComputation) {
    persistMasteryForAssessmentRecord({
      db,
      assessmentRecordId: assessmentId,
      mastery: masteryComputation,
      learnerExpectedGrade: payload.learnerExpectedGrade ?? payload.classGrade,
      computedAt,
    });
    replaceAssessmentItemResponses({
      db,
      learnerResultId: assessmentId,
      learnerUid: learnerRecord.learnerUid,
      mastery: masteryComputation,
    });
  } else {
    db.prepare(
      `
      UPDATE assessment_records
      SET
        model_version = @modelVersion,
        benchmark_version = @benchmarkVersion,
        scoring_profile_version = @scoringProfileVersion
      WHERE id = @assessmentId
      `,
    ).run({
      assessmentId,
      modelVersion: resolvedModelVersion || ASSESSMENT_LEGACY_MODEL_VERSION,
      benchmarkVersion: resolvedBenchmarkVersion || null,
      scoringProfileVersion: resolvedScoringProfileVersion || null,
    });
  }
  const row = db
    .prepare(
      `
      SELECT
        id,
        learner_uid AS learnerUid,
        child_name AS childName,
        child_id AS childId,
        gender,
        age,
        school_id AS schoolId,
        class_grade AS classGrade,
        assessment_date AS assessmentDate,
        assessment_type AS assessmentType,
        letter_identification_score AS letterIdentificationScore,
        sound_identification_score AS soundIdentificationScore,
        decodable_words_score AS decodableWordsScore,
        undecodable_words_score AS undecodableWordsScore,
        made_up_words_score AS madeUpWordsScore,
        story_reading_score AS storyReadingScore,
        fluency_accuracy_score AS fluencyAccuracyScore,
        reading_comprehension_score AS readingComprehensionScore,
        computed_reading_level AS computedReadingLevel,
        computed_level_band AS computedLevelBand,
        reading_rules_version AS readingRulesVersion,
        model_version AS assessmentModelVersion,
        reading_stage_label AS readingStageLabel,
        reading_stage_order AS readingStageOrder,
        benchmark_grade_level AS benchmarkGradeLevel,
        expected_vs_actual_status AS expectedVsActualStatus,
        stage_reason_code AS stageReasonCode,
        stage_reason_summary AS stageReasonSummary,
        mastery_profile_summary_json AS masteryProfileSummaryJson,
        notes,
        created_at AS createdAt
      FROM assessment_records
      WHERE id = @assessmentId
      LIMIT 1
    `,
    )
    .get({ assessmentId }) as AssessmentRecord | undefined;

  if (!row) {
    throw new Error("Could not load saved assessment record.");
  }

  upsertSchoolSupportStatusSnapshot(db, learnerRecord.schoolId);

  return { ...row, createdByUserId };
}

