export function saveOnlineTrainingEvent(
  payload: OnlineTrainingEventInput & {
    startDateTime: string;
    endDateTime: string;
    attendeeEmails: string[];
    calendarEventId?: string | null;
    calendarLink?: string | null;
    meetLink?: string | null;
  },
  createdByUserId: number,
): OnlineTrainingEventRecord {
  const db = getDb();
  const insertResult = db
    .prepare(
      `
      INSERT INTO online_training_events (
        title,
        description,
        audience,
        start_datetime,
        end_datetime,
        duration_minutes,
        attendee_emails,
        attendee_count,
        online_teachers_trained,
        online_school_leaders_trained,
        calendar_event_id,
        calendar_link,
        meet_link,
        created_by_user_id
      ) VALUES (
        @title,
        @description,
        @audience,
        @startDateTime,
        @endDateTime,
        @durationMinutes,
        @attendeeEmails,
        @attendeeCount,
        @onlineTeachersTrained,
        @onlineSchoolLeadersTrained,
        @calendarEventId,
        @calendarLink,
        @meetLink,
        @createdByUserId
      )
    `,
    )
    .run({
      title: payload.title,
      description: payload.description?.trim() ? payload.description : null,
      audience: payload.audience,
      startDateTime: payload.startDateTime,
      endDateTime: payload.endDateTime,
      durationMinutes: payload.durationMinutes,
      attendeeEmails: payload.attendeeEmails.join(","),
      attendeeCount: payload.attendeeEmails.length,
      onlineTeachersTrained: 0,
      onlineSchoolLeadersTrained: 0,
      calendarEventId: payload.calendarEventId ?? null,
      calendarLink: payload.calendarLink ?? null,
      meetLink: payload.meetLink ?? null,
      createdByUserId,
    });

  const eventId = Number(insertResult.lastInsertRowid);
  const row = db
    .prepare(
      `
      SELECT
        id,
        title,
        description,
        audience,
        start_datetime AS startDateTime,
        end_datetime AS endDateTime,
        duration_minutes AS durationMinutes,
        attendee_count AS attendeeCount,
        online_teachers_trained AS onlineTeachersTrained,
        online_school_leaders_trained AS onlineSchoolLeadersTrained,
        calendar_event_id AS calendarEventId,
        calendar_link AS calendarLink,
        meet_link AS meetLink,
        recording_url AS recordingUrl,
        chat_summary AS chatSummary,
        attendance_captured_at AS attendanceCapturedAt,
        created_at AS createdAt
      FROM online_training_events
      WHERE id = @eventId
      LIMIT 1
    `,
    )
    .get({ eventId }) as OnlineTrainingEventRecord | undefined;

  if (!row) {
    throw new Error("Could not load saved online training event.");
  }

  return {
    ...row,
    attendeeCount: Number(row.attendeeCount ?? 0),
    durationMinutes: Number(row.durationMinutes ?? 0),
    onlineTeachersTrained: Number(row.onlineTeachersTrained ?? 0),
    onlineSchoolLeadersTrained: Number(row.onlineSchoolLeadersTrained ?? 0),
  };
}

export function listOnlineTrainingEvents(limit = 20): OnlineTrainingEventRecord[] {
  const rows = getDb()
    .prepare(
      `
      SELECT
        id,
        title,
        description,
        audience,
        start_datetime AS startDateTime,
        end_datetime AS endDateTime,
        duration_minutes AS durationMinutes,
        attendee_count AS attendeeCount,
        online_teachers_trained AS onlineTeachersTrained,
        online_school_leaders_trained AS onlineSchoolLeadersTrained,
        calendar_event_id AS calendarEventId,
        calendar_link AS calendarLink,
        meet_link AS meetLink,
        recording_url AS recordingUrl,
        chat_summary AS chatSummary,
        attendance_captured_at AS attendanceCapturedAt,
        created_at AS createdAt
      FROM online_training_events
      ORDER BY start_datetime DESC, id DESC
      LIMIT @limit
    `,
    )
    .all({ limit }) as OnlineTrainingEventRecord[];

  return rows.map((row) => ({
    ...row,
    attendeeCount: Number(row.attendeeCount ?? 0),
    durationMinutes: Number(row.durationMinutes ?? 0),
    onlineTeachersTrained: Number(row.onlineTeachersTrained ?? 0),
    onlineSchoolLeadersTrained: Number(row.onlineSchoolLeadersTrained ?? 0),
  }));
}

export function getOnlineTrainingEventById(eventId: number): OnlineTrainingEventRecord | null {
  const row = getDb()
    .prepare(
      `
      SELECT
        id,
        title,
        description,
        audience,
        start_datetime AS startDateTime,
        end_datetime AS endDateTime,
        duration_minutes AS durationMinutes,
        attendee_count AS attendeeCount,
        online_teachers_trained AS onlineTeachersTrained,
        online_school_leaders_trained AS onlineSchoolLeadersTrained,
        calendar_event_id AS calendarEventId,
        calendar_link AS calendarLink,
        meet_link AS meetLink,
        recording_url AS recordingUrl,
        chat_summary AS chatSummary,
        attendance_captured_at AS attendanceCapturedAt,
        created_at AS createdAt
      FROM online_training_events
      WHERE id = @eventId
      LIMIT 1
    `,
    )
    .get({ eventId }) as OnlineTrainingEventRecord | undefined;

  if (!row) {
    return null;
  }

  return {
    ...row,
    attendeeCount: Number(row.attendeeCount ?? 0),
    durationMinutes: Number(row.durationMinutes ?? 0),
    onlineTeachersTrained: Number(row.onlineTeachersTrained ?? 0),
    onlineSchoolLeadersTrained: Number(row.onlineSchoolLeadersTrained ?? 0),
  };
}

export function saveOnlineTrainingAttendance(
  eventId: number,
  input: {
    onlineTeachersTrained: number;
    onlineSchoolLeadersTrained: number;
    attendeeCount?: number;
    recordingUrl?: string | null;
    chatSummary?: string | null;
  },
) {
  getDb()
    .prepare(
      `
      UPDATE online_training_events
      SET
        online_teachers_trained = @onlineTeachersTrained,
        online_school_leaders_trained = @onlineSchoolLeadersTrained,
        attendee_count = @attendeeCount,
        recording_url = @recordingUrl,
        chat_summary = @chatSummary,
        attendance_captured_at = @attendanceCapturedAt
      WHERE id = @eventId
    `,
    )
    .run({
      eventId,
      onlineTeachersTrained: Math.max(0, Math.floor(input.onlineTeachersTrained)),
      onlineSchoolLeadersTrained: Math.max(0, Math.floor(input.onlineSchoolLeadersTrained)),
      attendeeCount:
        input.attendeeCount !== undefined
          ? Math.max(0, Math.floor(input.attendeeCount))
          : Math.max(
            0,
            Math.floor(input.onlineTeachersTrained) + Math.floor(input.onlineSchoolLeadersTrained),
          ),
      recordingUrl: input.recordingUrl?.trim() ? input.recordingUrl.trim() : null,
      chatSummary: input.chatSummary?.trim() ? input.chatSummary.trim() : null,
      attendanceCapturedAt: new Date().toISOString(),
    });

  return getOnlineTrainingEventById(eventId);
}

const recordCodePrefix: Record<PortalRecordModule, string> = {
  training: "TS",
  visit: "VS",
  assessment: "AS",
  story: "ST",
  story_activity: "SA",
};

function formatRecordCode(module: PortalRecordModule, id: number) {
  return `${recordCodePrefix[module]}-${id.toString().padStart(4, "0")}`;
}

function canReviewRecords(user: PortalUser) {
  return user.isSupervisor || user.isME || user.isAdmin || user.isSuperAdmin;
}

function canViewAllRecords(user: PortalUser) {
  return user.isSupervisor || user.isME || user.isAdmin || user.isSuperAdmin;
}

function parsePortalRecord(
  row: {
    id: number;
    recordCode: string;
    module: PortalRecordModule;
    date: string;
    district: string;
    schoolId: number | null;
    schoolName: string;
    programType: string | null;
    status: PortalRecordStatus;
    followUpDate: string | null;
    followUpType: string | null;
    followUpOwnerUserId: number | null;
    followUpOwnerName: string | null;
    payloadJson: string;
    reviewNote: string | null;
    createdByUserId: number;
    createdByName: string;
    createdAt: string;
    updatedAt: string;
    deletedAt?: string | null;
    deletedByUserId?: number | null;
    deleteReason?: string | null;
  },
): PortalRecord {
  return {
    id: row.id,
    recordCode: row.recordCode,
    module: row.module,
    date: row.date,
    district: row.district,
    schoolId: row.schoolId !== null ? Number(row.schoolId) : null,
    schoolName: row.schoolName,
    programType: row.programType ?? undefined,
    status: row.status,
    followUpDate: row.followUpDate ?? undefined,
    followUpType: row.followUpType === null ? undefined : (row.followUpType as PortalRecord["followUpType"]),
    followUpOwnerUserId: row.followUpOwnerUserId === null ? undefined : Number(row.followUpOwnerUserId),
    followUpOwnerName: row.followUpOwnerName ?? undefined,
    payload: JSON.parse(row.payloadJson || "{}"),
    reviewNote: row.reviewNote,
    createdByUserId: row.createdByUserId,
    createdByName: row.createdByName,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
    deletedAt: row.deletedAt ?? null,
    deletedByUserId: row.deletedByUserId ?? null,
    deleteReason: row.deleteReason ?? null,
  };
}

function asRecordArray(value: unknown) {
  if (Array.isArray(value)) {
    return value.filter((item) => item && typeof item === "object") as Array<Record<string, unknown>>;
  }
  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value) as unknown;
      if (Array.isArray(parsed)) {
        return parsed.filter((item) => item && typeof item === "object") as Array<Record<string, unknown>>;
      }
    } catch {
      return [];
    }
  }
  return [];
}

function toNumberOrNull(value: unknown) {
  if (value === null || value === undefined || value === "") {
    return null;
  }
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    return null;
  }
  return parsed;
}

function normalizeTeacherGender(value: unknown): "Male" | "Female" | null {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (normalized === "male" || normalized === "m") {
    return "Male";
  }
  if (normalized === "female" || normalized === "f") {
    return "Female";
  }
  return null;
}

function normalizeAssessmentType(value: unknown): "baseline" | "progress" | "endline" {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (normalized.includes("end")) {
    return "endline";
  }
  if (
    normalized.includes("progress") ||
    normalized.includes("midline") ||
    normalized.includes("year 1") ||
    normalized.includes("year 2")
  ) {
    return "progress";
  }
  return "baseline";
}

type VisitImplementationStatus = "started" | "not_started" | "partial";
type VisitPathway = "observation" | "demo_and_meeting" | "mixed";

type VisitLeadershipNextAction = {
  action: string;
  ownerContactId: number | null;
  dueDate: string | null;
};

function normalizeVisitImplementationStatus(value: unknown): VisitImplementationStatus {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (normalized === "not_started" || normalized === "not started" || normalized === "no") {
    return "not_started";
  }
  if (normalized === "partial" || normalized === "partially" || normalized === "partially_started") {
    return "partial";
  }
  return "started";
}

function normalizeVisitPathway(
  status: VisitImplementationStatus,
  value: unknown,
): VisitPathway {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (normalized === "demo_and_meeting" || normalized === "demo and meeting") {
    return "demo_and_meeting";
  }
  if (normalized === "mixed" || normalized === "partial") {
    return "mixed";
  }
  if (normalized === "observation") {
    return "observation";
  }
  if (status === "not_started") {
    return "demo_and_meeting";
  }
  if (status === "partial") {
    return "mixed";
  }
  return "observation";
}

function parseIdArray(value: unknown): number[] {
  const fromCsv = (raw: string) =>
    raw
      .split(",")
      .map((entry) => Number(String(entry ?? "").trim()))
      .filter((entry) => Number.isInteger(entry) && entry > 0);

  let values: number[] = [];
  if (Array.isArray(value)) {
    values = value
      .map((entry) => Number(entry))
      .filter((entry) => Number.isInteger(entry) && entry > 0);
  } else if (typeof value === "string" && value.trim()) {
    const trimmed = value.trim();
    if (trimmed.startsWith("[") && trimmed.endsWith("]")) {
      try {
        const parsed = JSON.parse(trimmed) as unknown;
        if (Array.isArray(parsed)) {
          values = parsed
            .map((entry) => Number(entry))
            .filter((entry) => Number.isInteger(entry) && entry > 0);
        }
      } catch {
        values = fromCsv(trimmed);
      }
    } else {
      values = fromCsv(trimmed);
    }
  } else if (value && typeof value === "object") {
    values = Object.values(value as Record<string, unknown>)
      .map((entry) => Number(entry))
      .filter((entry) => Number.isInteger(entry) && entry > 0);
  }
  return [...new Set(values)];
}

function parseBooleanFlag(value: unknown, defaultValue = false): boolean {
  if (typeof value === "boolean") {
    return value;
  }
  if (typeof value === "number") {
    return value > 0;
  }
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (!normalized) {
    return defaultValue;
  }
  if (normalized === "yes" || normalized === "true" || normalized === "1") {
    return true;
  }
  if (normalized === "no" || normalized === "false" || normalized === "0") {
    return false;
  }
  return defaultValue;
}

function parseDateString(value: unknown): string | null {
  const normalized = String(value ?? "").trim();
  if (!normalized) {
    return null;
  }
  const dateOnly = normalized.slice(0, 10);
  return /^\d{4}-\d{2}-\d{2}$/.test(dateOnly) ? dateOnly : null;
}

function parseIntegerValue(value: unknown): number | null {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    return null;
  }
  return Math.round(parsed);
}

function parseVisitLeadershipNextActions(value: unknown): VisitLeadershipNextAction[] {
  const rows = asRecordArray(value);
  if (rows.length > 0) {
    return rows
      .map((row) => {
        const action = String(row.action ?? row.task ?? "").trim();
        const ownerContactIdRaw = Number(
          row.ownerContactId ?? row.owner_contact_id ?? row.ownerId,
        );
        const ownerContactId =
          Number.isInteger(ownerContactIdRaw) && ownerContactIdRaw > 0
            ? ownerContactIdRaw
            : null;
        const dueDate = parseDateString(row.dueDate ?? row.due_date);
        return {
          action,
          ownerContactId,
          dueDate,
        };
      })
      .filter((row) => row.action);
  }

  const raw = String(value ?? "").trim();
  if (!raw) {
    return [];
  }

  try {
    const parsed = JSON.parse(raw) as unknown;
    if (Array.isArray(parsed)) {
      return parseVisitLeadershipNextActions(parsed);
    }
  } catch {
    // Ignore parse failure and return an empty list.
  }

  return [];
}

type AssessmentReadingRuleSettings = {
  readingLevelVersion: string;
  emergentCwpmMax: number;
  minimumCwpmMax: number;
  competentCwpmMax: number;
  comprehensionMinPercent: number;
  comprehensionMinScore: number;
  comprehensionTotalItems: number;
  useAccuracyFloor: boolean;
  accuracyFloor: number;
};

type SchoolSupportRuleSettings = {
  rulesVersion: string;
  nonReadersThreshold: number;
  belowMinimumThreshold: number;
  decodingProficiencyThreshold: number;
  progressMinBelowMinimumDrop: number;
  progressMinCwpm20Gain: number;
  graduationPrepBelowMinimumMax: number;
  graduationPrepAt40Min: number;
};

type TeacherSupportRuleSettings = {
  rulesVersion: string;
  catchupOverallThreshold: number;
  criticalDomainThreshold: number;
  onTrackOverallThreshold: number;
  onTrackMinDelta: number;
};

type ComputedReadingLevelResult = {
  computedReadingLevel: "Level0 Non-reader" | "Level1 Emergent" | "Level2 Minimum" | "Level3 Competent" | "Level4 Strong";
  computedLevelBand: number;
  rulesVersion: string;
  comprehensionPercent: number | null;
  comprehensionPass: boolean;
  accuracyPass: boolean;
};

