function replaceAssessmentItemResponses(args: {
  db: Database.Database;
  learnerResultId: number;
  assessmentSessionResultId?: number | null;
  assessmentSessionId?: number | null;
  learnerUid?: string | null;
  mastery: ReturnType<typeof computeOneTestStyleMasteryAssessment>;
}) {
  const { db, learnerResultId, assessmentSessionResultId, assessmentSessionId, learnerUid, mastery } = args;
  db.prepare("DELETE FROM assessment_item_responses WHERE learner_result_id = @learnerResultId").run({
    learnerResultId,
  });
  if (mastery.itemScores.length === 0) {
    return;
  }
  const insert = db.prepare(
    `
    INSERT INTO assessment_item_responses (
      learner_result_id,
      assessment_session_result_id,
      assessment_session_id,
      learner_uid,
      domain_key,
      item_key,
      accuracy,
      latency_ms,
      attempts,
      hint_used,
      correction_used,
      item_score,
      latency_score,
      attempt_support_score,
      model_version,
      scoring_profile_version
    ) VALUES (
      @learnerResultId,
      @assessmentSessionResultId,
      @assessmentSessionId,
      @learnerUid,
      @domainKey,
      @itemKey,
      @accuracy,
      @latencyMs,
      @attempts,
      @hintUsed,
      @correctionUsed,
      @itemScore,
      @latencyScore,
      @attemptSupportScore,
      @modelVersion,
      @scoringProfileVersion
    )
    `,
  );
  mastery.itemScores.forEach((item) => {
    insert.run({
      learnerResultId,
      assessmentSessionResultId: assessmentSessionResultId ?? null,
      assessmentSessionId: assessmentSessionId ?? null,
      learnerUid: learnerUid ?? null,
      domainKey: item.domainKey,
      itemKey: item.itemKey,
      accuracy: item.accuracy ? 1 : 0,
      latencyMs: item.latencyMs,
      attempts: item.attempts,
      hintUsed: item.hintUsed ? 1 : 0,
      correctionUsed: item.correctionUsed ? 1 : 0,
      itemScore: item.itemScore,
      latencyScore: item.latencyScore,
      attemptSupportScore: item.attemptSupportScore,
      modelVersion: mastery.modelVersion,
      scoringProfileVersion: mastery.scoringProfileVersion,
    });
  });
}

function getSchoolSupportRuleSettings(db: Database.Database): SchoolSupportRuleSettings {
  const row = db
    .prepare(
      `
      SELECT
        rules_version AS rulesVersion,
        non_readers_threshold AS nonReadersThreshold,
        below_minimum_threshold AS belowMinimumThreshold,
        decoding_proficiency_threshold AS decodingProficiencyThreshold,
        progress_min_below_minimum_drop AS progressMinBelowMinimumDrop,
        progress_min_cwpm20_gain AS progressMinCwpm20Gain,
        graduation_prep_below_minimum_max AS graduationPrepBelowMinimumMax,
        graduation_prep_at40_min AS graduationPrepAt40Min
      FROM school_support_settings
      WHERE id = 1
      LIMIT 1
      `,
    )
    .get() as
    | {
      rulesVersion: string;
      nonReadersThreshold: number;
      belowMinimumThreshold: number;
      decodingProficiencyThreshold: number;
      progressMinBelowMinimumDrop: number;
      progressMinCwpm20Gain: number;
      graduationPrepBelowMinimumMax: number;
      graduationPrepAt40Min: number;
    }
    | undefined;

  return {
    rulesVersion: row?.rulesVersion || SCHOOL_SUPPORT_RULE_VERSION,
    nonReadersThreshold: Number(row?.nonReadersThreshold ?? 30),
    belowMinimumThreshold: Number(row?.belowMinimumThreshold ?? 55),
    decodingProficiencyThreshold: Number(row?.decodingProficiencyThreshold ?? 45),
    progressMinBelowMinimumDrop: Number(row?.progressMinBelowMinimumDrop ?? 5),
    progressMinCwpm20Gain: Number(row?.progressMinCwpm20Gain ?? 5),
    graduationPrepBelowMinimumMax: Number(row?.graduationPrepBelowMinimumMax ?? 20),
    graduationPrepAt40Min: Number(row?.graduationPrepAt40Min ?? 60),
  };
}

