function normalizeParticipantRole(value: unknown) {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (normalized === "classroom teacher" || normalized === "teacher") {
    return "Classroom teacher";
  }
  if (
    normalized === "school leader" ||
    normalized === "leader" ||
    normalized === "head teacher" ||
    normalized === "deputy head teacher" ||
    normalized === "dos" ||
    normalized === "proprietor" ||
    normalized === "director"
  ) {
    return "School Leader";
  }
  return String(value ?? "").trim() || "School Leader";
}

function normalizeContactRoleFromCategory(category: SchoolContactCategory) {
  return category === "Teacher" ? "Classroom teacher" : "School Leader";
}

function resolveContactByTeacherUid(
  db: Database.Database,
  teacherUid: string,
): SchoolContactRecord | null {
  const normalizedTeacherUid = teacherUid.trim();
  if (!normalizedTeacherUid) {
    return null;
  }
  const row = db
    .prepare(
      `
        SELECT contact_id AS contactId
        FROM school_contacts
        WHERE lower(trim(COALESCE(teacher_uid, ''))) = lower(trim(@teacherUid))
        LIMIT 1
      `,
    )
    .get({ teacherUid: normalizedTeacherUid }) as { contactId: number } | undefined;

  if (!row?.contactId) {
    return null;
  }
  return getSchoolContactByIdInternal(db, row.contactId);
}

function resolveActivityContact(
  db: Database.Database,
  row: Record<string, unknown>,
  schoolId: number,
): SchoolContactRecord {
  const contactIdRaw = Number(
    row.contactId ??
      row.contact_id ??
      row.participantContactId ??
      row.teacherContactId,
  );
  let contact: SchoolContactRecord | null = null;
  if (Number.isInteger(contactIdRaw) && contactIdRaw > 0) {
    contact = getSchoolContactByIdInternal(db, contactIdRaw);
  }

  if (!contact) {
    const contactUid = String(
      row.contactUid ??
        row.contact_uid ??
        row.participantContactUid ??
        row.teacherContactUid,
    )
      .trim();
    if (contactUid) {
      contact = getSchoolContactByUidInternal(db, contactUid);
    }
  }

  if (!contact) {
    const teacherUid = String(row.teacherUid ?? row.teacher_uid ?? "")
      .trim();
    if (teacherUid) {
      contact = resolveContactByTeacherUid(db, teacherUid);
    }
  }

  if (!contact) {
    throw new Error("Participant not found in school roster. Add to School Account first.");
  }
  if (contact.schoolId !== schoolId) {
    throw new Error("Participant must belong to the selected school account.");
  }

  return contact;
}

function resolveActivityLearner(
  db: Database.Database,
  row: Record<string, unknown>,
  schoolId: number,
): SchoolLearnerRecord {
  const learnerIdRaw = Number(row.learnerId ?? row.learner_id);
  let learner: SchoolLearnerRecord | null = null;
  if (Number.isInteger(learnerIdRaw) && learnerIdRaw > 0) {
    learner = getSchoolLearnerByIdInternal(db, learnerIdRaw);
  }

  if (!learner) {
    const learnerUid = String(row.learnerUid ?? row.learner_uid ?? "")
      .trim();
    if (learnerUid) {
      learner = getSchoolLearnerByUidInternal(db, learnerUid);
    }
  }

  if (!learner) {
    throw new Error("Learner not found in school roster. Add learner to this school first.");
  }
  if (learner.schoolId !== schoolId) {
    throw new Error("Learner must belong to the selected school account.");
  }

  return learner;
}

function ensureSchoolHasPrimaryContact(schoolId: number) {
  const row = getDb()
    .prepare(
      `
        SELECT
          sd.id AS schoolId,
          sd.primary_contact_id AS primaryContactId,
          sc.category
        FROM schools_directory sd
        LEFT JOIN school_contacts sc
          ON sc.contact_id = sd.primary_contact_id
        WHERE sd.id = @schoolId
        LIMIT 1
      `,
    )
    .get({ schoolId }) as
    | { schoolId: number; primaryContactId: number | null; category: SchoolContactCategory | null }
    | undefined;

  if (!row?.schoolId) {
    throw new Error("Selected school account was not found.");
  }
  if (!row.primaryContactId || !row.category) {
    throw new Error("Each school must have a primary contact before recording activities.");
  }
}

function getPeriodKey(value: string | null | undefined) {
  const normalized = String(value ?? "").trim();
  if (!normalized) {
    return new Date().toISOString().slice(0, 7);
  }
  return normalized.slice(0, 7);
}

function toPercentSafe(part: number, total: number) {
  if (total <= 0) return 0;
  return Number(((part / total) * 100).toFixed(1));
}

function parseDomainScoresJson(input: string | null | undefined) {
  if (!input) {
    return {} as Record<string, unknown>;
  }
  try {
    const parsed = JSON.parse(input) as unknown;
    if (parsed && typeof parsed === "object") {
      return parsed as Record<string, unknown>;
    }
  } catch {
    return {} as Record<string, unknown>;
  }
  return {} as Record<string, unknown>;
}

function computeAssessmentDistributionMetrics(
  db: Database.Database,
  rows: Array<{
    computedLevelBand: number | null;
    fluencyScore: number | null;
    decodingScore: number | null;
  }>,
  decodingThreshold: number,
) {
  const settings = getAssessmentReadingRuleSettings(db);
  const n = rows.length;
  let level0 = 0;
  let level01 = 0;
  let at20Plus = 0;
  let at40Plus = 0;
  let at60Plus = 0;
  let decodingProficient = 0;

  rows.forEach((row) => {
    const band =
      row.computedLevelBand !== null && Number.isFinite(Number(row.computedLevelBand))
        ? Number(row.computedLevelBand)
        : computeReadingBandFromCwpm(row.fluencyScore, settings);
    if (band <= 0) level0 += 1;
    if (band <= 1) level01 += 1;
    if (band >= 2) at20Plus += 1;
    if (band >= 3) at40Plus += 1;
    if (band >= 4) at60Plus += 1;
    if (row.decodingScore !== null && Number(row.decodingScore) >= decodingThreshold) {
      decodingProficient += 1;
    }
  });

  return {
    n,
    nonReadersPct: toPercentSafe(level0, n),
    belowMinimumPct: toPercentSafe(level01, n),
    at20PlusPct: toPercentSafe(at20Plus, n),
    at40PlusPct: toPercentSafe(at40Plus, n),
    at60PlusPct: toPercentSafe(at60Plus, n),
    decodingProficientPct: toPercentSafe(decodingProficient, n),
  };
}

function upsertSchoolSupportStatusSnapshot(
  db: Database.Database,
  schoolId: number,
) {
  const latestSession = db
    .prepare(
      `
      SELECT
        id,
        assessment_date AS assessmentDate
      FROM assessment_sessions
      WHERE school_id = @schoolId
      ORDER BY assessment_date DESC, id DESC
      LIMIT 1
      `,
    )
    .get({ schoolId }) as { id: number; assessmentDate: string } | undefined;

  if (!latestSession?.id) {
    return;
  }

  const settings = getSchoolSupportRuleSettings(db);
  const latestRows = db
    .prepare(
      `
      SELECT
        computed_level_band AS computedLevelBand,
        fluency_score AS fluencyScore,
        decoding_score AS decodingScore,
        model_version AS modelVersion,
        phonemic_awareness_mastery_status AS phonemicAwarenessMasteryStatus,
        grapheme_phoneme_correspondence_mastery_status AS graphemePhonemeCorrespondenceMasteryStatus,
        blending_decoding_mastery_status AS blendingDecodingMasteryStatus,
        word_recognition_fluency_mastery_status AS wordRecognitionFluencyMasteryStatus,
        comprehension_mastery_status AS comprehensionMasteryStatus
      FROM assessment_session_results
      WHERE assessment_session_id = @sessionId
      `,
    )
    .all({ sessionId: latestSession.id }) as Array<{
      computedLevelBand: number | null;
      fluencyScore: number | null;
      decodingScore: number | null;
      modelVersion: string | null;
      phonemicAwarenessMasteryStatus: string | null;
      graphemePhonemeCorrespondenceMasteryStatus: string | null;
      blendingDecodingMasteryStatus: string | null;
      wordRecognitionFluencyMasteryStatus: string | null;
      comprehensionMasteryStatus: string | null;
    }>;
  const latest = computeAssessmentDistributionMetrics(
    db,
    latestRows,
    settings.decodingProficiencyThreshold,
  );

  const baselineSession = db
    .prepare(
      `
      SELECT id
      FROM assessment_sessions
      WHERE school_id = @schoolId
        AND assessment_type = 'baseline'
      ORDER BY assessment_date ASC, id ASC
      LIMIT 1
      `,
    )
    .get({ schoolId }) as { id: number } | undefined;

  let baseline: ReturnType<typeof computeAssessmentDistributionMetrics> | null = null;
  if (baselineSession?.id) {
    const baselineRows = db
      .prepare(
        `
        SELECT
          computed_level_band AS computedLevelBand,
          fluency_score AS fluencyScore,
          decoding_score AS decodingScore
        FROM assessment_session_results
        WHERE assessment_session_id = @sessionId
        `,
      )
      .all({ sessionId: baselineSession.id }) as Array<{
        computedLevelBand: number | null;
        fluencyScore: number | null;
        decodingScore: number | null;
      }>;
    baseline = computeAssessmentDistributionMetrics(
      db,
      baselineRows,
      settings.decodingProficiencyThreshold,
    );
  }

  const graduationRow = db
    .prepare(
      `
      SELECT COALESCE(is_eligible, 0) AS isEligible
      FROM school_graduation_eligibility_cache
      WHERE school_id = @schoolId
      LIMIT 1
      `,
    )
    .get({ schoolId }) as { isEligible: number } | undefined;
  const graduationEligible = Number(graduationRow?.isEligible ?? 0) === 1;

  const belowMinimumDrop =
    baseline && baseline.n > 0
      ? Number((baseline.belowMinimumPct - latest.belowMinimumPct).toFixed(1))
      : null;
  const cwpm20Gain =
    baseline && baseline.n > 0
      ? Number((latest.at20PlusPct - baseline.at20PlusPct).toFixed(1))
      : null;

  const masteryRows = latestRows.filter((row) =>
    isOneTestStyleModelVersion(row.modelVersion),
  );
  const masteryFoundationalRedCount = masteryRows.filter((row) => {
    const pa = normalizeMasteryStatus(row.phonemicAwarenessMasteryStatus) ?? "red";
    const gpc = normalizeMasteryStatus(row.graphemePhonemeCorrespondenceMasteryStatus) ?? "red";
    const blend = normalizeMasteryStatus(row.blendingDecodingMasteryStatus) ?? "red";
    return pa === "red" || gpc === "red" || blend === "red";
  }).length;
  const masteryFluencyAmberCount = masteryRows.filter((row) => {
    const fluency = normalizeMasteryStatus(row.wordRecognitionFluencyMasteryStatus) ?? "red";
    return fluency === "amber";
  }).length;
  const masteryFoundationalGreenAndCompCount = masteryRows.filter((row) => {
    const pa = normalizeMasteryStatus(row.phonemicAwarenessMasteryStatus) ?? "red";
    const gpc = normalizeMasteryStatus(row.graphemePhonemeCorrespondenceMasteryStatus) ?? "red";
    const blend = normalizeMasteryStatus(row.blendingDecodingMasteryStatus) ?? "red";
    const comp = normalizeMasteryStatus(row.comprehensionMasteryStatus) ?? "red";
    return pa === "green" && gpc === "green" && blend === "green" && comp === "green";
  }).length;
  const masteryFoundationalRedPct =
    masteryRows.length > 0 ? toPercentSafe(masteryFoundationalRedCount, masteryRows.length) : null;
  const masteryFluencyAmberPct =
    masteryRows.length > 0 ? toPercentSafe(masteryFluencyAmberCount, masteryRows.length) : null;
  const masteryProgressingPct =
    masteryRows.length > 0
      ? toPercentSafe(masteryFoundationalGreenAndCompCount, masteryRows.length)
      : null;

  let status:
    | "Requires Remedial & Catch-Up"
    | "Progressing (Maintain + Strengthen)"
    | "Graduation Prep (Approaching criteria)"
    | "Graduation Eligible";
  if (graduationEligible) {
    status = "Graduation Eligible";
  } else if (
    masteryRows.length > 0 &&
    masteryFoundationalRedPct !== null &&
    masteryFoundationalRedPct >= 40
  ) {
    status = "Requires Remedial & Catch-Up";
  } else if (
    masteryRows.length > 0 &&
    masteryProgressingPct !== null &&
    masteryProgressingPct >= 70
  ) {
    status = "Graduation Prep (Approaching criteria)";
  } else if (
    masteryRows.length > 0 &&
    masteryFluencyAmberPct !== null &&
    masteryFluencyAmberPct >= 35
  ) {
    status = "Progressing (Maintain + Strengthen)";
  } else if (
    latest.n <= 0 ||
    latest.nonReadersPct >= settings.nonReadersThreshold ||
    latest.belowMinimumPct >= settings.belowMinimumThreshold ||
    latest.decodingProficientPct < settings.decodingProficiencyThreshold
  ) {
    status = "Requires Remedial & Catch-Up";
  } else if (
    latest.belowMinimumPct <= settings.graduationPrepBelowMinimumMax &&
    latest.at40PlusPct >= settings.graduationPrepAt40Min
  ) {
    status = "Graduation Prep (Approaching criteria)";
  } else if (
    (belowMinimumDrop !== null &&
      belowMinimumDrop >= settings.progressMinBelowMinimumDrop) ||
    (cwpm20Gain !== null && cwpm20Gain >= settings.progressMinCwpm20Gain)
  ) {
    status = "Progressing (Maintain + Strengthen)";
  } else {
    status = "Progressing (Maintain + Strengthen)";
  }

  const metrics = {
    nAssessed: latest.n,
    nonReadersPct: latest.nonReadersPct,
    belowMinimumPct: latest.belowMinimumPct,
    at20PlusPct: latest.at20PlusPct,
    at40PlusPct: latest.at40PlusPct,
    at60PlusPct: latest.at60PlusPct,
    decodingProficientPct: latest.decodingProficientPct,
    baselineBelowMinimumPct: baseline?.belowMinimumPct ?? null,
    baselineAt20PlusPct: baseline?.at20PlusPct ?? null,
    belowMinimumDropPp: belowMinimumDrop,
    at20PlusGainPp: cwpm20Gain,
    graduationEligible: graduationEligible ? "yes" : "no",
    masteryAssessedN: masteryRows.length,
    foundationalRedPct: masteryFoundationalRedPct,
    fluencyAmberPct: masteryFluencyAmberPct,
    foundationalGreenAndComprehensionGreenPct: masteryProgressingPct,
  };
  const recommendedActions = SCHOOL_SUPPORT_ACTIONS[status] ?? [];
  const periodKey = getPeriodKey(latestSession.assessmentDate);
  const now = new Date().toISOString();

  db.prepare(
    `
    INSERT INTO school_support_status_snapshots (
      school_id,
      period_key,
      status,
      metrics_json,
      recommended_actions_json,
      rules_version,
      computed_at
    ) VALUES (
      @schoolId,
      @periodKey,
      @status,
      @metricsJson,
      @recommendedActionsJson,
      @rulesVersion,
      @computedAt
    )
    ON CONFLICT(school_id, period_key) DO UPDATE SET
      status = excluded.status,
      metrics_json = excluded.metrics_json,
      recommended_actions_json = excluded.recommended_actions_json,
      rules_version = excluded.rules_version,
      computed_at = excluded.computed_at
    `,
  ).run({
    schoolId,
    periodKey,
    status,
    metricsJson: JSON.stringify(metrics),
    recommendedActionsJson: JSON.stringify(recommendedActions),
    rulesVersion: settings.rulesVersion,
    computedAt: now,
  });
}

function upsertTeacherSupportStatusSnapshot(
  db: Database.Database,
  schoolId: number,
  teacherUid: string,
) {
  const normalizedTeacherUid = teacherUid.trim();
  if (!normalizedTeacherUid) {
    return;
  }

  const rows = db
    .prepare(
      `
      SELECT
        le.lesson_date AS lessonDate,
        le.overall_score AS overallScore,
        le.domain_scores_json AS domainScoresJson,
        tr.full_name AS teacherName
      FROM lesson_evaluations le
      LEFT JOIN teacher_roster tr ON tr.teacher_uid = le.teacher_uid
      WHERE le.school_id = @schoolId
        AND le.teacher_uid = @teacherUid
        AND le.status = 'active'
      ORDER BY le.lesson_date ASC, le.id ASC
      `,
    )
    .all({ schoolId, teacherUid: normalizedTeacherUid }) as Array<{
      lessonDate: string;
      overallScore: number;
      domainScoresJson: string;
      teacherName: string | null;
    }>;

  if (rows.length === 0) {
    return;
  }

  const settings = getTeacherSupportRuleSettings(db);
  const baseline = rows[0];
  const latest = rows[rows.length - 1];
  const baselinePct = score4ToPercent(Number(baseline.overallScore));
  const latestPct = score4ToPercent(Number(latest.overallScore));
  const deltaOverall =
    baselinePct !== null && latestPct !== null
      ? Number((latestPct - baselinePct).toFixed(1))
      : null;

  const latestDomainScores = parseDomainScoresJson(latest.domainScoresJson);
  const newSoundPct = score4ToPercent(
    toNumberOrNull(
      latestDomainScores.new_sound ??
        latestDomainScores.newSound ??
        null,
    ),
  );
  const decodingPct = score4ToPercent(
    toNumberOrNull(
      latestDomainScores.decoding ??
        null,
    ),
  );

  let status: "Needs Catch-up Training" | "Needs Coaching & Follow-up" | "On Track";
  if (
    latestPct === null ||
    latestPct < settings.catchupOverallThreshold ||
    (newSoundPct !== null && newSoundPct < settings.criticalDomainThreshold) ||
    (decodingPct !== null && decodingPct < settings.criticalDomainThreshold)
  ) {
    status = "Needs Catch-up Training";
  } else if (
    latestPct >= settings.onTrackOverallThreshold &&
    deltaOverall !== null &&
    deltaOverall >= settings.onTrackMinDelta
  ) {
    status = "On Track";
  } else {
    status = "Needs Coaching & Follow-up";
  }

  const metrics = {
    latestOverallPct: latestPct,
    baselineOverallPct: baselinePct,
    deltaOverallPct: deltaOverall,
    criticalNewSoundPct: newSoundPct,
    criticalDecodingPct: decodingPct,
    evaluationsCount: rows.length,
  };
  const periodKey = getPeriodKey(latest.lessonDate);
  const now = new Date().toISOString();

  db.prepare(
    `
    INSERT INTO teacher_support_status_snapshots (
      school_id,
      teacher_uid,
      period_key,
      status,
      recommended_action,
      evaluations_count,
      metrics_json,
      rules_version,
      computed_at
    ) VALUES (
      @schoolId,
      @teacherUid,
      @periodKey,
      @status,
      @recommendedAction,
      @evaluationsCount,
      @metricsJson,
      @rulesVersion,
      @computedAt
    )
    ON CONFLICT(school_id, teacher_uid, period_key) DO UPDATE SET
      status = excluded.status,
      recommended_action = excluded.recommended_action,
      evaluations_count = excluded.evaluations_count,
      metrics_json = excluded.metrics_json,
      rules_version = excluded.rules_version,
      computed_at = excluded.computed_at
    `,
  ).run({
    schoolId,
    teacherUid: normalizedTeacherUid,
    periodKey,
    status,
    recommendedAction: TEACHER_SUPPORT_ACTIONS[status] ?? "",
    evaluationsCount: rows.length,
    metricsJson: JSON.stringify(metrics),
    rulesVersion: settings.rulesVersion,
    computedAt: now,
  });
}

function normalizeOptionalFeedbackText(value: unknown) {
  const normalized = String(value ?? "").trim();
  return normalized ? normalized : null;
}

function syncTrainingFeedbackTestimonials(
  db: Database.Database,
  trainingRecordId: number,
  schoolId: number,
  createdByUserId: number,
) {
  db.prepare(
    `
    DELETE FROM portal_testimonials
    WHERE source_type = 'training_feedback'
      AND source_training_record_id = @trainingRecordId
    `,
  ).run({ trainingRecordId });

  const school = db
    .prepare(
      `
      SELECT name, district
      FROM schools_directory
      WHERE id = @schoolId
      LIMIT 1
      `,
    )
    .get({ schoolId }) as { name: string; district: string } | undefined;

  const feedbackRows = db
    .prepare(
      `
      SELECT
        tf.id,
        tf.role_snapshot AS roleSnapshot,
        tf.how_training_changed_teaching AS changedTeaching,
        tf.what_you_will_do_to_improve_reading_levels AS improveReading,
        sc.full_name AS fullName
      FROM training_feedback_entries tf
      LEFT JOIN school_contacts sc ON sc.contact_id = tf.contact_id
      WHERE tf.training_record_id = @trainingRecordId
        AND tf.feedback_role = 'participant'
      ORDER BY tf.id ASC
      `,
    )
    .all({ trainingRecordId }) as Array<{
      id: number;
      roleSnapshot: string | null;
      changedTeaching: string | null;
      improveReading: string | null;
      fullName: string | null;
    }>;

  const insert = db.prepare(
    `
    INSERT INTO portal_testimonials (
      storyteller_name,
      storyteller_role,
      school_name,
      district,
      story_text,
      video_source_type,
      video_file_name,
      video_stored_path,
      video_mime_type,
      video_size_bytes,
      is_published,
      moderation_status,
      source_type,
      source_training_feedback_id,
      source_training_record_id,
      quote_field,
      created_by_user_id
    ) VALUES (
      @storytellerName,
      @storytellerRole,
      @schoolName,
      @district,
      @storyText,
      'upload',
      'auto-feedback.txt',
      '',
      'text/plain',
      0,
      0,
      'pending',
      'training_feedback',
      @sourceTrainingFeedbackId,
      @sourceTrainingRecordId,
      @quoteField,
      @createdByUserId
    )
    `,
  );

  feedbackRows.forEach((row) => {
    const changed = normalizeOptionalFeedbackText(row.changedTeaching);
    const improve = normalizeOptionalFeedbackText(row.improveReading);
    const selectedQuote = changed || improve;
    if (!selectedQuote || selectedQuote.length < 20) {
      return;
    }
    insert.run({
      storytellerName: row.fullName?.trim() || "Training participant",
      storytellerRole: row.roleSnapshot?.trim() || "Teacher",
      schoolName: school?.name ?? "Unknown school",
      district: school?.district ?? "Unknown district",
      storyText: selectedQuote,
      sourceTrainingFeedbackId: row.id,
      sourceTrainingRecordId: trainingRecordId,
      quoteField: changed ? "how_training_changed_teaching" : "what_you_will_do_to_improve_reading_levels",
      createdByUserId,
    });
  });
}

function syncTrainingFeedbackEntries(
  db: Database.Database,
  args: {
    recordId: number;
    schoolId: number;
    payload: Record<string, unknown>;
    userId: number;
  },
) {
  db.prepare("DELETE FROM training_feedback_entries WHERE training_record_id = @recordId").run({
    recordId: args.recordId,
  });

  const participantRows = asRecordArray(args.payload.participants);
  const feedbackBundleRaw = String(args.payload.trainingFeedbackBundleJson ?? "").trim();
  const parsedFeedbackBundle =
    feedbackBundleRaw && feedbackBundleRaw.startsWith("{")
      ? (() => {
          try {
            const parsed = JSON.parse(feedbackBundleRaw) as Record<string, unknown>;
            return parsed && typeof parsed === "object" ? parsed : null;
          } catch {
            return null;
          }
        })()
      : null;
  const participantBundleRows = Array.isArray(parsedFeedbackBundle?.participants)
    ? (parsedFeedbackBundle?.participants as Array<Record<string, unknown>>)
    : [];
  const facilitatorBundleRows = Array.isArray(parsedFeedbackBundle?.facilitators)
    ? (parsedFeedbackBundle?.facilitators as Array<Record<string, unknown>>)
    : [];
  const selectedFacilitatorId = String(parsedFeedbackBundle?.selectedFacilitatorId ?? "")
    .trim();
  const selectedFacilitator =
    facilitatorBundleRows.find(
      (row) => String(row.id ?? "").trim() === selectedFacilitatorId,
    ) ??
    facilitatorBundleRows[0] ??
    null;
  const facilitatorFeedback =
    parsedFeedbackBundle?.facilitatorFeedback &&
    typeof parsedFeedbackBundle.facilitatorFeedback === "object"
      ? (parsedFeedbackBundle.facilitatorFeedback as Record<string, unknown>)
      : null;

  const participantWhatWentWell = normalizeOptionalFeedbackText(
    args.payload.what_went_well_participant ?? args.payload.whatWentWellParticipant,
  );
  const participantChangedTeachingLegacy = normalizeOptionalFeedbackText(
    args.payload.how_training_changed_teaching ?? args.payload.howTrainingChangedTeaching,
  );
  const participantImproveReadingLegacy = normalizeOptionalFeedbackText(
    args.payload.what_you_will_do_to_improve_reading_levels ??
      args.payload.whatYouWillDoToImproveReadingLevels,
  );
  const participantChallenges = normalizeOptionalFeedbackText(
    args.payload.challenges_participant ?? args.payload.challenges,
  );
  const participantRecommendations = normalizeOptionalFeedbackText(
    args.payload.recommendations_next_training_participant ??
      args.payload.recommendations_next_training ??
      args.payload.recommendationsNextTraining,
  );
  const trainerWhatWentWell = normalizeOptionalFeedbackText(
    facilitatorFeedback?.whatWentWell ??
      args.payload.what_went_well_trainer ??
      args.payload.whatWentWellTrainer,
  );
  const trainerChallenges = normalizeOptionalFeedbackText(
    facilitatorFeedback?.challenges ?? args.payload.challenges_trainer,
  );
  const trainerRecommendations = normalizeOptionalFeedbackText(
    facilitatorFeedback?.actionsRecommendations ??
      args.payload.recommendations_next_training_trainer,
  );
  const trainerGeneralObservation = normalizeOptionalFeedbackText(
    facilitatorFeedback?.generalObservation ?? args.payload.facilitatorGeneralObservation,
  );
  const trainerNextStep = normalizeOptionalFeedbackText(
    facilitatorFeedback?.nextStep ?? args.payload.facilitatorNextStep,
  );
  const trainerPhotoFileName = normalizeOptionalFeedbackText(
    facilitatorFeedback?.photoFileName ?? args.payload.feedbackPhotoFileName,
  );
  const selectedFacilitatorName = normalizeOptionalFeedbackText(
    selectedFacilitator?.fullName ?? args.payload.facilitatorName,
  );
  const selectedFacilitatorPhone = normalizeOptionalFeedbackText(
    selectedFacilitator?.phone ?? args.payload.facilitatorPhone,
  );
  const followUpOwnerUserId = Number(
    args.payload.followUpOwnerUserId ??
      args.payload.follow_up_owner_user_id ??
      0,
  );

  const insert = db.prepare(
    `
    INSERT INTO training_feedback_entries (
      training_record_id,
      school_id,
      contact_id,
      trainer_user_id,
      feedback_role,
      what_went_well,
      how_training_changed_teaching,
      what_you_will_do_to_improve_reading_levels,
      challenges,
      recommendations_next_training,
      role_snapshot,
      gender_snapshot,
      class_taught_snapshot,
      submitted_at
    ) VALUES (
      @trainingRecordId,
      @schoolId,
      @contactId,
      @trainerUserId,
      @feedbackRole,
      @whatWentWell,
      @howTrainingChangedTeaching,
      @whatYouWillDoToImproveReadingLevels,
      @challenges,
      @recommendationsNextTraining,
      @roleSnapshot,
      @genderSnapshot,
      @classTaughtSnapshot,
      @submittedAt
    )
    `,
  );
  const submittedAt = new Date().toISOString();

  if (participantBundleRows.length > 0) {
    participantBundleRows.forEach((row) => {
      const changedTeaching = normalizeOptionalFeedbackText(
        row.changedThinking ?? row.how_training_changed_teaching,
      );
      const improveReading = normalizeOptionalFeedbackText(
        row.improveReading ?? row.what_you_will_do_to_improve_reading_levels,
      );
      if (!changedTeaching && !improveReading) {
        return;
      }

      let contact: SchoolContactRecord | null = null;
      const contactId = Number(row.contactId ?? row.contact_id);
      const contactUid = String(row.contactUid ?? row.contact_uid ?? "").trim();
      if (Number.isInteger(contactId) && contactId > 0) {
        contact = getSchoolContactByIdInternal(db, contactId);
      }
      if (!contact && contactUid) {
        contact = getSchoolContactByUidInternal(db, contactUid);
      }
      if (!contact) {
        try {
          contact = resolveActivityContact(db, row, args.schoolId);
        } catch {
          contact = null;
        }
      }

      const participantRole = normalizeParticipantRole(
        row.role ?? (contact ? normalizeContactRoleFromCategory(contact.category) : "Teacher"),
      );
      const participantGender =
        contact?.gender === "Male" || contact?.gender === "Female"
          ? contact.gender
          : normalizeTeacherGender(row.gender);
      insert.run({
        trainingRecordId: args.recordId,
        schoolId: args.schoolId,
        contactId: contact?.contactId ?? null,
        trainerUserId: null,
        feedbackRole: "participant",
        whatWentWell: null,
        howTrainingChangedTeaching: changedTeaching,
        whatYouWillDoToImproveReadingLevels: improveReading,
        challenges: null,
        recommendationsNextTraining: null,
        roleSnapshot: participantRole,
        genderSnapshot: participantGender,
        classTaughtSnapshot: normalizeOptionalFeedbackText(contact?.classTaught),
        submittedAt,
      });
    });
  } else {
    participantRows.forEach((row) => {
      const hasAnyParticipantFeedback =
        participantWhatWentWell ||
        participantChangedTeachingLegacy ||
        participantImproveReadingLegacy ||
        participantChallenges ||
        participantRecommendations;
      if (!hasAnyParticipantFeedback) {
        return;
      }
      const contact = resolveActivityContact(db, row, args.schoolId);
      insert.run({
        trainingRecordId: args.recordId,
        schoolId: args.schoolId,
        contactId: contact.contactId,
        trainerUserId: null,
        feedbackRole: "participant",
        whatWentWell: participantWhatWentWell,
        howTrainingChangedTeaching: participantChangedTeachingLegacy,
        whatYouWillDoToImproveReadingLevels: participantImproveReadingLegacy,
        challenges: participantChallenges,
        recommendationsNextTraining: participantRecommendations,
        roleSnapshot: normalizeParticipantRole(
          row.role ?? normalizeContactRoleFromCategory(contact.category),
        ),
        genderSnapshot:
          contact.gender === "Male" || contact.gender === "Female"
            ? contact.gender
            : normalizeTeacherGender(row.gender),
        classTaughtSnapshot: normalizeOptionalFeedbackText(contact.classTaught),
        submittedAt,
      });
    });
  }

  const hasTrainerFeedback =
    trainerWhatWentWell ||
    trainerChallenges ||
    trainerRecommendations ||
    trainerGeneralObservation ||
    trainerNextStep ||
    selectedFacilitatorName ||
    selectedFacilitatorPhone ||
    trainerPhotoFileName;
  if (hasTrainerFeedback) {
    const trainerRecommendationsMerged = [
      trainerRecommendations,
      trainerNextStep ? `Next Step: ${trainerNextStep}` : "",
      selectedFacilitatorName
        ? `Facilitator: ${selectedFacilitatorName}${selectedFacilitatorPhone ? ` (${selectedFacilitatorPhone})` : ""}`
        : "",
      trainerPhotoFileName ? `Photo: ${trainerPhotoFileName}` : "",
    ]
      .filter(Boolean)
      .join("\n");
    insert.run({
      trainingRecordId: args.recordId,
      schoolId: args.schoolId,
      contactId: null,
      trainerUserId:
        Number.isInteger(followUpOwnerUserId) && followUpOwnerUserId > 0
          ? followUpOwnerUserId
          : null,
      feedbackRole: "trainer",
      whatWentWell: trainerWhatWentWell,
      howTrainingChangedTeaching: trainerGeneralObservation,
      whatYouWillDoToImproveReadingLevels: trainerNextStep,
      challenges: trainerChallenges,
      recommendationsNextTraining: trainerRecommendationsMerged || null,
      roleSnapshot: "Trainer",
      genderSnapshot: null,
      classTaughtSnapshot: null,
      submittedAt,
    });
  }

  syncTrainingFeedbackTestimonials(db, args.recordId, args.schoolId, args.userId);
}

function normalizeLinkedPayload(module: PortalRecordModule, payload: PortalRecordInput["payload"], fallbackSchoolId: number) {
  const linkedPayload: Record<string, unknown> = { ...(payload ?? {}) };
  const db = getDb();
  if (!Number.isInteger(fallbackSchoolId) || fallbackSchoolId <= 0) {
    throw new Error("School selection is required.");
  }

  if (module === "training") {
    const participantRows = asRecordArray(linkedPayload.participants).filter((row) =>
      Object.values(row).some((value) => String(value ?? "").trim() !== ""),
    );
    const normalizedRows = participantRows.map((row) => {
      const contact = resolveActivityContact(db, row, fallbackSchoolId);
      const school = getSchoolDirectoryRecordById(fallbackSchoolId);
      const inferredGender =
        contact.gender === "Male" || contact.gender === "Female"
          ? contact.gender
          : normalizeTeacherGender(row.gender) ?? "";
      const role = normalizeParticipantRole(
        row.role ?? normalizeContactRoleFromCategory(contact.category),
      );
      return {
        contactId: contact.contactId,
        contactUid: contact.contactUid,
        participantName: contact.fullName,
        role,
        gender: inferredGender,
        schoolAccountId: fallbackSchoolId,
        schoolAttachedTo: school?.name ?? String(row.schoolAttachedTo ?? "").trim(),
        teacherUid: contact.teacherUid ?? null,
        phoneContact: contact.phone ?? String(row.phoneContact ?? row.phone ?? "").trim(),
        email: contact.email ?? String(row.email ?? "").trim(),
      };
    });

    linkedPayload.participants = JSON.stringify(normalizedRows);
    linkedPayload.participantsTotal = normalizedRows.length;
    linkedPayload.classroomTeachers = normalizedRows.filter((row) => row.role === "Classroom teacher").length;
    linkedPayload.schoolLeaders = normalizedRows.filter((row) => row.role === "School Leader").length;
    linkedPayload.maleCount = normalizedRows.filter((row) => row.gender === "Male").length;
    linkedPayload.femaleCount = normalizedRows.filter((row) => row.gender === "Female").length;
    linkedPayload.numberAttended = normalizedRows.length;
  }

  if (module === "visit") {
    const implementationStatus = normalizeVisitImplementationStatus(
      linkedPayload.implementationStatus ?? linkedPayload.implementation_status,
    );
    const visitPathway = normalizeVisitPathway(
      implementationStatus,
      linkedPayload.visitPathway ?? linkedPayload.visit_pathway,
    );
    linkedPayload.implementationStatus = implementationStatus;
    linkedPayload.visitPathway = visitPathway;
    linkedPayload.classesImplementing = parseStringList(
      linkedPayload.classesImplementing ?? linkedPayload.classes_implementing,
    );
    linkedPayload.classesNotImplementing = parseStringList(
      linkedPayload.classesNotImplementing ?? linkedPayload.classes_not_implementing,
    );
    linkedPayload.demoComponents = parseStringList(
      linkedPayload.demoComponents ?? linkedPayload.demo_components,
    );
    linkedPayload.demoMaterialsUsed = parseStringList(
      linkedPayload.demoMaterialsUsed ?? linkedPayload.materials_used,
    );
    linkedPayload.classesToStartFirst = parseStringList(
      linkedPayload.classesToStartFirst ?? linkedPayload.classes_to_start_first,
    );
    linkedPayload.supportNeededFromOzeki = parseStringList(
      linkedPayload.supportNeededFromOzeki ?? linkedPayload.support_needed_from_ozeki,
    );
    linkedPayload.demoTeachersPresentContactIds = parseIdArray(
      linkedPayload.demoTeachersPresentContactIds ??
      linkedPayload.demo_teachers_present_contact_ids,
    );
    linkedPayload.leadershipAttendeesContactIds = parseIdArray(
      linkedPayload.leadershipAttendeesContactIds ??
      linkedPayload.leadership_attendees_contact_ids,
    );

    const responsibleContactIdRaw = Number(
      linkedPayload.implementationResponsibleContactId ??
      linkedPayload.implementation_responsible_contact_id,
    );
    linkedPayload.implementationResponsibleContactId =
      Number.isInteger(responsibleContactIdRaw) && responsibleContactIdRaw > 0
        ? responsibleContactIdRaw
        : "";

    const parsedNextActions = parseVisitLeadershipNextActions(
      linkedPayload.leadershipNextActionsJson ?? linkedPayload.leadership_next_actions_json,
    );
    linkedPayload.leadershipNextActionsJson = JSON.stringify(parsedNextActions);

    const hasTeacherData =
      String(linkedPayload.teacherObserved ?? "").trim() ||
      String(linkedPayload.teacherContactUid ?? "").trim() ||
      String(linkedPayload.teacherContactId ?? "").trim() ||
      String(linkedPayload.teacherUid ?? "").trim();
    if (hasTeacherData) {
      const teacher = resolveActivityContact(
        db,
        {
          participantName: linkedPayload.teacherObserved,
          contactId: linkedPayload.teacherContactId,
          contactUid: linkedPayload.teacherContactUid,
          teacherUid: linkedPayload.teacherUid,
        },
        fallbackSchoolId,
      );
      linkedPayload.teacherObserved = teacher.fullName;
      linkedPayload.teacherContactId = teacher.contactId;
      linkedPayload.teacherContactUid = teacher.contactUid;
      linkedPayload.teacherUid = teacher.teacherUid ?? "";
      linkedPayload.teacherGender =
        teacher.gender === "Male" || teacher.gender === "Female" ? teacher.gender : "";
      linkedPayload.visitParticipants = JSON.stringify([
        {
          contactId: teacher.contactId,
          contactUid: teacher.contactUid,
          participantName: teacher.fullName,
          role: normalizeContactRoleFromCategory(teacher.category),
        },
      ]);
    }
  }

  if (module === "assessment") {
    const classGrade = String(linkedPayload.classLevel ?? linkedPayload.classGrade ?? "").trim() || "Unspecified";
    const learnerRows = asRecordArray(linkedPayload.egraLearnersData).filter((row) =>
      Object.values(row).some((value) => String(value ?? "").trim() !== ""),
    );

    const normalizedRows = learnerRows.map((row) => {
      const learner = resolveActivityLearner(db, row, fallbackSchoolId);
      const sex = learner.gender === "Boy" ? "M" : learner.gender === "Girl" ? "F" : "";
      return {
        ...row,
        learnerUid: learner.learnerUid,
        learnerId: learner.learnerId,
        learnerName: learner.learnerName,
        childName: learner.learnerName,
        childId: learner.internalChildId ?? String(learner.learnerId),
        sex,
        age: learner.age,
        classGrade: String(row.classGrade ?? classGrade).trim() || classGrade,
      };
    });

    linkedPayload.egraLearnersData = JSON.stringify(normalizedRows);
    linkedPayload.learnersAssessed = normalizedRows.length;
  }

  if (module === "story") {
    const storyParticipantRows = asRecordArray(linkedPayload.storyParticipants);
    if (storyParticipantRows.length > 0) {
      const resolvedParticipants = storyParticipantRows.map((row) => {
        const contact = resolveActivityContact(db, row, fallbackSchoolId);
        return {
          contactId: contact.contactId,
          contactUid: contact.contactUid,
          participantName: contact.fullName,
          role: normalizeContactRoleFromCategory(contact.category),
        };
      });
      linkedPayload.storyParticipants = JSON.stringify(resolvedParticipants);
    }

    const storyLearnerRows = asRecordArray(linkedPayload.storyLearners);
    if (storyLearnerRows.length > 0) {
      const resolvedLearners = storyLearnerRows.map((row) => {
        const learner = resolveActivityLearner(db, row, fallbackSchoolId);
        return {
          learnerId: learner.learnerId,
          learnerUid: learner.learnerUid,
          learnerName: learner.learnerName,
          classGrade: learner.classGrade,
        };
      });
      linkedPayload.storyLearners = JSON.stringify(resolvedLearners);
    }
  }

  return linkedPayload;
}

function clearPortalRecordLinkages(db: Database.Database, recordId: number) {
  db.prepare(
    `
      DELETE FROM activity_insights
      WHERE activity_id = @recordId
        AND activity_type IN ('training', 'visit', 'assessment', 'story_activity')
    `,
  ).run({ recordId });
  db.prepare("DELETE FROM portal_training_attendance WHERE portal_record_id = @recordId").run({ recordId });
  db.prepare("DELETE FROM training_feedback_entries WHERE training_record_id = @recordId").run({
    recordId,
  });
  db.prepare(
    `
      DELETE FROM portal_testimonials
      WHERE source_type = 'training_feedback'
        AND source_training_record_id = @recordId
    `,
  ).run({ recordId });
  db.prepare(
    `
      DELETE FROM visit_participants
      WHERE visit_id IN (
        SELECT id
        FROM coaching_visits
        WHERE portal_record_id = @recordId
      )
    `,
  ).run({ recordId });
  db.prepare("DELETE FROM coaching_visits WHERE portal_record_id = @recordId").run({ recordId });
  db.prepare("DELETE FROM assessment_records WHERE source_portal_record_id = @recordId").run({ recordId });
  db.prepare("DELETE FROM assessment_sessions WHERE portal_record_id = @recordId").run({ recordId });
  db.prepare(
    `
      DELETE FROM story_activity_participants
      WHERE story_activity_id IN (
        SELECT id
        FROM story_activities
        WHERE portal_record_id = @recordId
      )
    `,
  ).run({ recordId });
  db.prepare(
    `
      DELETE FROM story_activity_learners
      WHERE story_activity_id IN (
        SELECT id
        FROM story_activities
        WHERE portal_record_id = @recordId
      )
    `,
  ).run({ recordId });
  db.prepare("DELETE FROM story_activities WHERE portal_record_id = @recordId").run({ recordId });
}

function syncPortalRecordLinkages(
  db: Database.Database,
  args: {
    recordId: number;
    module: PortalRecordModule;
    payload: Record<string, unknown>;
    schoolId: number;
    date: string;
    programType: string | null | undefined;
    followUpType?: string | null;
    followUpOwnerUserId?: number | null;
    userId: number;
  },
) {
  clearPortalRecordLinkages(db, args.recordId);

  if (args.module === "training") {
    const participantRows = asRecordArray(args.payload.participants);
    const insertAttendance = db.prepare(`
      INSERT INTO portal_training_attendance (
        portal_record_id,
        school_id,
        contact_id,
        contact_uid,
        participant_name,
        participant_role,
        role_at_time,
        gender,
        teacher_uid,
        attended,
        phone,
        email
      ) VALUES (
        @portalRecordId,
        @schoolId,
        @contactId,
        @contactUid,
        @participantName,
        @participantRole,
        @roleAtTime,
        @gender,
        @teacherUid,
        @attended,
        @phone,
        @email
      )
    `);

    participantRows.forEach((row) => {
      const contact = resolveActivityContact(db, row, args.schoolId);
      const roleAtTime = normalizeParticipantRole(
        row.role ?? normalizeContactRoleFromCategory(contact.category),
      );
      const gender =
        contact.gender === "Male" || contact.gender === "Female"
          ? contact.gender
          : normalizeTeacherGender(row.gender);
      insertAttendance.run({
        portalRecordId: args.recordId,
        schoolId: args.schoolId,
        contactId: contact.contactId,
        contactUid: contact.contactUid,
        participantName: contact.fullName,
        participantRole: roleAtTime,
        roleAtTime,
        gender: gender ?? null,
        teacherUid: contact.teacherUid ?? (String(row.teacherUid ?? "").trim() || null),
        attended: 1,
        phone: contact.phone ?? (String(row.phoneContact ?? row.phone ?? "").trim() || null),
        email: contact.email ?? (String(row.email ?? "").trim() || null),
      });
    });

    if (args.followUpType && !String(args.payload.followUpType ?? "").trim()) {
      args.payload.followUpType = String(args.followUpType);
    }
    if (
      Number.isInteger(args.followUpOwnerUserId) &&
      Number(args.followUpOwnerUserId) > 0 &&
      !String(args.payload.followUpOwnerUserId ?? "").trim()
    ) {
      args.payload.followUpOwnerUserId = Number(args.followUpOwnerUserId);
    }

    syncTrainingFeedbackEntries(db, {
      recordId: args.recordId,
      schoolId: args.schoolId,
      payload: args.payload,
      userId: args.userId,
    });
  }

  if (args.module === "visit") {
    const visitType = String(
      args.payload.visitType ?? args.programType ?? "Coaching visit",
    ).trim() || "Coaching visit";
    const cycleRaw = Number(args.payload.coachingCycleNumber ?? args.payload.coachingCycle);
    const coachingCycleNumber = Number.isInteger(cycleRaw) && cycleRaw >= 1 && cycleRaw <= 4 ? cycleRaw : null;
    const focusAreas = args.payload.focusAreas ?? args.payload.objectivesCovered ?? [];
    const focusAreasJson = Array.isArray(focusAreas)
      ? JSON.stringify(focusAreas.map((item) => String(item).trim()).filter(Boolean))
      : JSON.stringify(
        String(focusAreas ?? "")
          .split(",")
          .map((item) => item.trim())
          .filter(Boolean),
      );
    const implementationStatus = normalizeVisitImplementationStatus(
      args.payload.implementationStatus ?? args.payload.implementation_status,
    );
    const visitPathway = normalizeVisitPathway(
      implementationStatus,
      args.payload.visitPathway ?? args.payload.visit_pathway,
    );
    const classesImplementing = parseStringList(
      args.payload.classesImplementing ?? args.payload.classes_implementing,
    );
    const classesNotImplementing = parseStringList(
      args.payload.classesNotImplementing ?? args.payload.classes_not_implementing,
    );
    const classesImplementingJson = JSON.stringify(classesImplementing);
    const classesNotImplementingJson = JSON.stringify(classesNotImplementing);

    db.prepare(`
      INSERT INTO coaching_visits (
        visit_uid,
        portal_record_id,
        school_id,
        visit_date,
        visit_type,
        coaching_cycle_number,
        coach_user_id,
        focus_areas_json,
        implementation_status,
        visit_pathway,
        classes_implementing_json,
        classes_not_implementing_json,
        updated_at
      ) VALUES (
        @visitUid,
        @portalRecordId,
        @schoolId,
        @visitDate,
        @visitType,
        @coachingCycleNumber,
        @coachUserId,
        @focusAreasJson,
        @implementationStatus,
        @visitPathway,
        @classesImplementingJson,
        @classesNotImplementingJson,
        datetime('now')
      )
      ON CONFLICT(portal_record_id) DO UPDATE SET
        school_id = excluded.school_id,
        visit_date = excluded.visit_date,
        visit_type = excluded.visit_type,
        coaching_cycle_number = excluded.coaching_cycle_number,
        coach_user_id = excluded.coach_user_id,
        focus_areas_json = excluded.focus_areas_json,
        implementation_status = excluded.implementation_status,
        visit_pathway = excluded.visit_pathway,
        classes_implementing_json = excluded.classes_implementing_json,
        classes_not_implementing_json = excluded.classes_not_implementing_json,
        updated_at = datetime('now')
    `).run({
      visitUid: `vis_${args.recordId}`,
      portalRecordId: args.recordId,
      schoolId: args.schoolId,
      visitDate: args.date,
      visitType,
      coachingCycleNumber,
      coachUserId: args.userId,
      focusAreasJson,
      implementationStatus,
      visitPathway,
      classesImplementingJson,
      classesNotImplementingJson,
    });

    const visitRow = db
      .prepare(
        `
          SELECT id
          FROM coaching_visits
          WHERE portal_record_id = @portalRecordId
          LIMIT 1
        `,
      )
      .get({ portalRecordId: args.recordId }) as { id: number } | undefined;

    if (visitRow?.id) {
      const hasTeacherData =
        String(args.payload.teacherObserved ?? "").trim() ||
        String(args.payload.teacherContactUid ?? "").trim() ||
        String(args.payload.teacherContactId ?? "").trim() ||
        String(args.payload.teacherUid ?? "").trim();
      if (hasTeacherData && visitPathway !== "demo_and_meeting") {
        const teacher = resolveActivityContact(
          db,
          {
            participantName: args.payload.teacherObserved,
            contactId: args.payload.teacherContactId,
            contactUid: args.payload.teacherContactUid,
            teacherUid: args.payload.teacherUid,
            role: "School Leader",
          },
          args.schoolId,
        );
        db.prepare(
          `
            INSERT INTO visit_participants (
              visit_id,
              school_id,
              contact_id,
              role_at_time,
              attended
            ) VALUES (
              @visitId,
              @schoolId,
              @contactId,
              @roleAtTime,
              1
            )
          `,
        ).run({
          visitId: visitRow.id,
          schoolId: args.schoolId,
          contactId: teacher.contactId,
          roleAtTime: normalizeContactRoleFromCategory(teacher.category),
        });
      }

      const demoDelivered = parseBooleanFlag(
        args.payload.demoDelivered ?? args.payload.demo_delivered,
        true,
      );
      const demoClass = String(args.payload.demoClass ?? args.payload.demo_class ?? "").trim();
      const demoFocus = String(args.payload.demoFocus ?? args.payload.demo_focus ?? "").trim();
      const demoMinutesRaw = parseIntegerValue(
        args.payload.demoMinutes ?? args.payload.demo_minutes,
      );
      const demoMinutes =
        demoMinutesRaw !== null && demoMinutesRaw > 0 ? demoMinutesRaw : null;
      const demoComponents = parseStringList(
        args.payload.demoComponents ?? args.payload.demo_components,
      );
      const materialsUsed = parseStringList(
        args.payload.demoMaterialsUsed ?? args.payload.materials_used,
      );
      const demoTeachersPresentContactIds = parseIdArray(
        args.payload.demoTeachersPresentContactIds ??
        args.payload.demo_teachers_present_contact_ids,
      );
      const takeawaysText = String(
        args.payload.demoTakeawaysText ?? args.payload.takeaways_text ?? "",
      ).trim();

      const implementationStartDate = parseDateString(
        args.payload.implementationStartDate ?? args.payload.start_date,
      );
      const dailyReadingTimeRaw = parseIntegerValue(
        args.payload.dailyReadingTimeMinutes ?? args.payload.daily_reading_time_minutes,
      );
      const dailyReadingTimeMinutes =
        dailyReadingTimeRaw !== null && dailyReadingTimeRaw >= 0 ? dailyReadingTimeRaw : null;
      const classesToStartFirst = parseStringList(
        args.payload.classesToStartFirst ?? args.payload.classes_to_start_first,
      );
      const responsibleContactIdRaw = Number(
        args.payload.implementationResponsibleContactId ??
        args.payload.implementation_responsible_contact_id,
      );
      const responsibleContactId =
        Number.isInteger(responsibleContactIdRaw) && responsibleContactIdRaw > 0
          ? responsibleContactIdRaw
          : null;
      const supportNeeded = parseStringList(
        args.payload.supportNeededFromOzeki ?? args.payload.support_needed_from_ozeki,
      );

      const hasDemoData =
        demoClass.length > 0 ||
        demoFocus.length > 0 ||
        demoMinutes !== null ||
        demoComponents.length > 0 ||
        materialsUsed.length > 0 ||
        demoTeachersPresentContactIds.length > 0 ||
        takeawaysText.length > 0 ||
        implementationStartDate !== null ||
        dailyReadingTimeMinutes !== null ||
        classesToStartFirst.length > 0 ||
        responsibleContactId !== null ||
        supportNeeded.length > 0;
      const shouldPersistDemo = visitPathway !== "observation" || hasDemoData;

      if (shouldPersistDemo) {
        db.prepare(
          `
            INSERT INTO visit_demo (
              visit_id,
              demo_delivered,
              demo_class,
              demo_focus,
              demo_minutes,
              demo_components_json,
              materials_used_json,
              teachers_present_contact_ids_json,
              takeaways_text,
              implementation_start_date,
              daily_reading_time_minutes,
              classes_to_start_json,
              responsible_contact_id,
              support_needed_json,
              updated_at
            ) VALUES (
              @visitId,
              @demoDelivered,
              @demoClass,
              @demoFocus,
              @demoMinutes,
              @demoComponentsJson,
              @materialsUsedJson,
              @teachersPresentContactIdsJson,
              @takeawaysText,
              @implementationStartDate,
              @dailyReadingTimeMinutes,
              @classesToStartJson,
              @responsibleContactId,
              @supportNeededJson,
              datetime('now')
            )
            ON CONFLICT(visit_id) DO UPDATE SET
              demo_delivered = excluded.demo_delivered,
              demo_class = excluded.demo_class,
              demo_focus = excluded.demo_focus,
              demo_minutes = excluded.demo_minutes,
              demo_components_json = excluded.demo_components_json,
              materials_used_json = excluded.materials_used_json,
              teachers_present_contact_ids_json = excluded.teachers_present_contact_ids_json,
              takeaways_text = excluded.takeaways_text,
              implementation_start_date = excluded.implementation_start_date,
              daily_reading_time_minutes = excluded.daily_reading_time_minutes,
              classes_to_start_json = excluded.classes_to_start_json,
              responsible_contact_id = excluded.responsible_contact_id,
              support_needed_json = excluded.support_needed_json,
              updated_at = datetime('now')
          `,
        ).run({
          visitId: visitRow.id,
          demoDelivered: demoDelivered ? 1 : 0,
          demoClass: demoClass || null,
          demoFocus: demoFocus || null,
          demoMinutes,
          demoComponentsJson: JSON.stringify(demoComponents),
          materialsUsedJson: JSON.stringify(materialsUsed),
          teachersPresentContactIdsJson: JSON.stringify(demoTeachersPresentContactIds),
          takeawaysText: takeawaysText || null,
          implementationStartDate,
          dailyReadingTimeMinutes,
          classesToStartJson: JSON.stringify(classesToStartFirst),
          responsibleContactId,
          supportNeededJson: JSON.stringify(supportNeeded),
        });
      } else {
        db.prepare("DELETE FROM visit_demo WHERE visit_id = @visitId").run({
          visitId: visitRow.id,
        });
      }

      const meetingHeld = parseBooleanFlag(
        args.payload.leadershipMeetingHeld ?? args.payload.meeting_held,
        true,
      );
      const attendeesContactIds = parseIdArray(
        args.payload.leadershipAttendeesContactIds ??
        args.payload.leadership_attendees_contact_ids,
      );
      const summaryText = String(
        args.payload.leadershipSummary ?? args.payload.summary_text ?? "",
      ).trim();
      const agreementsText = String(
        args.payload.leadershipAgreements ?? args.payload.agreements_text ?? "",
      ).trim();
      const risksText = String(
        args.payload.leadershipRisks ?? args.payload.risks_text ?? "",
      ).trim();
      const nextActions = parseVisitLeadershipNextActions(
        args.payload.leadershipNextActionsJson ?? args.payload.next_actions_json,
      );
      const nextVisitDate = parseDateString(
        args.payload.leadershipNextVisitDate ?? args.payload.next_visit_date,
      );

      const hasMeetingData =
        attendeesContactIds.length > 0 ||
        summaryText.length > 0 ||
        agreementsText.length > 0 ||
        risksText.length > 0 ||
        nextActions.length > 0 ||
        nextVisitDate !== null;
      const shouldPersistMeeting = visitPathway !== "observation" || hasMeetingData;

      if (shouldPersistMeeting) {
        db.prepare(
          `
            INSERT INTO visit_leadership_meeting (
              visit_id,
              meeting_held,
              attendees_contact_ids_json,
              summary_text,
              agreements_text,
              risks_text,
              next_actions_json,
              next_visit_date,
              updated_at
            ) VALUES (
              @visitId,
              @meetingHeld,
              @attendeesContactIdsJson,
              @summaryText,
              @agreementsText,
              @risksText,
              @nextActionsJson,
              @nextVisitDate,
              datetime('now')
            )
            ON CONFLICT(visit_id) DO UPDATE SET
              meeting_held = excluded.meeting_held,
              attendees_contact_ids_json = excluded.attendees_contact_ids_json,
              summary_text = excluded.summary_text,
              agreements_text = excluded.agreements_text,
              risks_text = excluded.risks_text,
              next_actions_json = excluded.next_actions_json,
              next_visit_date = excluded.next_visit_date,
              updated_at = datetime('now')
          `,
        ).run({
          visitId: visitRow.id,
          meetingHeld: meetingHeld ? 1 : 0,
          attendeesContactIdsJson: JSON.stringify(attendeesContactIds),
          summaryText: summaryText || null,
          agreementsText: agreementsText || null,
          risksText: risksText || null,
          nextActionsJson: JSON.stringify(nextActions),
          nextVisitDate,
        });
      } else {
        db.prepare("DELETE FROM visit_leadership_meeting WHERE visit_id = @visitId").run({
          visitId: visitRow.id,
        });
      }
    }
  }

  if (args.module === "assessment") {
    const classGrade = String(args.payload.classLevel ?? args.payload.classGrade ?? "").trim() || "Unspecified";
    const toolVersion = String(args.payload.toolVersion ?? "EGRA-v1").trim() || "EGRA-v1";
    const assessmentType = normalizeAssessmentType(args.payload.assessmentType ?? args.programType);
    const masterySettings = getOneTestMasterySettings(db);
    const resolvedModelVersion = ASSESSMENT_MODEL_VERSION_UG_MASTERY_ONETEST_STYLE_V1;
    const resolvedBenchmarkVersion = String(
      args.payload.benchmarkVersion ?? masterySettings.benchmarkVersion,
    ).trim() || masterySettings.benchmarkVersion;
    const resolvedScoringProfileVersion = String(
      args.payload.scoringProfileVersion ?? masterySettings.scoringProfileVersion,
    ).trim() || masterySettings.scoringProfileVersion;
    const isOneTestModel = isOneTestStyleModelVersion(resolvedModelVersion);
    const rows = asRecordArray(args.payload.egraLearnersData);

    const existingSession = db
      .prepare(
        `
        SELECT id, session_uid AS sessionUid
        FROM assessment_sessions
        WHERE portal_record_id = @portalRecordId
        LIMIT 1
      `,
      )
      .get({ portalRecordId: args.recordId }) as { id: number; sessionUid: string } | undefined;

    let sessionId = existingSession?.id ?? null;
    if (!sessionId) {
      const insert = db
        .prepare(
          `
          INSERT INTO assessment_sessions (
            session_uid,
            portal_record_id,
            school_id,
            assessment_date,
            assessment_type,
            class_grade,
            tool_version,
            assessor_user_id
          ) VALUES (
            @sessionUid,
            @portalRecordId,
            @schoolId,
            @assessmentDate,
            @assessmentType,
            @classGrade,
            @toolVersion,
            @assessorUserId
          )
        `,
        )
        .run({
          sessionUid: `sess_${args.recordId}`,
          portalRecordId: args.recordId,
          schoolId: args.schoolId,
          assessmentDate: args.date,
          assessmentType,
          classGrade,
          toolVersion,
          assessorUserId: args.userId,
        });
      sessionId = Number(insert.lastInsertRowid);
    } else {
      db.prepare(
        `
        UPDATE assessment_sessions
        SET
          school_id = @schoolId,
          assessment_date = @assessmentDate,
          assessment_type = @assessmentType,
          class_grade = @classGrade,
          tool_version = @toolVersion,
          assessor_user_id = @assessorUserId,
          updated_at = datetime('now')
        WHERE id = @sessionId
      `,
      ).run({
        sessionId,
        schoolId: args.schoolId,
        assessmentDate: args.date,
        assessmentType,
        classGrade,
        toolVersion,
        assessorUserId: args.userId,
      });
    }

    if (!sessionId) {
      return;
    }

    db.prepare(
      `
      UPDATE assessment_sessions
      SET
        model_version = @modelVersion,
        benchmark_version = @benchmarkVersion,
        scoring_profile_version = @scoringProfileVersion
      WHERE id = @sessionId
      `,
    ).run({
      sessionId,
      modelVersion: resolvedModelVersion,
      benchmarkVersion: resolvedBenchmarkVersion,
      scoringProfileVersion: resolvedScoringProfileVersion,
    });

    db.prepare("DELETE FROM assessment_session_results WHERE assessment_session_id = @sessionId").run({
      sessionId,
    });
    db.prepare("DELETE FROM assessment_records WHERE source_portal_record_id = @recordId").run({
      recordId: args.recordId,
    });
    const readingRuleSettings = getAssessmentReadingRuleSettings(db, {
      grade: classGrade,
      language: "English",
      atDate: args.date,
    });
    const computedAt = new Date().toISOString();

    const insertSessionResult = db.prepare(`
      INSERT INTO assessment_session_results (
        assessment_session_id,
        source_row_key,
        learner_id,
        learner_uid,
        letter_sounds_score,
        decoding_score,
        fluency_score,
        fluency_accuracy_score,
        comprehension_score,
        computed_reading_level,
        computed_level_band,
        rules_version,
        computed_at
      ) VALUES (
        @assessmentSessionId,
        @sourceRowKey,
        @learnerId,
        @learnerUid,
        @letterSoundsScore,
        @decodingScore,
        @fluencyScore,
        @fluencyAccuracyScore,
        @comprehensionScore,
        @computedReadingLevel,
        @computedLevelBand,
        @rulesVersion,
        @computedAt
      )
    `);

    const insertAssessment = db.prepare(`
      INSERT INTO assessment_records (
        learner_uid,
        child_name,
        child_id,
        gender,
        age,
        school_id,
        class_grade,
        assessment_date,
        assessment_type,
        letter_identification_score,
        sound_identification_score,
        decodable_words_score,
        undecodable_words_score,
        made_up_words_score,
        story_reading_score,
        fluency_accuracy_score,
        reading_comprehension_score,
        computed_reading_level,
        computed_level_band,
        reading_rules_version,
        reading_level_computed_at,
        notes,
        created_by_user_id,
        source_portal_record_id,
        source_row_key
      ) VALUES (
        @learnerUid,
        @childName,
        @childId,
        @gender,
        @age,
        @schoolId,
        @classGrade,
        @assessmentDate,
        @assessmentType,
        @letterIdentificationScore,
        @soundIdentificationScore,
        @decodableWordsScore,
        @undecodableWordsScore,
        @madeUpWordsScore,
        @storyReadingScore,
        @fluencyAccuracyScore,
        @readingComprehensionScore,
        @computedReadingLevel,
        @computedLevelBand,
        @rulesVersion,
        @computedAt,
        @notes,
        @createdByUserId,
        @sourcePortalRecordId,
        @sourceRowKey
      )
    `);
    rows.forEach((row, index) => {
      const learner = resolveActivityLearner(db, row, args.schoolId);
      const learnerUid = learner.learnerUid;
      const learnerName = learner.learnerName;
      const childId =
        String(row.childId ?? row.learnerId ?? "").trim() ||
        learner.internalChildId ||
        String(learner.learnerId);
      const age = learner.age;
      const learnerGender = learner.gender;

      const letterIdentificationScore = toNumberOrNull(
        row.letterIdentification ?? row.letterIdentication ?? row.letterSoundsScore,
      );
      const soundIdentificationScore = toNumberOrNull(
        row.soundIdentification ?? row.letterSoundScore ?? row.letterSoundsScore,
      );
      const decodableWordsScore = toNumberOrNull(row.decodableWords);
      const undecodableWordsScore = toNumberOrNull(row.undecodableWords);
      const madeUpWordsScore = toNumberOrNull(row.madeUpWords);
      const fluencyScore = toNumberOrNull(row.storyReading ?? row.fluencyScore);
      const fluencyAccuracyScore = toNumberOrNull(
        row.fluencyAccuracy ??
          row.fluencyAccuracyScore ??
          row.fluency_accuracy_score ??
          row.accuracy,
      );
      const comprehensionScore = toNumberOrNull(
        row.readingComprehension ?? row.comprehensionScore,
      );
      const decodingCandidates = [
        decodableWordsScore,
        undecodableWordsScore,
        madeUpWordsScore,
      ].filter((score): score is number => score !== null);
      const decodingScore =
        decodingCandidates.length > 0
          ? decodingCandidates.reduce((sum, score) => sum + score, 0) / decodingCandidates.length
          : toNumberOrNull(row.decodingScore);

      const computed = computeAssessmentReadingLevel(
        {
          fluencyCwpm: fluencyScore,
          fluencyAccuracy: fluencyAccuracyScore,
          comprehensionScore,
        },
        readingRuleSettings,
      );

      const rowDomainInputsRaw =
        row.masteryDomainInputs ?? row.mastery_domains ?? row.domain_mastery_inputs ?? null;
      const rowItemResponsesRaw =
        row.masteryItemResponses ??
        row.mastery_item_responses ??
        row.itemResponses ??
        row.assessmentItemResponses ??
        null;
      const rowDomainInputs = parseDomainInputsFromUnknown(
        typeof rowDomainInputsRaw === "string"
          ? safeParseJson<Record<string, unknown>>(rowDomainInputsRaw, {})
          : rowDomainInputsRaw,
      );
      const rowItemResponses = parseItemResponsesFromUnknown(
        typeof rowItemResponsesRaw === "string"
          ? safeParseJson<unknown[]>(rowItemResponsesRaw, [])
          : rowItemResponsesRaw,
      );
      const rowExpectedGrade =
        String(
          row.learnerExpectedGrade ??
            row.expectedGradeLevel ??
            row.gradeExpectation ??
            classGrade,
        ).trim() || classGrade;

      const masteryComputation = isOneTestModel
        ? computeOneTestStyleMasteryAssessment({
          grade: rowExpectedGrade,
          age,
          domainInputs: rowDomainInputs,
          itemResponses: rowItemResponses,
          legacyScores: {
            letterIdentificationScore,
            soundIdentificationScore,
            decodableWordsScore,
            undecodableWordsScore,
            madeUpWordsScore,
            storyReadingScore: fluencyScore,
            readingComprehensionScore: comprehensionScore,
            fluencyAccuracyScore,
          },
          settings: masterySettings,
          modelVersion: resolvedModelVersion,
          benchmarkVersion: resolvedBenchmarkVersion,
          scoringProfileVersion: resolvedScoringProfileVersion,
        })
        : null;

      const sourceRowKey = String(row.no ?? index + 1);
      const computedReadingLevel = masteryComputation
        ? toLegacyReadingLabelFromStage(
          masteryComputation.readingStageOrder,
          masteryComputation.readingStageLabel,
        )
        : computed.computedReadingLevel;
      const computedLevelBand = masteryComputation
        ? stageBandFromOrder(masteryComputation.readingStageOrder)
        : computed.computedLevelBand;
      const rulesVersion = masteryComputation
        ? masteryComputation.modelVersion
        : computed.rulesVersion;

      const insertedSession = insertSessionResult.run({
        assessmentSessionId: sessionId,
        sourceRowKey,
        learnerId: learner.learnerId,
        learnerUid,
        letterSoundsScore:
          toNumberOrNull(soundIdentificationScore ?? letterIdentificationScore) ?? null,
        decodingScore: decodingScore ?? null,
        fluencyScore: fluencyScore ?? null,
        fluencyAccuracyScore: fluencyAccuracyScore ?? null,
        comprehensionScore: comprehensionScore ?? null,
        computedReadingLevel,
        computedLevelBand,
        rulesVersion,
        computedAt,
      });
      const sessionResultId = Number(insertedSession.lastInsertRowid);

      const insertedAssessment = insertAssessment.run({
        learnerUid,
        childName: learnerName,
        childId,
        gender: learnerGender,
        age,
        schoolId: args.schoolId,
        classGrade,
        assessmentDate: args.date,
        assessmentType,
        letterIdentificationScore: letterIdentificationScore ?? null,
        soundIdentificationScore: soundIdentificationScore ?? null,
        decodableWordsScore: decodableWordsScore ?? null,
        undecodableWordsScore: undecodableWordsScore ?? null,
        madeUpWordsScore: madeUpWordsScore ?? null,
        storyReadingScore: fluencyScore ?? null,
        fluencyAccuracyScore: fluencyAccuracyScore ?? null,
        readingComprehensionScore: comprehensionScore ?? null,
        computedReadingLevel,
        computedLevelBand,
        rulesVersion,
        computedAt,
        notes: null,
        createdByUserId: args.userId,
        sourcePortalRecordId: args.recordId,
        sourceRowKey,
      });
      const assessmentRecordId = Number(insertedAssessment.lastInsertRowid);

      if (masteryComputation) {
        persistMasteryForSessionResult({
          db,
          sessionResultId,
          mastery: masteryComputation,
          computedAt,
        });
        persistMasteryForAssessmentRecord({
          db,
          assessmentRecordId,
          mastery: masteryComputation,
          learnerExpectedGrade: rowExpectedGrade,
          computedAt,
        });
        replaceAssessmentItemResponses({
          db,
          learnerResultId: assessmentRecordId,
          assessmentSessionResultId: sessionResultId,
          assessmentSessionId: sessionId,
          learnerUid,
          mastery: masteryComputation,
        });
      } else {
        db.prepare(
          `
          UPDATE assessment_session_results
          SET
            model_version = @modelVersion,
            benchmark_version = @benchmarkVersion,
            scoring_profile_version = @scoringProfileVersion
          WHERE id = @id
          `,
        ).run({
          id: sessionResultId,
          modelVersion: resolvedModelVersion || ASSESSMENT_LEGACY_MODEL_VERSION,
          benchmarkVersion: resolvedBenchmarkVersion || null,
          scoringProfileVersion: resolvedScoringProfileVersion || null,
        });
        db.prepare(
          `
          UPDATE assessment_records
          SET
            model_version = @modelVersion,
            benchmark_version = @benchmarkVersion,
            scoring_profile_version = @scoringProfileVersion,
            learner_expected_grade = @learnerExpectedGrade
          WHERE id = @id
          `,
        ).run({
          id: assessmentRecordId,
          modelVersion: resolvedModelVersion || ASSESSMENT_LEGACY_MODEL_VERSION,
          benchmarkVersion: resolvedBenchmarkVersion || null,
          scoringProfileVersion: resolvedScoringProfileVersion || null,
          learnerExpectedGrade: rowExpectedGrade || null,
        });
      }
    });

    upsertSchoolSupportStatusSnapshot(db, args.schoolId);
  }

  if (args.module === "story") {
    const insertStory = db.prepare(`
      INSERT INTO story_activities (
        portal_record_id,
        school_id,
        date,
        session_type,
        learners_count,
        drafts_count,
        revisions_count,
        notes,
        created_by_user_id
      ) VALUES (
        @portalRecordId,
        @schoolId,
        @date,
        @sessionType,
        @learnersCount,
        @draftsCount,
        @revisionsCount,
        @notes,
        @createdByUserId
      )
    `).run({
      portalRecordId: args.recordId,
      schoolId: args.schoolId,
      date: args.date,
      sessionType: String(args.payload.sessionType ?? "upload"),
      learnersCount: Number(args.payload.learnersCount ?? 0),
      draftsCount: Number(args.payload.draftsCount ?? 0),
      revisionsCount: Number(args.payload.revisionsCount ?? 0),
      notes: String(args.payload.notes ?? ""),
      createdByUserId: args.userId,
    });

    const storyActivityId = Number(insertStory.lastInsertRowid);
    if (Number.isInteger(storyActivityId) && storyActivityId > 0) {
      const participantRows = asRecordArray(args.payload.storyParticipants);
      const insertStoryParticipant = db.prepare(
        `
          INSERT INTO story_activity_participants (
            story_activity_id,
            school_id,
            contact_id,
            role_at_time
          ) VALUES (
            @storyActivityId,
            @schoolId,
            @contactId,
            @roleAtTime
          )
        `,
      );
      participantRows.forEach((row) => {
        const contact = resolveActivityContact(db, row, args.schoolId);
        insertStoryParticipant.run({
          storyActivityId,
          schoolId: args.schoolId,
          contactId: contact.contactId,
          roleAtTime: normalizeContactRoleFromCategory(contact.category),
        });
      });

      const learnerRows = asRecordArray(args.payload.storyLearners);
      const insertStoryLearner = db.prepare(
        `
          INSERT INTO story_activity_learners (
            story_activity_id,
            school_id,
            learner_id
          ) VALUES (
            @storyActivityId,
            @schoolId,
            @learnerId
          )
        `,
      );
      learnerRows.forEach((row) => {
        const learner = resolveActivityLearner(db, row, args.schoolId);
        insertStoryLearner.run({
          storyActivityId,
          schoolId: args.schoolId,
          learnerId: learner.learnerId,
        });
      });
    }
  }
}

function normalizePayload(input: PortalRecordInput) {
  const linkedPayload = normalizeLinkedPayload(input.module, input.payload ?? {}, input.schoolId ?? 0);
  return JSON.stringify(linkedPayload);
}

function assertSponsorshipPayload(input: PortalRecordInput) {
  const requiresSponsorship =
    input.module === "training" ||
    input.module === "visit" ||
    input.module === "assessment" ||
    input.module === "story" ||
    input.module === "story_activity";
  if (!requiresSponsorship) {
    return;
  }
  if (input.status === "Draft") {
    return;
  }

  const payload =
    input.payload && typeof input.payload === "object" && !Array.isArray(input.payload)
      ? (input.payload as Record<string, unknown>)
      : {};

  const sponsorshipType = readString(payload, [
    "sponsorshipType",
    "sponsorType",
    "sponsor_category",
  ]);
  if (!sponsorshipType) {
    throw new Error("Sponsorship type is required for this form.");
  }

  const sponsoredBy = readString(payload, [
    "sponsoredBy",
    "sponsorName",
    "sponsored_by",
  ]);
  if (!sponsoredBy) {
    throw new Error("Sponsored by is required for this form.");
  }
}

function assertVisitImplementationPayload(input: PortalRecordInput) {
  if (input.module !== "visit" || input.status === "Draft") {
    return;
  }

  const payload =
    input.payload && typeof input.payload === "object" && !Array.isArray(input.payload)
      ? (input.payload as Record<string, unknown>)
      : {};

  const implementationStatus = normalizeVisitImplementationStatus(
    payload.implementationStatus ?? payload.implementation_status,
  );

  const classesImplementing = parseStringList(
    payload.classesImplementing ?? payload.classes_implementing,
  );
  const classesNotImplementing = parseStringList(
    payload.classesNotImplementing ?? payload.classes_not_implementing,
  );

  if (implementationStatus === "partial") {
    if (classesImplementing.length === 0) {
      throw new Error("For partial implementation, select classes implementing.");
    }
    if (classesNotImplementing.length === 0) {
      throw new Error("For partial implementation, select classes not implementing.");
    }
  }

  const requiresObservation =
    implementationStatus === "started" || implementationStatus === "partial";
  if (requiresObservation) {
    const teacherObserved = readString(payload, ["teacherObserved"]);
    const classLevel = readString(payload, ["classLevel"]);
    if (!teacherObserved) {
      throw new Error("Teacher selection is required when implementation has started.");
    }
    if (!classLevel) {
      throw new Error("Class observed is required when implementation has started.");
    }
  }

  const requiresDemoAndMeeting =
    implementationStatus === "not_started" || implementationStatus === "partial";
  if (requiresDemoAndMeeting) {
    const demoClass = readString(payload, ["demoClass", "demo_class"]);
    const demoFocus = readString(payload, ["demoFocus", "demo_focus"]);
    const demoMinutes = Number(payload.demoMinutes ?? payload.demo_minutes ?? 0);
    const demoTeachers = parseIdArray(
      payload.demoTeachersPresentContactIds ?? payload.demo_teachers_present_contact_ids,
    );
    const demoTakeaways = readString(payload, ["demoTakeawaysText", "takeaways_text"]);
    if (!demoClass) {
      throw new Error("Demo class is required for demo + meeting visits.");
    }
    if (!demoFocus) {
      throw new Error("Demo focus is required for demo + meeting visits.");
    }
    if (!Number.isFinite(demoMinutes) || demoMinutes <= 0) {
      throw new Error("Demo period length (minutes) is required for demo + meeting visits.");
    }
    if (demoTeachers.length === 0) {
      throw new Error("Select at least one teacher present for the lesson demo.");
    }
    if (!demoTakeaways) {
      throw new Error("Key demonstration takeaways are required.");
    }

    const startDate = parseDateString(payload.implementationStartDate ?? payload.start_date);
    const dailyReadingMinutes = Number(
      payload.dailyReadingTimeMinutes ?? payload.daily_reading_time_minutes ?? 0,
    );
    const classesToStart = parseStringList(
      payload.classesToStartFirst ?? payload.classes_to_start_first,
    );
    const responsibleContactId = Number(
      payload.implementationResponsibleContactId ??
      payload.implementation_responsible_contact_id ??
      0,
    );
    if (!startDate) {
      throw new Error("Implementation start date is required.");
    }
    if (!Number.isFinite(dailyReadingMinutes) || dailyReadingMinutes <= 0) {
      throw new Error("Daily reading time agreed (minutes) is required.");
    }
    if (classesToStart.length === 0) {
      throw new Error("Select classes to start first.");
    }
    if (!Number.isInteger(responsibleContactId) || responsibleContactId <= 0) {
      throw new Error("Responsible person at school is required.");
    }

    const leadershipSummary = readString(payload, ["leadershipSummary", "summary_text"]);
    const leadershipAgreements = readString(payload, ["leadershipAgreements", "agreements_text"]);
    const leadershipRisks = readString(payload, ["leadershipRisks", "risks_text"]);
    const leadershipNextActions = parseVisitLeadershipNextActions(
      payload.leadershipNextActionsJson ?? payload.next_actions_json,
    );
    const leadershipNextVisitDate = parseDateString(
      payload.leadershipNextVisitDate ?? payload.next_visit_date,
    );
    if (!leadershipSummary) {
      throw new Error("Headteacher/DOS meeting summary is required.");
    }
    if (!leadershipAgreements) {
      throw new Error("Headteacher/DOS agreements are required.");
    }
    if (!leadershipRisks) {
      throw new Error("Risks/barriers discussed are required.");
    }
    if (leadershipNextActions.length === 0) {
      throw new Error("Add at least one leadership next action with owner and due date.");
    }
    if (!leadershipNextVisitDate) {
      throw new Error("Next visit date is required for demo + meeting visits.");
    }
  }
}

type InsightRecommendationWriteRow = {
  recId: string;
  priority: "high" | "medium" | "low";
  notes: string | null;
};

const recommendationCatalogIds = new Set(
  EXTENDED_RECOMMENDATION_CATALOG.map((item) => item.id.toLowerCase()),
);

function normalizeInsightPriority(value: unknown): "high" | "medium" | "low" {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase();
  if (normalized === "high") {
    return "high";
  }
  if (normalized === "low") {
    return "low";
  }
  return "medium";
}

function normalizeInsightText(value: unknown): string | null {
  const text = String(value ?? "").trim();
  return text ? text : null;
}

function parseInsightRecommendationRows(payload: Record<string, unknown>): InsightRecommendationWriteRow[] {
  const rowsById = new Map<string, InsightRecommendationWriteRow>();

  const recJsonRaw = payload.insightsRecommendationsRecJson;
  if (typeof recJsonRaw === "string" && recJsonRaw.trim()) {
    try {
      const parsed = JSON.parse(recJsonRaw);
      if (Array.isArray(parsed)) {
        parsed.forEach((entry) => {
          if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
            return;
          }
          const row = entry as Record<string, unknown>;
          const recId = String(row.recId ?? row.id ?? "")
            .trim()
            .toUpperCase();
          if (!recId || !recommendationCatalogIds.has(recId.toLowerCase())) {
            return;
          }
          rowsById.set(recId, {
            recId,
            priority: normalizeInsightPriority(row.priority),
            notes: normalizeInsightText(row.notes),
          });
        });
      }
    } catch {
      // Ignore malformed draft recommendation payload and continue with recIds.
    }
  }

  const rawRecIds = payload.insightsRecommendationsRecIds;
  if (Array.isArray(rawRecIds)) {
    rawRecIds.forEach((entry) => {
      const recId = String(entry ?? "")
        .trim()
        .toUpperCase();
      if (!recId || !recommendationCatalogIds.has(recId.toLowerCase())) {
        return;
      }
      const existing = rowsById.get(recId);
      rowsById.set(recId, existing ?? { recId, priority: "medium", notes: null });
    });
  } else if (typeof rawRecIds === "string" && rawRecIds.trim()) {
    rawRecIds
      .split(",")
      .map((entry) => entry.trim().toUpperCase())
      .filter(Boolean)
      .forEach((recId) => {
        if (!recommendationCatalogIds.has(recId.toLowerCase())) {
          return;
        }
        const existing = rowsById.get(recId);
        rowsById.set(recId, existing ?? { recId, priority: "medium", notes: null });
      });
  }

  return [...rowsById.values()];
}

function assertStandardizedInsightsPayload(input: PortalRecordInput) {
  if (input.status === "Draft") {
    return;
  }
  if (!["training", "visit", "assessment", "story"].includes(input.module)) {
    return;
  }

  const payload =
    input.payload && typeof input.payload === "object" && !Array.isArray(input.payload)
      ? (input.payload as Record<string, unknown>)
      : {};

  const keyFindings = normalizeInsightText(payload.insightsKeyFindings);
  if (!keyFindings) {
    throw new Error("Key findings are required for final submission.");
  }

  const conclusionsNextSteps = normalizeInsightText(payload.insightsConclusionsNextSteps);
  if (!conclusionsNextSteps) {
    throw new Error("Conclusions + next steps are required for final submission.");
  }

  const recommendationRows = parseInsightRecommendationRows(payload);
  if (recommendationRows.length === 0) {
    throw new Error("Select at least one REC recommendation for final submission.");
  }
}

function mapModuleToInsightActivityType(module: PortalRecordModule):
  "training" | "visit" | "assessment" | "story_activity" {
  if (module === "story") {
    return "story_activity";
  }
  return module;
}

function clearPortalActivityInsights(db: Database.Database, activityType: string, activityId: number) {
  db.prepare(
    `
      DELETE FROM activity_insights
      WHERE activity_type = @activityType
        AND activity_id = @activityId
    `,
  ).run({
    activityType,
    activityId,
  });
}

function syncPortalRecordInsights(
  db: Database.Database,
  args: {
    recordId: number;
    module: PortalRecordModule;
    payload: Record<string, unknown>;
    schoolId: number;
    userId: number;
    status: PortalRecordStatus;
  },
) {
  if (!["training", "visit", "assessment", "story"].includes(args.module)) {
    return;
  }

  const activityType = mapModuleToInsightActivityType(args.module);
  const keyFindings = normalizeInsightText(args.payload.insightsKeyFindings);
  const whatWentWell = normalizeInsightText(args.payload.insightsWhatWentWell);
  const challenges = normalizeInsightText(args.payload.insightsChallenges);
  const conclusionsNextSteps = normalizeInsightText(args.payload.insightsConclusionsNextSteps);
  const recommendationRows = parseInsightRecommendationRows(args.payload);
  const isDraft = args.status === "Draft";
  const isEmptyInsight =
    !keyFindings &&
    !whatWentWell &&
    !challenges &&
    !conclusionsNextSteps &&
    recommendationRows.length === 0;

  if (isDraft && isEmptyInsight) {
    clearPortalActivityInsights(db, activityType, args.recordId);
    return;
  }

  const existing = db
    .prepare(
      `
      SELECT insights_id AS insightsId
      FROM activity_insights
      WHERE activity_type = @activityType
        AND activity_id = @activityId
        AND scope_type = 'school'
        AND scope_id = @scopeId
      LIMIT 1
      `,
    )
    .get({
      activityType,
      activityId: args.recordId,
      scopeId: String(args.schoolId),
    }) as { insightsId: number } | undefined;

  let insightsId = existing?.insightsId ?? null;
  if (insightsId) {
    db.prepare(
      `
      UPDATE activity_insights
      SET
        key_findings = @keyFindings,
        what_went_well = @whatWentWell,
        challenges = @challenges,
        conclusions_next_steps = @conclusionsNextSteps,
        created_by_user_id = @createdByUserId,
        finalized = @finalized,
        updated_at = datetime('now')
      WHERE insights_id = @insightsId
      `,
    ).run({
      insightsId,
      keyFindings,
      whatWentWell,
      challenges,
      conclusionsNextSteps,
      createdByUserId: args.userId,
      finalized: isDraft ? 0 : 1,
    });
  } else {
    const insert = db
      .prepare(
        `
        INSERT INTO activity_insights (
          activity_type,
          activity_id,
          scope_type,
          scope_id,
          key_findings,
          what_went_well,
          challenges,
          conclusions_next_steps,
          created_by_user_id,
          finalized,
          created_at,
          updated_at
        ) VALUES (
          @activityType,
          @activityId,
          'school',
          @scopeId,
          @keyFindings,
          @whatWentWell,
          @challenges,
          @conclusionsNextSteps,
          @createdByUserId,
          @finalized,
          datetime('now'),
          datetime('now')
        )
        `,
      )
      .run({
        activityType,
        activityId: args.recordId,
        scopeId: String(args.schoolId),
        keyFindings,
        whatWentWell,
        challenges,
        conclusionsNextSteps,
        createdByUserId: args.userId,
        finalized: isDraft ? 0 : 1,
      });
    insightsId = Number(insert.lastInsertRowid);
  }

  if (!insightsId) {
    return;
  }

  db.prepare("DELETE FROM activity_recommendations WHERE insights_id = @insightsId").run({
    insightsId,
  });
  if (recommendationRows.length === 0) {
    return;
  }

  const insertRecommendation = db.prepare(
    `
      INSERT INTO activity_recommendations (
        insights_id,
        rec_id,
        priority,
        notes,
        created_at
      ) VALUES (
        @insightsId,
        @recId,
        @priority,
        @notes,
        datetime('now')
      )
    `,
  );
  recommendationRows.forEach((row) => {
    insertRecommendation.run({
      insightsId,
      recId: row.recId,
      priority: row.priority,
      notes: row.notes,
    });
  });
}

function getSchoolDirectoryRecordById(id: number) {
  const row = getDb()
    .prepare(
      `
    SELECT
    id,
      school_uid AS schoolUid,
        school_code AS schoolCode,
          name,
          COALESCE(region, '') AS region,
            COALESCE(sub_region, '') AS subRegion,
              district,
              sub_county AS subCounty,
                parish,
                village,
                CASE
          WHEN COALESCE(enrollment_total, 0) > 0 THEN COALESCE(enrollment_total, 0)
          WHEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0) > 0
            THEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0)
          ELSE COALESCE(enrolled_learners, 0)
        END AS enrollmentTotal,
      enrollment_by_grade AS enrollmentByGrade,
        enrolled_boys AS enrolledBoys,
          enrolled_girls AS enrolledGirls,
            COALESCE(enrolled_baby, 0) AS enrolledBaby,
              COALESCE(enrolled_middle, 0) AS enrolledMiddle,
                COALESCE(enrolled_top, 0) AS enrolledTop,
                  COALESCE(enrolled_p1, 0) AS enrolledP1,
                    COALESCE(enrolled_p2, 0) AS enrolledP2,
                      COALESCE(enrolled_p3, 0) AS enrolledP3,
                        (
          COALESCE(enrolled_baby, 0) +
          COALESCE(enrolled_middle, 0) +
          COALESCE(enrolled_top, 0) +
          COALESCE(enrolled_p1, 0) +
          COALESCE(enrolled_p2, 0) +
          COALESCE(enrolled_p3, 0)
        ) AS directImpactLearners,
                        COALESCE(enrolled_p4, 0) AS enrolledP4,
                          COALESCE(enrolled_p5, 0) AS enrolledP5,
                            COALESCE(enrolled_p6, 0) AS enrolledP6,
                              COALESCE(enrolled_p7, 0) AS enrolledP7,
                                CASE
          WHEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0) > 0
            THEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0)
          ELSE COALESCE(enrolled_learners, 0)
        END AS enrolledLearners,
      gps_lat AS gpsLat,
        gps_lng AS gpsLng,
          contact_name AS contactName,
            contact_phone AS contactPhone,
              primary_contact_id AS primaryContactId,
                primary_contact.full_name AS primaryContactName,
                  primary_contact.category AS primaryContactCategory,
              COALESCE(program_status, 'active') AS programStatus,
                graduated_at AS graduatedAt,
                  graduated_by_user_id AS graduatedByUserId,
                      graduation_notes AS graduationNotes,
                        graduation_version AS graduationVersion,
              notes,
              schools_directory.created_at AS createdAt
      FROM schools_directory
      LEFT JOIN school_contacts primary_contact
        ON primary_contact.contact_id = schools_directory.primary_contact_id
      WHERE id = @id
      LIMIT 1
      `,
    )
    .get({ id }) as SchoolDirectoryRecord | undefined;

  return row ?? null;
}

function findSchoolByNormalizedName(name: string, excludeId?: number) {
  const normalizedName = name.trim().toLowerCase();
  if (!normalizedName) {
    return null;
  }

  const row = getDb()
    .prepare(
      `
      SELECT id, school_code AS schoolCode, name, district
      FROM schools_directory
      WHERE lower(trim(name)) = @normalizedName
        ${excludeId ? "AND id != @excludeId" : ""}
      LIMIT 1
      `,
    )
    .get(
      excludeId
        ? { normalizedName, excludeId }
        : { normalizedName },
    ) as { id: number; schoolCode: string; name: string; district: string } | undefined;

  return row ?? null;
}

function resolveDistrictCode(db: Database.Database, district: string) {
  const normalizedDistrict = district.trim();
  if (!normalizedDistrict) {
    return "";
  }

  const existing = db
    .prepare(
      `
      SELECT district_id AS districtId
      FROM schools_directory
      WHERE lower(trim(district)) = lower(trim(@district))
        AND district_id LIKE 'DT-%'
      ORDER BY id ASC
      LIMIT 1
      `,
    )
    .get({ district: normalizedDistrict }) as { districtId: string | null } | undefined;
  const existingSequence = parseCodeSequence(String(existing?.districtId ?? ""), "DT-");
  if (existingSequence) {
    return toPaddedCode("DT-", existingSequence, 3);
  }

  const rows = db
    .prepare(
      `
      SELECT district_id AS districtId
      FROM schools_directory
      WHERE district_id LIKE 'DT-%'
      `,
    )
    .all() as Array<{ districtId: string | null }>;
  let maxSequence = 0;
  rows.forEach((row) => {
    const parsed = parseCodeSequence(String(row.districtId ?? ""), "DT-");
    if (parsed && parsed > maxSequence) {
      maxSequence = parsed;
    }
  });

  return toPaddedCode("DT-", maxSequence + 1, 3);
}

function checkPortalDuplicate(
  db: Database.Database,
  module: PortalRecordModule,
  date: string,
  schoolId: number,
  schoolName: string,
  excludeId?: number,
) {
  const row = db
    .prepare(
      `
      SELECT id
      FROM portal_records
      WHERE module = @module
        AND date = @date
    AND(
      school_id = @schoolId
          OR(school_id IS NULL AND lower(trim(school_name)) = lower(trim(@schoolName)))
    )
        ${excludeId ? "AND id != @excludeId" : ""}
      LIMIT 1
    `,
    )
    .get({ module, date, schoolId, schoolName, excludeId }) as { id?: number } | undefined;

  return Boolean(row?.id);
}

export function createPortalRecord(input: PortalRecordInput, user: PortalUser): PortalRecord {
  const db = getDb();
  if (!input.schoolId || input.schoolId <= 0) {
    throw new Error("School selection is required.");
  }
  const trainingStatus = String(
    (input.payload as Record<string, unknown> | undefined)?.trainingStatus ?? "",
  )
    .trim()
    .toLowerCase();
  const isTrainingScheduled = input.module === "training" && trainingStatus === "scheduled";
  if (input.module === "training" && !isTrainingScheduled) {
    if (!input.followUpDate?.trim()) {
      throw new Error("Training follow-up date is required.");
    }
    if (!input.followUpType?.trim()) {
      throw new Error("Training follow-up type is required.");
    }
    if (!Number.isInteger(input.followUpOwnerUserId) || Number(input.followUpOwnerUserId) <= 0) {
      throw new Error("Training follow-up owner is required.");
    }
  }
  assertStandardizedInsightsPayload(input);
  assertSponsorshipPayload(input);
  assertVisitImplementationPayload(input);

  const school = getSchoolDirectoryRecordById(input.schoolId);
  if (!school) {
    throw new Error("Selected school account was not found.");
  }
  ensureSchoolHasPrimaryContact(school.id);

  if (checkPortalDuplicate(db, input.module, input.date, school.id, school.name)) {
    throw new Error(
      `Duplicate prevention: a ${input.module} entry already exists for this school and date.`,
    );
  }

  const payloadJson = normalizePayload(input);
  const payloadData = JSON.parse(payloadJson) as Record<string, unknown>;

  const id = db.transaction(() => {
    const insertResult = db
      .prepare(
        `
        INSERT INTO portal_records(
      record_code,
      module,
      date,
      district,
      school_id,
      school_name,
      program_type,
      status,
      follow_up_date,
      follow_up_type,
      follow_up_owner_user_id,
      payload_json,
      created_by_user_id,
      updated_by_user_id
    ) VALUES(
      @recordCode,
      @module,
      @date,
      @district,
      @schoolId,
      @schoolName,
      @programType,
      @status,
      @followUpDate,
      @followUpType,
      @followUpOwnerUserId,
      @payloadJson,
      @createdByUserId,
      @updatedByUserId
    )
      `,
      )
      .run({
        recordCode: `${recordCodePrefix[input.module]}-PENDING`,
        module: input.module,
        date: input.date,
        district: school.district,
        schoolId: school.id,
        schoolName: school.name,
        programType: input.programType ?? null,
        status: input.status,
        followUpDate: input.followUpDate ?? null,
        followUpType: input.followUpType ?? null,
        followUpOwnerUserId:
          Number.isInteger(input.followUpOwnerUserId) && Number(input.followUpOwnerUserId) > 0
            ? Number(input.followUpOwnerUserId)
            : null,
        payloadJson,
        createdByUserId: user.id,
        updatedByUserId: user.id,
      });

    const createdId = Number(insertResult.lastInsertRowid);
    const recordCode = formatRecordCode(input.module, createdId);
    db.prepare("UPDATE portal_records SET record_code = @recordCode WHERE id = @id").run({
      id: createdId,
      recordCode,
    });
    syncPortalRecordLinkages(db, {
      recordId: createdId,
      module: input.module,
      payload: payloadData,
      schoolId: school.id,
      date: input.date,
      programType: input.programType,
      followUpType: input.followUpType,
      followUpOwnerUserId: input.followUpOwnerUserId,
      userId: user.id,
    });
    syncPortalRecordInsights(db, {
      recordId: createdId,
      module: input.module,
      payload: payloadData,
      schoolId: school.id,
      userId: user.id,
      status: input.status,
    });

    logAuditEvent(
      user.id,
      user.fullName,
      "create",
      "portal_records",
      createdId,
      null,
      JSON.stringify(input),
      `Created ${input.module} record: ${recordCode} `,
    );

    return createdId;
  })();

  const record = getPortalRecordById(id, user);
  if (!record) {
    throw new Error("Could not load newly created record.");
  }

  if (input.module === "assessment" || input.module === "story" || input.module === "story_activity") {
    refreshSchoolGraduationEligibilityCache(school.id);
  }

  return record;
}

export function updatePortalRecord(
  id: number,
  input: PortalRecordInput,
  user: PortalUser,
): PortalRecord {
  const db = getDb();
  if (!input.schoolId || input.schoolId <= 0) {
    throw new Error("School selection is required.");
  }
  const trainingStatus = String(
    (input.payload as Record<string, unknown> | undefined)?.trainingStatus ?? "",
  )
    .trim()
    .toLowerCase();
  const isTrainingScheduled = input.module === "training" && trainingStatus === "scheduled";
  if (input.module === "training" && !isTrainingScheduled) {
    if (!input.followUpDate?.trim()) {
      throw new Error("Training follow-up date is required.");
    }
    if (!input.followUpType?.trim()) {
      throw new Error("Training follow-up type is required.");
    }
    if (!Number.isInteger(input.followUpOwnerUserId) || Number(input.followUpOwnerUserId) <= 0) {
      throw new Error("Training follow-up owner is required.");
    }
  }
  assertStandardizedInsightsPayload(input);
  assertSponsorshipPayload(input);
  assertVisitImplementationPayload(input);

  const school = getSchoolDirectoryRecordById(input.schoolId);
  if (!school) {
    throw new Error("Selected school account was not found.");
  }
  ensureSchoolHasPrimaryContact(school.id);

  const current = db
    .prepare(
      `
      SELECT id, created_by_user_id AS createdByUserId, status
      , school_id AS schoolId
      FROM portal_records
      WHERE id = @id
      LIMIT 1
    `,
    )
    .get({ id }) as
    | { id: number; createdByUserId: number; status: PortalRecordStatus; schoolId: number | null }
    | undefined;

  if (!current) {
    throw new Error("Record not found.");
  }

  const canEditOwn = current.createdByUserId === user.id && current.status !== "Approved";
  if (!(canEditOwn || canReviewRecords(user))) {
    throw new Error("You do not have permission to edit this record.");
  }

  if (checkPortalDuplicate(db, input.module, input.date, school.id, school.name, id)) {
    throw new Error(
      `Duplicate prevention: a ${input.module} entry already exists for this school and date.`,
    );
  }

  const payloadJson = normalizePayload(input);
  const payloadData = JSON.parse(payloadJson) as Record<string, unknown>;

  db.transaction(() => {
    db.prepare(
      `
      UPDATE portal_records
    SET
    module = @module,
      date = @date,
      district = @district,
      school_id = @schoolId,
      school_name = @schoolName,
      program_type = @programType,
      status = @status,
      follow_up_date = @followUpDate,
      follow_up_type = @followUpType,
      follow_up_owner_user_id = @followUpOwnerUserId,
      payload_json = @payloadJson,
      updated_by_user_id = @updatedByUserId,
      updated_at = datetime('now')
      WHERE id = @id
      `,
    ).run({
      id,
      module: input.module,
      date: input.date,
      district: school.district,
      schoolId: school.id,
      schoolName: school.name,
      programType: input.programType ?? null,
      status: input.status,
      followUpDate: input.followUpDate ?? null,
      followUpType: input.followUpType ?? null,
      followUpOwnerUserId:
        Number.isInteger(input.followUpOwnerUserId) && Number(input.followUpOwnerUserId) > 0
          ? Number(input.followUpOwnerUserId)
          : null,
      payloadJson,
      updatedByUserId: user.id,
    });

    syncPortalRecordLinkages(db, {
      recordId: id,
      module: input.module,
      payload: payloadData,
      schoolId: school.id,
      date: input.date,
      programType: input.programType,
      followUpType: input.followUpType,
      followUpOwnerUserId: input.followUpOwnerUserId,
      userId: user.id,
    });
    syncPortalRecordInsights(db, {
      recordId: id,
      module: input.module,
      payload: payloadData,
      schoolId: school.id,
      userId: user.id,
      status: input.status,
    });

    logAuditEvent(
      user.id,
      user.fullName,
      "update",
      "portal_records",
      id,
      JSON.stringify(current),
      JSON.stringify(input),
      `Updated ${input.module} record: ${id} `,
    );
  })();

  const updated = getPortalRecordById(id, user);
  if (!updated) {
    throw new Error("Could not load updated record.");
  }

  if (input.module === "assessment" || input.module === "story" || input.module === "story_activity") {
    refreshSchoolGraduationEligibilityCache(school.id);
    if (current.schoolId && Number(current.schoolId) !== school.id) {
      refreshSchoolGraduationEligibilityCache(Number(current.schoolId));
    }
  }

  return updated;
}

export function setPortalRecordStatus(
  id: number,
  status: PortalRecordStatus,
  user: PortalUser,
  reviewNote?: string,
) {
  if (!canReviewRecords(user)) {
    throw new Error("Only supervisors, M&E, or admins can approve/return records.");
  }

  const db = getDb();
  const current = db
    .prepare(
      `
      SELECT
        module,
        school_id AS schoolId,
        payload_json AS payloadJson
      FROM portal_records
      WHERE id = @id
      LIMIT 1
      `,
    )
    .get({ id }) as
    | {
      module: PortalRecordModule;
      schoolId: number | null;
      payloadJson: string;
    }
    | undefined;
  if (!current) {
    throw new Error("Record not found.");
  }
  const payload = safeParseObject(current.payloadJson);
  if (status !== "Draft") {
    assertStandardizedInsightsPayload({
      module: current.module,
      date: "",
      district: "",
      schoolName: "",
      status,
      schoolId: current.schoolId,
      payload: payload as PortalRecordPayload,
    });
  }

  db.prepare(
    `
    UPDATE portal_records
    SET
    status = @status,
      review_note = @reviewNote,
      updated_by_user_id = @updatedByUserId,
      updated_at = datetime('now')
    WHERE id = @id
      `,
  ).run({
    id,
    status,
    reviewNote: reviewNote?.trim() ? reviewNote : null,
    updatedByUserId: user.id,
  });

  if (Number.isInteger(current.schoolId) && Number(current.schoolId) > 0) {
    syncPortalRecordInsights(db, {
      recordId: id,
      module: current.module,
      payload,
      schoolId: Number(current.schoolId),
      userId: user.id,
      status,
    });
  }

  logAuditEvent(
    user.id,
    user.fullName,
    "set_status",
    "portal_records",
    id,
    null,
    JSON.stringify({ status, reviewNote }),
    `Set status to ${status} for record ${id}`,
  );

  const updated = getPortalRecordById(id, user);
  if (!updated) {
    throw new Error("Could not load updated record.");
  }

  return updated;
}

export function softDeletePortalRecord(
  id: number,
  user: PortalUser,
  reason: string,
): void {
  const db = getDb();
  const current = getPortalRecordById(id, user);

  if (!current) {
    throw new Error("Record not found or already deleted.");
  }

  // Only admins or the creator (if not approved) can delete
  const canDelete = user.isSuperAdmin || user.isAdmin || (current.createdByUserId === user.id && current.status !== "Approved");

  if (!canDelete) {
    throw new Error("You do not have permission to delete this record.");
  }

  db.prepare(`
    UPDATE portal_records
    SET
    deleted_at = datetime('now'),
      deleted_by_user_id = @userId,
      delete_reason = @reason,
      updated_at = datetime('now'),
      updated_by_user_id = @userId
    WHERE id = @id
      `).run({
    id,
    userId: user.id,
    reason: reason.trim() || "User requested deletion",
  });

  logAuditEvent(
    user.id,
    user.fullName,
    "delete",
    "portal_records",
    id,
    JSON.stringify(current),
    null,
    `Soft - deleted ${current.module} record ${id}.Reason: ${reason} `,
  );
}

export function getPortalRecordById(id: number, user: PortalUser): PortalRecord | null {
  const db = getDb();
  const row = db
    .prepare(
      `
    SELECT
    pr.id,
      pr.record_code AS recordCode,
        pr.module,
        pr.date,
        pr.district,
        pr.school_id AS schoolId,
          pr.school_name AS schoolName,
            pr.program_type AS programType,
              pr.status,
              pr.follow_up_date AS followUpDate,
              pr.follow_up_type AS followUpType,
              pr.follow_up_owner_user_id AS followUpOwnerUserId,
              pfu.full_name AS followUpOwnerName,
                pr.payload_json AS payloadJson,
                  pr.review_note AS reviewNote,
                    pr.created_by_user_id AS createdByUserId,
                      pu.full_name AS createdByName,
                        pr.created_at AS createdAt,
                          pr.updated_at AS updatedAt,
                            pr.deleted_at AS deletedAt,
                              pr.deleted_by_user_id AS deletedByUserId,
                                pr.delete_reason AS deleteReason
      FROM portal_records pr
      JOIN portal_users pu ON pu.id = pr.created_by_user_id
      LEFT JOIN portal_users pfu ON pfu.id = pr.follow_up_owner_user_id
      WHERE pr.id = @id AND pr.deleted_at IS NULL
      LIMIT 1
      `,
    )
    .get({ id }) as
    | {
      id: number;
      recordCode: string;
      module: PortalRecordModule;
      date: string;
      district: string;
      schoolId: number | null;
      schoolName: string;
      programType: string | null;
      status: PortalRecordStatus;
      followUpDate: string | null;
      followUpType: string | null;
      followUpOwnerUserId: number | null;
      followUpOwnerName: string | null;
      payloadJson: string;
      reviewNote: string | null;
      createdByUserId: number;
      createdByName: string;
      createdAt: string;
      updatedAt: string;
      deletedAt: string | null;
      deletedByUserId: number | null;
      deleteReason: string | null;
    }
    | undefined;

  if (!row) {
    return null;
  }

  if (!canViewAllRecords(user) && row.createdByUserId !== user.id) {
    return null;
  }

  return parsePortalRecord(row);
}

export function listPortalRecords(filters: PortalRecordFilters, user: PortalUser): PortalRecord[] {
  const whereClauses = ["pr.module = @module"];
  const params: Record<string, string | number> = { module: filters.module };

  if (!canViewAllRecords(user)) {
    whereClauses.push("pr.created_by_user_id = @currentUserId");
    params.currentUserId = user.id;
  } else if (user.role === "Staff" && user.geographyScope) {
    // If staff and have a scope (e.g. "district:Bungoma" or "region:Western")
    const [scopeType, scopeValue] = user.geographyScope.split(":");
    if (scopeType === "district") {
      whereClauses.push("lower(pr.district) = lower(@scopedDistrict)");
      params.scopedDistrict = scopeValue;
    } else if (scopeType === "region") {
      // We'll need a join or subquery if region isn't on portal_records, 
      // but usually district is enough for staff. 
      // For now, let's stick to district-based scoping if provided.
    }
  }

  if (filters.dateFrom) {
    whereClauses.push("pr.date >= @dateFrom");
    params.dateFrom = filters.dateFrom;
  }
  if (filters.dateTo) {
    whereClauses.push("pr.date <= @dateTo");
    params.dateTo = filters.dateTo;
  }
  if (filters.district) {
    whereClauses.push("lower(pr.district) LIKE lower(@district)");
    params.district = `% ${filters.district}% `;
  }
  if (filters.school) {
    whereClauses.push("lower(pr.school_name) LIKE lower(@school)");
    params.school = `% ${filters.school}% `;
  }
  if (filters.status) {
    whereClauses.push("pr.status = @status");
    params.status = filters.status;
  }
  if (filters.createdBy && canViewAllRecords(user)) {
    whereClauses.push("pr.created_by_user_id = @createdBy");
    params.createdBy = filters.createdBy;
  }
  if (filters.programType) {
    whereClauses.push("lower(pr.program_type) LIKE lower(@programType)");
    params.programType = `% ${filters.programType}% `;
  }

  const rows = getDb()
    .prepare(
      `
    SELECT
    pr.id,
      pr.record_code AS recordCode,
        pr.module,
        pr.date,
        pr.district,
        pr.school_id AS schoolId,
          pr.school_name AS schoolName,
            pr.program_type AS programType,
              pr.status,
              pr.follow_up_date AS followUpDate,
              pr.follow_up_type AS followUpType,
              pr.follow_up_owner_user_id AS followUpOwnerUserId,
              pfu.full_name AS followUpOwnerName,
                pr.payload_json AS payloadJson,
                  pr.review_note AS reviewNote,
                    pr.created_by_user_id AS createdByUserId,
                      pu.full_name AS createdByName,
                        pr.created_at AS createdAt,
                          pr.updated_at AS updatedAt,
                            pr.deleted_at AS deletedAt,
                              pr.deleted_by_user_id AS deletedByUserId,
                                pr.delete_reason AS deleteReason
      FROM portal_records pr
      JOIN portal_users pu ON pu.id = pr.created_by_user_id
      LEFT JOIN portal_users pfu ON pfu.id = pr.follow_up_owner_user_id
      WHERE ${whereClauses.join(" AND ")} AND pr.deleted_at IS NULL
      ORDER BY pr.date DESC, pr.updated_at DESC
      LIMIT 300
      `,
    )
    .all(params) as Array<{
      id: number;
      recordCode: string;
      module: PortalRecordModule;
      date: string;
      district: string;
      schoolId: number | null;
      schoolName: string;
      programType: string | null;
      status: PortalRecordStatus;
      followUpDate: string | null;
      followUpType: string | null;
      followUpOwnerUserId: number | null;
      followUpOwnerName: string | null;
      payloadJson: string;
      reviewNote: string | null;
      createdByUserId: number;
      createdByName: string;
      createdAt: string;
      updatedAt: string;
      deletedAt: string | null;
      deletedByUserId: number | null;
      deleteReason: string | null;
    }>;

  return rows.map((row) => parsePortalRecord(row));
}

function getWeekBounds() {
  const now = new Date();
  const day = now.getDay();
  const diffToMonday = (day + 6) % 7;
  const monday = new Date(now);
  monday.setDate(now.getDate() - diffToMonday);
  monday.setHours(0, 0, 0, 0);

  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  sunday.setHours(23, 59, 59, 999);

  return {
    from: monday.toISOString().slice(0, 10),
    to: sunday.toISOString().slice(0, 10),
  };
}

function getTodayPlusDays(days: number) {
  const date = new Date();
  date.setDate(date.getDate() + days);
  return date.toISOString().slice(0, 10);
}

export function getPortalDashboardData(user: PortalUser): PortalDashboardData {
  const db = getDb();
  const weekBounds = getWeekBounds();
  const today = new Date().toISOString().slice(0, 10);
  const weekAhead = getTodayPlusDays(7);

  const baseUserFilter = canViewAllRecords(user) ? "" : "AND created_by_user_id = @currentUserId";
  const baseParams = canViewAllRecords(user) ? {} : { currentUserId: user.id };

  const kpiRows = db
    .prepare(
      `
      SELECT module, COUNT(*) AS total
      FROM portal_records
      WHERE date >= @from AND date <= @to
      ${baseUserFilter}
      GROUP BY module
      `,
    )
    .all({ ...baseParams, from: weekBounds.from, to: weekBounds.to }) as Array<{
      module: PortalRecordModule;
      total: number;
    }>;

  const agendaRows = db
    .prepare(
      `
    SELECT
    id,
      record_code AS recordCode,
        module,
        date,
        school_name AS schoolName,
          program_type AS programType
      FROM portal_records
      WHERE date >= @today
        AND date <= @weekAhead
        ${baseUserFilter}
      ORDER BY date ASC, id ASC
      LIMIT 15
      `,
    )
    .all({ ...baseParams, today, weekAhead }) as DashboardAgendaItem[];

  const followUpRows = db
    .prepare(
      `
    SELECT
    id,
      record_code AS recordCode,
        module,
        school_name AS schoolName,
          follow_up_date AS followUpDate
      FROM portal_records
      WHERE follow_up_date IS NOT NULL
        AND follow_up_date <= @today
        AND status != 'Approved'
        ${baseUserFilter}
      ORDER BY follow_up_date ASC
      LIMIT 12
      `,
    )
    .all({ ...baseParams, today }) as DashboardFollowUpItem[];

  const recentRows = db
    .prepare(
      `
    SELECT
    id,
      record_code AS recordCode,
        module,
        date,
        school_name AS schoolName,
          status,
          updated_at AS updatedAt
      FROM portal_records
      WHERE 1 = 1
        ${baseUserFilter}
      ORDER BY updated_at DESC
      LIMIT 10
      `,
    )
    .all(baseParams) as DashboardActivityItem[];

  const getCount = (module: PortalRecordModule) =>
    Number(kpiRows.find((row) => row.module === module)?.total ?? 0);

  const learnersResult = db
    .prepare("SELECT SUM(enrolled_learners) as total FROM schools_directory")
    .get() as { total: number };
  const totalLearners = learnersResult?.total ?? 0;

  const visitRows = db
    .prepare(
      `
      SELECT
        school_id AS schoolId,
        school_name AS schoolName,
        district,
        date,
        payload_json AS payloadJson
      FROM portal_records
      WHERE module = 'visit'
        AND deleted_at IS NULL
        ${baseUserFilter}
      ORDER BY date DESC, id DESC
      `,
    )
    .all(baseParams) as Array<{
      schoolId: number | null;
      schoolName: string;
      district: string;
      date: string;
      payloadJson: string;
    }>;

  const latestBySchool = new Map<
    string,
    {
      date: string;
      implementationStatus: VisitImplementationStatus;
      visitPathway: VisitPathway;
    }
  >();
  let demoVisitsConducted = 0;

  visitRows.forEach((row) => {
    let payload: Record<string, unknown> = {};
    try {
      const parsed = JSON.parse(row.payloadJson || "{}") as unknown;
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        payload = parsed as Record<string, unknown>;
      }
    } catch {
      payload = {};
    }

    const implementationStatus = normalizeVisitImplementationStatus(
      payload.implementationStatus ?? payload.implementation_status,
    );
    const visitPathway = normalizeVisitPathway(
      implementationStatus,
      payload.visitPathway ?? payload.visit_pathway,
    );
    if (visitPathway === "demo_and_meeting" || visitPathway === "mixed") {
      demoVisitsConducted += 1;
    }

    const key =
      Number.isInteger(row.schoolId) && Number(row.schoolId) > 0
        ? `id:${Number(row.schoolId)}`
        : `name:${row.schoolName.trim().toLowerCase()}|${row.district.trim().toLowerCase()}`;
    const current = latestBySchool.get(key);
    if (!current || row.date >= current.date) {
      latestBySchool.set(key, {
        date: row.date,
        implementationStatus,
        visitPathway,
      });
    }
  });

  const schoolsWithImplementationData = latestBySchool.size;
  const implementingSchools = [...latestBySchool.values()].filter(
    (entry) =>
      entry.implementationStatus === "started" || entry.implementationStatus === "partial",
  ).length;
  const notImplementingSchools = [...latestBySchool.values()].filter(
    (entry) => entry.implementationStatus === "not_started",
  ).length;
  const schoolsImplementingPercent =
    schoolsWithImplementationData > 0
      ? Number(((implementingSchools / schoolsWithImplementationData) * 100).toFixed(1))
      : 0;
  const schoolsNotImplementingPercent =
    schoolsWithImplementationData > 0
      ? Number(((notImplementingSchools / schoolsWithImplementationData) * 100).toFixed(1))
      : 0;

  return {
    kpis: {
      trainingsLogged: getCount("training"),
      schoolVisits: getCount("visit"),
      assessments: getCount("assessment"),
      storyActivities: getCount("story"),
      learnersReached: totalLearners,
      schoolsImplementingPercent,
      schoolsNotImplementingPercent,
      demoVisitsConducted,
    },
    weekAgenda: agendaRows,
    dueFollowUps: followUpRows,
    recentActivity: recentRows,
  };
}

export function createSchoolDirectoryRecord(input: SchoolDirectoryInput): SchoolDirectoryRecord {
  const db = getDb();
  const normalizedName = input.name.trim();
  const normalizedDistrict = input.district.trim();
  const normalizedSubCounty = input.subCounty?.trim() || "Unspecified";
  const normalizedParish = input.parish?.trim() || "Unspecified";
  const normalizedRegion = inferRegionFromDistrict(normalizedDistrict) ?? "";
  const normalizedSubRegion = inferSubRegionFromDistrict(normalizedDistrict) ?? "";
  const enrolledBoys = Math.max(0, Math.floor(Number(input.enrolledBoys ?? 0)));
  const enrolledGirls = Math.max(0, Math.floor(Number(input.enrolledGirls ?? 0)));
  const enrolledBaby = Math.max(0, Math.floor(Number(input.enrolledBaby ?? 0)));
  const enrolledMiddle = Math.max(0, Math.floor(Number(input.enrolledMiddle ?? 0)));
  const enrolledTop = Math.max(0, Math.floor(Number(input.enrolledTop ?? 0)));
  const enrolledP1 = Math.max(0, Math.floor(Number(input.enrolledP1 ?? 0)));
  const enrolledP2 = Math.max(0, Math.floor(Number(input.enrolledP2 ?? 0)));
  const enrolledP3 = Math.max(0, Math.floor(Number(input.enrolledP3 ?? 0)));
  const enrolledP4 = Math.max(0, Math.floor(Number(input.enrolledP4 ?? 0)));
  const enrolledP5 = Math.max(0, Math.floor(Number(input.enrolledP5 ?? 0)));
  const enrolledP6 = Math.max(0, Math.floor(Number(input.enrolledP6 ?? 0)));
  const enrolledP7 = Math.max(0, Math.floor(Number(input.enrolledP7 ?? 0)));
  const directImpactEnrollment =
    enrolledBaby +
    enrolledMiddle +
    enrolledTop +
    enrolledP1 +
    enrolledP2 +
    enrolledP3;
  const generalEnrollment = enrolledBoys + enrolledGirls;
  const providedEnrollmentTotal =
    input.enrollmentTotal !== undefined
      ? Math.max(0, Math.floor(Number(input.enrollmentTotal)))
      : null;
  const enrollmentTotal =
    generalEnrollment > 0
      ? generalEnrollment
      : Math.max(0, providedEnrollmentTotal ?? directImpactEnrollment);
  const primaryContactName = input.proprietor.fullName.trim();
  const primaryContactGender = input.proprietor.gender;
  const primaryContactPhone = input.proprietor.phone?.trim() || "";
  const primaryContactCategory = normalizeSchoolContactCategory(
    input.proprietor.category ?? input.proprietor.roleTitle ?? "Proprietor",
  );

  if (!normalizedName) {
    throw new Error("School name is required.");
  }
  if (!normalizedDistrict) {
    throw new Error("District is required.");
  }
  if (!Number.isFinite(enrollmentTotal)) {
    throw new Error("Enrollment total must be a valid number.");
  }
  if (!primaryContactName) {
    throw new Error("A primary contact is required.");
  }

  const duplicateSchool = findSchoolByNormalizedName(normalizedName);
  if (duplicateSchool) {
    throw new Error(
      "A school with this name already exists. Append location details (district/sub-county/parish) to distinguish it.",
    );
  }

  const id = db.transaction(() => {
    const insertResult = db
      .prepare(
        `
        INSERT INTO schools_directory(
          school_uid,
          school_code,
          name,
          region,
          sub_region,
          region_id,
          subregion_id,
          district_id,
          district,
          sub_county,
          parish,
          village,
          enrollment_total,
          enrollment_by_grade,
          enrolled_boys,
          enrolled_girls,
          enrolled_baby,
          enrolled_middle,
          enrolled_top,
          enrolled_p1,
          enrolled_p2,
          enrolled_p3,
          enrolled_p4,
          enrolled_p5,
          enrolled_p6,
          enrolled_p7,
          enrolled_learners,
          gps_lat,
          gps_lng,
          contact_name,
          contact_phone,
          notes
        ) VALUES(
          @schoolUid,
          @schoolCode,
          @name,
          @region,
          @subRegion,
          @regionId,
          @subregionId,
          @districtId,
          @district,
          @subCounty,
          @parish,
          @village,
          @enrollmentTotal,
          @enrollmentByGrade,
          @enrolledBoys,
          @enrolledGirls,
          @enrolledBaby,
          @enrolledMiddle,
          @enrolledTop,
          @enrolledP1,
          @enrolledP2,
          @enrolledP3,
          @enrolledP4,
          @enrolledP5,
          @enrolledP6,
          @enrolledP7,
          @enrolledLearners,
          @gpsLat,
          @gpsLng,
          @contactName,
          @contactPhone,
          @notes
        )
      `,
      )
      .run({
        schoolUid: createGeneratedUid("sch"),
        schoolCode: "S-PENDING",
        name: normalizedName,
        region: normalizedRegion,
        subRegion: normalizedSubRegion,
        regionId: stableIdFromText("reg", normalizedRegion),
        subregionId: stableIdFromText("sub", normalizedSubRegion),
        districtId: resolveDistrictCode(db, normalizedDistrict),
        district: normalizedDistrict,
        subCounty: normalizedSubCounty,
        parish: normalizedParish,
        village: input.village?.trim() ? input.village : null,
        enrollmentTotal,
        enrollmentByGrade: input.enrollmentByGrade?.trim() ? input.enrollmentByGrade.trim() : null,
        enrolledBoys,
        enrolledGirls,
        enrolledBaby,
        enrolledMiddle,
        enrolledTop,
        enrolledP1,
        enrolledP2,
        enrolledP3,
        enrolledP4,
        enrolledP5,
        enrolledP6,
        enrolledP7,
        enrolledLearners: enrollmentTotal,
        gpsLat: input.gpsLat?.trim() ? input.gpsLat : null,
        gpsLng: input.gpsLng?.trim() ? input.gpsLng : null,
        contactName: primaryContactName,
        contactPhone: primaryContactPhone || input.contactPhone?.trim() || null,
        notes: input.notes?.trim() ? input.notes.trim() : null,
      });

    const schoolId = Number(insertResult.lastInsertRowid);
    const schoolCode = toPaddedCode("S-", schoolId, 4);
    db.prepare("UPDATE schools_directory SET school_code = @schoolCode WHERE id = @id").run({
      id: schoolId,
      schoolCode,
    });

    addSchoolContactToSchool({
      schoolId,
      fullName: primaryContactName,
      gender: primaryContactGender,
      phone: primaryContactPhone || undefined,
      email: input.proprietor.email?.trim() || undefined,
      whatsapp: input.proprietor.whatsapp?.trim() || undefined,
      category: primaryContactCategory,
      roleTitle: input.proprietor.roleTitle?.trim() || primaryContactCategory,
      isPrimaryContact: true,
    });

    return schoolId;
  })();

  const row = getSchoolDirectoryRecordById(id);
  if (!row) {
    throw new Error("Could not load created school.");
  }

  return row;
}

export function getReportPreviewStats(input: {
  user: PortalUser;
  scopeType: ImpactReportScopeType;
  scopeValue: string;
  periodStart: string;
  periodEnd: string;
  programsIncluded: ImpactReportProgramType[];
}) {
  const { startDate, endDate } = normalizeDateRange(input.periodStart, input.periodEnd);
  const scopeValue = normalizeScopeValue(input.scopeType, input.scopeValue);
  const scopeSet = resolveGeoScope(input.scopeType, scopeValue);

  const portalRows = listScopedPortalRows(
    input.user,
    startDate,
    endDate,
    input.scopeType,
    scopeSet,
    input.programsIncluded,
  );

  const schoolsImpacted = new Set(
    portalRows.map((row) => row.schoolName.trim().toLowerCase()).filter(Boolean),
  );

  if (input.programsIncluded.includes("training")) {
    const legacySessions = listScopedLegacyTrainingSessions(
      input.user,
      startDate,
      endDate,
      input.scopeType,
      scopeSet,
    );
    legacySessions.forEach((session) => {
      schoolsImpacted.add(session.schoolName.trim().toLowerCase());
    });
  }

  let learnersAssessed = 0;
  const linkedPortalAssessmentIds = new Set<number>();

  if (input.programsIncluded.includes("assessment")) {
    const assessmentAnalytics = collectScopedAssessmentAnalytics({
      user: input.user,
      startDate,
      endDate,
      scopeType: input.scopeType,
      scopeSet,
    });
    learnersAssessed += assessmentAnalytics.learnersAssessed;
    assessmentAnalytics.schoolsImpacted.forEach((schoolKey) => {
      schoolsImpacted.add(schoolKey);
    });
    assessmentAnalytics.linkedPortalRecordIds.forEach((recordId) => {
      linkedPortalAssessmentIds.add(recordId);
    });

    portalRows
      .filter((row) => row.module === "assessment" && !linkedPortalAssessmentIds.has(row.id))
      .forEach((row) => {
        learnersAssessed += Number(readNumeric(row.payload, ["learnersAssessed"]) ?? 0);
        const schoolKey = row.schoolName.trim().toLowerCase();
        if (schoolKey) {
          schoolsImpacted.add(schoolKey);
        }
      });
  }

  if (input.programsIncluded.includes("assessment")) {
    const db = getDb();
    const canViewAll = canViewAllRecords(input.user);
    const legacyFilter = canViewAll ? "" : "AND ar.created_by_user_id = @currentUserId";
    const params = canViewAll
      ? { startDate, endDate }
      : { startDate, endDate, currentUserId: input.user.id };

    const legacyRows = db
      .prepare(
        `
    SELECT
    ar.school_name AS schoolName,
      ar.district,
      ar.learners_assessed AS learnersAssessed
        FROM legacy_assessment_records ar
        WHERE ar.assessment_date >= @startDate
          AND ar.assessment_date <= @endDate
          ${legacyFilter}
    `,
      )
      .all(params) as Array<{
        schoolName: string;
        district: string;
        learnersAssessed: number;
      }>;

    legacyRows
      .filter((row) => scopeSetMatches(input.scopeType, scopeSet, row.district, row.schoolName))
      .forEach((row) => {
        schoolsImpacted.add(row.schoolName.trim().toLowerCase());
        learnersAssessed += Number(row.learnersAssessed ?? 0);
      });
  }

  return {
    schoolsIncluded: schoolsImpacted.size,
    learnersAssessed,
    dataCompleteness: "Complete" as const,
  };
}

export function updateSchoolDirectoryRecord(
  schoolId: number,
  input: {
    name?: string;
    district?: string;
    subCounty?: string;
    parish?: string;
    village?: string | null;
    enrollmentTotal?: number;
    enrollmentByGrade?: string | null;
    enrolledBoys?: number;
    enrolledGirls?: number;
    enrolledBaby?: number;
    enrolledMiddle?: number;
    enrolledTop?: number;
    enrolledP1?: number;
    enrolledP2?: number;
    enrolledP3?: number;
    enrolledP4?: number;
    enrolledP5?: number;
    enrolledP6?: number;
    enrolledP7?: number;
    gpsLat?: string | null;
    gpsLng?: string | null;
    contactName?: string | null;
    contactPhone?: string | null;
    notes?: string | null;
  },
): SchoolDirectoryRecord {
  const current = getSchoolDirectoryRecordById(schoolId);
  if (!current) {
    throw new Error("School not found.");
  }

  const updates: string[] = [];
  const params: Record<string, unknown> = { schoolId };

  if (input.name !== undefined) {
    const value = input.name.trim();
    if (!value) {
      throw new Error("School name is required.");
    }
    const duplicateSchool = findSchoolByNormalizedName(value, schoolId);
    if (duplicateSchool) {
      throw new Error(
        "A school with this name already exists. Append location details (district/sub-county/parish) to distinguish it.",
      );
    }
    updates.push("name = @name");
    params.name = value;
  }
  if (input.district !== undefined) {
    const value = input.district.trim();
    if (!value) {
      throw new Error("District is required.");
    }
    updates.push("district = @district");
    updates.push("region = @region");
    updates.push("sub_region = @subRegion");
    updates.push("district_id = @districtId");
    updates.push("region_id = @regionId");
    updates.push("subregion_id = @subregionId");
    params.district = value;
    const region = inferRegionFromDistrict(value) ?? "";
    const subRegion = inferSubRegionFromDistrict(value) ?? "";
    params.region = region;
    params.subRegion = subRegion;
    params.districtId = resolveDistrictCode(getDb(), value);
    params.regionId = stableIdFromText("reg", region);
    params.subregionId = stableIdFromText("sub", subRegion);
  }
  if (input.subCounty !== undefined) {
    const value = input.subCounty.trim();
    if (!value) {
      throw new Error("Sub-county is required.");
    }
    updates.push("sub_county = @subCounty");
    params.subCounty = value;
  }
  if (input.parish !== undefined) {
    const value = input.parish.trim();
    if (!value) {
      throw new Error("Parish is required.");
    }
    updates.push("parish = @parish");
    params.parish = value;
  }
  if (input.village !== undefined) {
    const value = input.village?.trim();
    updates.push("village = @village");
    params.village = value ? value : null;
  }
  if (input.enrollmentByGrade !== undefined) {
    const value = input.enrollmentByGrade?.trim();
    updates.push("enrollment_by_grade = @enrollmentByGrade");
    params.enrollmentByGrade = value ? value : null;
  }
  if (input.enrollmentTotal !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrollmentTotal)));
    if (!Number.isFinite(value)) {
      throw new Error("Enrollment total must be a valid number.");
    }
    updates.push("enrollment_total = @enrollmentTotal");
    updates.push("enrolled_learners = @enrolledLearners");
    params.enrollmentTotal = value;
    params.enrolledLearners = value;
  }
  if (input.enrolledBoys !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledBoys)));
    if (!Number.isFinite(value)) {
      throw new Error("Enrolled boys must be a valid number.");
    }
    updates.push("enrolled_boys = @enrolledBoys");
    params.enrolledBoys = value;
  }
  if (input.enrolledGirls !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledGirls)));
    if (!Number.isFinite(value)) {
      throw new Error("Enrolled girls must be a valid number.");
    }
    updates.push("enrolled_girls = @enrolledGirls");
    params.enrolledGirls = value;
  }
  if (input.gpsLat !== undefined) {
    const value = input.gpsLat?.trim();
    updates.push("gps_lat = @gpsLat");
    params.gpsLat = value ? value : null;
  }
  if (input.gpsLng !== undefined) {
    const value = input.gpsLng?.trim();
    updates.push("gps_lng = @gpsLng");
    params.gpsLng = value ? value : null;
  }
  if (input.contactName !== undefined) {
    const value = input.contactName?.trim();
    updates.push("contact_name = @contactName");
    params.contactName = value ? value : null;
  }
  if (input.contactPhone !== undefined) {
    const value = input.contactPhone?.trim();
    updates.push("contact_phone = @contactPhone");
    params.contactPhone = value ? value : null;
  }
  if (input.notes !== undefined) {
    const value = input.notes?.trim();
    updates.push("notes = @notes");
    params.notes = value ? value : null;
  }

  if (updates.length === 0) {
    return current;
  }

  if (input.enrolledBaby !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledBaby)));
    updates.push("enrolled_baby = @enrolledBaby");
    params.enrolledBaby = value;
  }
  if (input.enrolledMiddle !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledMiddle)));
    updates.push("enrolled_middle = @enrolledMiddle");
    params.enrolledMiddle = value;
  }
  if (input.enrolledTop !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledTop)));
    updates.push("enrolled_top = @enrolledTop");
    params.enrolledTop = value;
  }
  if (input.enrolledP1 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP1)));
    updates.push("enrolled_p1 = @enrolledP1");
    params.enrolledP1 = value;
  }
  if (input.enrolledP2 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP2)));
    updates.push("enrolled_p2 = @enrolledP2");
    params.enrolledP2 = value;
  }
  if (input.enrolledP3 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP3)));
    updates.push("enrolled_p3 = @enrolledP3");
    params.enrolledP3 = value;
  }
  if (input.enrolledP4 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP4)));
    updates.push("enrolled_p4 = @enrolledP4");
    params.enrolledP4 = value;
  }
  if (input.enrolledP5 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP5)));
    updates.push("enrolled_p5 = @enrolledP5");
    params.enrolledP5 = value;
  }
  if (input.enrolledP6 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP6)));
    updates.push("enrolled_p6 = @enrolledP6");
    params.enrolledP6 = value;
  }
  if (input.enrolledP7 !== undefined) {
    const value = Math.max(0, Math.floor(Number(input.enrolledP7)));
    updates.push("enrolled_p7 = @enrolledP7");
    params.enrolledP7 = value;
  }

  // Recalculate general impact from total boys + total girls.
  const enrolledBoys =
    input.enrolledBoys !== undefined
      ? Math.max(0, Math.floor(Number(input.enrolledBoys)))
      : current.enrolledBoys;
  const enrolledGirls =
    input.enrolledGirls !== undefined
      ? Math.max(0, Math.floor(Number(input.enrolledGirls)))
      : current.enrolledGirls;

  if (input.enrollmentTotal === undefined) {
    const autoEnrollment = enrolledBoys + enrolledGirls;
    updates.push("enrollment_total = @enrollmentTotal");
    updates.push("enrolled_learners = @enrolledLearners");
    params.enrollmentTotal = autoEnrollment;
    params.enrolledLearners = autoEnrollment;
  }

  getDb()
    .prepare(
      `
      UPDATE schools_directory
      SET ${updates.join(", ")}
      WHERE id = @schoolId
      `,
    )
    .run(params);

  const updated = getSchoolDirectoryRecordById(schoolId);
  if (!updated) {
    throw new Error("Could not load updated school record.");
  }

  return updated;
}

export function listSchoolDirectoryRecords(
  filters?: {
    district?: string;
    query?: string;
  },
  user?: PortalUser,
): SchoolDirectoryRecord[] {
  const where: string[] = ["1=1"];
  const params: Record<string, string | number> = {};

  if (user && user.role === "Staff" && user.geographyScope && !canViewAllRecords(user)) {
    const [scopeType, scopeValue] = user.geographyScope.split(":");
    if (scopeType === "district") {
      where.push("lower(district) = lower(@scopedDistrict)");
      params.scopedDistrict = scopeValue;
    }
  }

  if (filters?.district) {
    where.push("lower(district) LIKE lower(@district)");
    params.district = `% ${filters.district}% `;
  }

  if (filters?.query) {
    where.push("(lower(name) LIKE lower(@query) OR lower(school_code) LIKE lower(@query))");
    params.query = `% ${filters.query}% `;
  }

  return getDb()
    .prepare(
      `
    SELECT
    id,
      school_uid AS schoolUid,
        school_code AS schoolCode,
          name,
          COALESCE(region, '') AS region,
            COALESCE(sub_region, '') AS subRegion,
              district,
              sub_county AS subCounty,
                parish,
                village,
                CASE
          WHEN COALESCE(enrollment_total, 0) > 0 THEN COALESCE(enrollment_total, 0)
          WHEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0) > 0
            THEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0)
          ELSE COALESCE(enrolled_learners, 0)
        END AS enrollmentTotal,
      enrollment_by_grade AS enrollmentByGrade,
        enrolled_boys AS enrolledBoys,
          enrolled_girls AS enrolledGirls,
            COALESCE(enrolled_baby, 0) AS enrolledBaby,
              COALESCE(enrolled_middle, 0) AS enrolledMiddle,
                COALESCE(enrolled_top, 0) AS enrolledTop,
                  COALESCE(enrolled_p1, 0) AS enrolledP1,
                    COALESCE(enrolled_p2, 0) AS enrolledP2,
                      COALESCE(enrolled_p3, 0) AS enrolledP3,
                        (
          COALESCE(enrolled_baby, 0) +
          COALESCE(enrolled_middle, 0) +
          COALESCE(enrolled_top, 0) +
          COALESCE(enrolled_p1, 0) +
          COALESCE(enrolled_p2, 0) +
          COALESCE(enrolled_p3, 0)
        ) AS directImpactLearners,
                        COALESCE(enrolled_p4, 0) AS enrolledP4,
                          COALESCE(enrolled_p5, 0) AS enrolledP5,
                            COALESCE(enrolled_p6, 0) AS enrolledP6,
                              COALESCE(enrolled_p7, 0) AS enrolledP7,
                                CASE
          WHEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0) > 0
            THEN COALESCE(enrolled_boys, 0) + COALESCE(enrolled_girls, 0)
          ELSE COALESCE(enrolled_learners, 0)
        END AS enrolledLearners,
      gps_lat AS gpsLat,
        gps_lng AS gpsLng,
          contact_name AS contactName,
            contact_phone AS contactPhone,
              primary_contact_id AS primaryContactId,
                primary_contact.full_name AS primaryContactName,
                  primary_contact.category AS primaryContactCategory,
              COALESCE(program_status, 'active') AS programStatus,
                graduated_at AS graduatedAt,
                  graduated_by_user_id AS graduatedByUserId,
                    graduation_notes AS graduationNotes,
                      graduation_version AS graduationVersion,
              notes,
              schools_directory.created_at AS createdAt
      FROM schools_directory
      LEFT JOIN school_contacts primary_contact
        ON primary_contact.contact_id = schools_directory.primary_contact_id
      WHERE ${where.join(" AND ")}
      ORDER BY schools_directory.created_at DESC
      LIMIT 500
      `,
    )
    .all(params) as SchoolDirectoryRecord[];
}

export function listPortalUsersForFilters(user: PortalUser) {
  if (!canViewAllRecords(user)) {
    return [{ id: user.id, fullName: user.fullName }];
  }

  return getDb()
    .prepare(
      `
      SELECT id, full_name AS fullName
      FROM portal_users
      ORDER BY full_name ASC
      `,
    )
    .all() as Array<{ id: number; fullName: string }>;
}

function parsePortalEvidenceRow(row: {
  id: number;
  recordId: number | null;
  module: PortalRecordModule;
  date: string;
  schoolName: string;
  fileName: string;
  storedPath: string;
  mimeType: string;
  sizeBytes: number;
  uploadedByName: string;
  uploadedByUserId?: number;
  createdAt: string;
}): PortalEvidenceRecord {
  return {
    id: row.id,
    recordId: row.recordId !== null ? Number(row.recordId) : null,
    module: row.module,
    date: row.date,
    schoolName: row.schoolName,
    fileName: row.fileName,
    storedPath: row.storedPath,
    mimeType: row.mimeType,
    sizeBytes: Number(row.sizeBytes),
    uploadedByName: row.uploadedByName,
    createdAt: row.createdAt,
  };
}

export function savePortalEvidence(input: {
  recordId?: number;
  module: PortalRecordModule;
  date: string;
  schoolName: string;
  fileName: string;
  storedPath: string;
  mimeType: string;
  sizeBytes: number;
  uploadedByUserId: number;
}): PortalEvidenceRecord {
  const db = getDb();
  const insertResult = db
    .prepare(
      `
      INSERT INTO portal_evidence(
        record_id,
        module,
        date,
        school_name,
        file_name,
        stored_path,
        mime_type,
        size_bytes,
        uploaded_by_user_id
      ) VALUES(
        @recordId,
        @module,
        @date,
        @schoolName,
        @fileName,
        @storedPath,
        @mimeType,
        @sizeBytes,
        @uploadedByUserId
      )
        `,
    )
    .run({
      recordId: input.recordId ?? null,
      module: input.module,
      date: input.date,
      schoolName: input.schoolName,
      fileName: input.fileName,
      storedPath: input.storedPath,
      mimeType: input.mimeType,
      sizeBytes: input.sizeBytes,
      uploadedByUserId: input.uploadedByUserId,
    });

  const id = Number(insertResult.lastInsertRowid);
  const row = db
    .prepare(
      `
    SELECT
    pe.id,
      pe.record_id AS recordId,
        pe.module,
        pe.date,
        pe.school_name AS schoolName,
          pe.file_name AS fileName,
            pe.stored_path AS storedPath,
              pe.mime_type AS mimeType,
                pe.size_bytes AS sizeBytes,
                  pu.full_name AS uploadedByName,
                    pe.created_at AS createdAt
      FROM portal_evidence pe
      JOIN portal_users pu ON pu.id = pe.uploaded_by_user_id
      WHERE pe.id = @id
      LIMIT 1
      `,
    )
    .get({ id }) as
    | {
      id: number;
      recordId: number | null;
      module: PortalRecordModule;
      date: string;
      schoolName: string;
      fileName: string;
      storedPath: string;
      mimeType: string;
      sizeBytes: number;
      uploadedByName: string;
      createdAt: string;
    }
    | undefined;

  if (!row) {
    throw new Error("Could not load saved evidence.");
  }

  return parsePortalEvidenceRow(row);
}

export function listPortalEvidence(
  filters: {
    module?: PortalRecordModule;
    dateFrom?: string;
    dateTo?: string;
    school?: string;
    recordId?: number;
  },
  user: PortalUser,
): PortalEvidenceRecord[] {
  const whereClauses = ["1=1"];
  const params: Record<string, string | number> = {};

  if (!canViewAllRecords(user)) {
    whereClauses.push("pe.uploaded_by_user_id = @currentUserId");
    params.currentUserId = user.id;
  }

  if (filters.module) {
    whereClauses.push("pe.module = @module");
    params.module = filters.module;
  }

  if (filters.dateFrom) {
    whereClauses.push("pe.date >= @dateFrom");
    params.dateFrom = filters.dateFrom;
  }

  if (filters.dateTo) {
    whereClauses.push("pe.date <= @dateTo");
    params.dateTo = filters.dateTo;
  }

  if (filters.school) {
    whereClauses.push("lower(pe.school_name) LIKE lower(@school)");
    params.school = `% ${filters.school}% `;
  }

  if (filters.recordId) {
    whereClauses.push("pe.record_id = @recordId");
    params.recordId = filters.recordId;
  }

  const rows = getDb()
    .prepare(
      `
    SELECT
    pe.id,
      pe.record_id AS recordId,
        pe.module,
        pe.date,
        pe.school_name AS schoolName,
          pe.file_name AS fileName,
            pe.stored_path AS storedPath,
              pe.mime_type AS mimeType,
                pe.size_bytes AS sizeBytes,
                  pu.full_name AS uploadedByName,
                    pe.created_at AS createdAt
      FROM portal_evidence pe
      JOIN portal_users pu ON pu.id = pe.uploaded_by_user_id
      WHERE ${whereClauses.join(" AND ")}
      ORDER BY pe.created_at DESC
      LIMIT 250
      `,
    )
    .all(params) as Array<{
      id: number;
      recordId: number | null;
      module: PortalRecordModule;
      date: string;
      schoolName: string;
      fileName: string;
      storedPath: string;
      mimeType: string;
      sizeBytes: number;
      uploadedByName: string;
      createdAt: string;
    }>;

  return rows.map((row) => parsePortalEvidenceRow(row));
}

export function getPortalEvidenceById(id: number, user: PortalUser): PortalEvidenceRecord | null {
  const row = getDb()
    .prepare(
      `
    SELECT
    pe.id,
      pe.record_id AS recordId,
        pe.module,
        pe.date,
        pe.school_name AS schoolName,
          pe.file_name AS fileName,
            pe.stored_path AS storedPath,
              pe.mime_type AS mimeType,
                pe.size_bytes AS sizeBytes,
                  pe.uploaded_by_user_id AS uploadedByUserId,
                    pu.full_name AS uploadedByName,
                      pe.created_at AS createdAt
      FROM portal_evidence pe
      JOIN portal_users pu ON pu.id = pe.uploaded_by_user_id
      WHERE pe.id = @id
      LIMIT 1
      `,
    )
    .get({ id }) as
    | {
      id: number;
      recordId: number | null;
      module: PortalRecordModule;
      date: string;
      schoolName: string;
      fileName: string;
      storedPath: string;
      mimeType: string;
      sizeBytes: number;
      uploadedByUserId: number;
      uploadedByName: string;
      createdAt: string;
    }
    | undefined;

  if (!row) {
    return null;
  }

  if (!canViewAllRecords(user) && row.uploadedByUserId !== user.id) {
    return null;
  }

  return parsePortalEvidenceRow(row);
}

