function isSectionIncluded(variant: ImpactReportVariant, sectionId: string) {
  if (sectionId === "cover-page" || sectionId === "table-of-contents") {
    return true;
  }

  if (variant === "Public Impact Report") {
    return [
      "1-executive-summary",
      "2-about-ozeki",
      "3-program-model",
      "4-coverage-reach",
      "5-training-results",
      "6-coaching-results",
      "7-learner-outcomes",
      "8-remedial-results",
      "9-resource-utilization",
      "10-regional-district-breakdown",
      "13-challenges-lessons",
      "14-next-cycle-priorities",
      "15-appendix-methods",
    ].includes(sectionId);
  }

  if (variant === "Partner Report") {
    return [
      "1-executive-summary",
      "2-about-ozeki",
      "3-program-model",
      "4-coverage-reach",
      "5-training-results",
      "6-coaching-results",
      "7-learner-outcomes",
      "8-remedial-results",
      "9-resource-utilization",
      "10-regional-district-breakdown",
      "12-case-studies",
      "13-challenges-lessons",
      "14-next-cycle-priorities",
      "15-appendix-methods",
    ].includes(sectionId);
  }

  return [
    "1-executive-summary",
    "3-program-model",
    "7-learner-outcomes",
    "11-school-level-report",
    "13-challenges-lessons",
    "14-next-cycle-priorities",
    "15-appendix-methods",
  ].includes(sectionId);
}

function buildImpactTemplatePackage(
  reportType: ImpactReportType,
  generatedDate: string,
): ImpactReportTemplatePackage {
  const variant = resolveImpactReportVariant(reportType);
  const sections: ImpactReportTemplateSection[] = sectionCatalog
    .map((section) => ({
      ...section,
      included: isSectionIncluded(variant, section.id),
    }))
    .sort((a, b) => a.order - b.order);

  const tableOfContents = sections
    .filter((section) => section.included && section.id !== "cover-page")
    .map((section) => section.title);

  return {
    masterTemplateId: impactTemplateId,
    masterTemplateName: impactTemplateName,
    variant,
    aiWritingRules: impactAiWritingRules,
    tableOfContents,
    sections,
    generatedDate,
  };
}

function safeParseObject(text: string): Record<string, unknown> {
  try {
    const parsed = JSON.parse(text || "{}");
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>;
    }
    return {};
  } catch {
    return {};
  }
}

function asNumber(value: unknown): number | null {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === "string" && value.trim()) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
}

function readNumeric(payload: Record<string, unknown>, keys: string[]): number | null {
  for (const key of keys) {
    const numeric = asNumber(payload[key]);
    if (numeric !== null) {
      return numeric;
    }
  }
  return null;
}

function readString(payload: Record<string, unknown>, keys: string[]): string | null {
  for (const key of keys) {
    const value = payload[key];
    if (typeof value === "string" && value.trim()) {
      return value.trim();
    }
  }
  return null;
}

function extractSponsorAttribution(payload: Record<string, unknown>): {
  sponsorType: string;
  sponsoredBy: string;
} | null {
  const sponsoredBy = readString(payload, [
    "sponsoredBy",
    "sponsorName",
    "sponsored_by",
    "partnerName",
  ]);
  if (!sponsoredBy) {
    return null;
  }
  const sponsorType =
    readString(payload, ["sponsorshipType", "sponsorType", "sponsor_category"]) ??
    "Unspecified";
  return {
    sponsorType,
    sponsoredBy,
  };
}

function parseStringList(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value
      .map((item) => (typeof item === "string" ? item.trim() : ""))
      .filter(Boolean);
  }
  if (typeof value === "string") {
    return value
      .split(/[,\n;|]/)
      .map((entry) => entry.trim())
      .filter(Boolean);
  }
  return [];
}

function inferAssessmentStage(payload: Record<string, unknown>): AssessmentStage {
  const raw = readString(payload, ["assessmentType", "stage", "phase", "assessmentPhase"]);
  if (!raw) {
    return "progress";
  }
  const normalized = raw.toLowerCase();
  if (normalized.includes("baseline")) return "baseline";
  if (normalized.includes("endline")) return "endline";
  return "progress";
}

interface GeoScopeSet {
  schools: Set<string>;
  districts: Set<string>;
}

function resolveGeoScope(scopeType: ImpactReportScopeType, scopeValue: string): GeoScopeSet | null {
  if (scopeType === "National") return null;
  const db = getDb();
  const schools = new Set<string>();
  const districts = new Set<string>();

  let schoolQuery = "";
  let districtNameQuery = "";

  if (scopeType === "Region") {
    schoolQuery = "SELECT name FROM schools_directory WHERE geo_region_id = ?";
    districtNameQuery = "SELECT d.name FROM geo_districts d JOIN geo_subregions sr ON d.subregion_id = sr.id WHERE sr.region_id = ?";
  } else if (scopeType === "Sub-region") {
    schoolQuery = "SELECT name FROM schools_directory WHERE geo_subregion_id = ?";
    districtNameQuery = "SELECT name FROM geo_districts WHERE subregion_id = ?";
  } else if (scopeType === "District") {
    schoolQuery = "SELECT name FROM schools_directory WHERE geo_district_id = ?";
    districtNameQuery = "SELECT name FROM geo_districts WHERE id = ?";
  } else if (scopeType === "Sub-county") {
    schoolQuery = "SELECT name FROM schools_directory WHERE geo_subcounty_id = ?";
  } else if (scopeType === "Parish") {
    schoolQuery = "SELECT name FROM schools_directory WHERE geo_parish_id = ?";
  } else if (scopeType === "School") {
    schoolQuery = "SELECT name FROM schools_directory WHERE id = ?";
  }

  if (schoolQuery) {
    const sRows = db.prepare(schoolQuery).all(scopeValue) as { name: string | null }[];
    sRows.forEach((r) => { if (r.name) schools.add(r.name.trim().toLowerCase()); });
  }
  if (districtNameQuery) {
    const dRows = db.prepare(districtNameQuery).all(scopeValue) as { name: string | null }[];
    dRows.forEach((r) => { if (r.name) districts.add(r.name.trim().toLowerCase()); });
  }
  return { schools, districts };
}

function scopeSetMatches(
  scopeType: ImpactReportScopeType,
  scopeSet: GeoScopeSet | null,
  district: string | null | undefined,
  schoolName: string | null | undefined,
) {
  if (!scopeSet || scopeType === "National") return true;
  const d = (district || "").trim().toLowerCase();
  const s = (schoolName || "").trim().toLowerCase();

  if (scopeType === "School" || scopeType === "Parish" || scopeType === "Sub-county") {
    return s ? scopeSet.schools.has(s) : false;
  }
  if (d && scopeSet.districts.has(d)) return true;
  if (s && scopeSet.schools.has(s)) return true;
  return false;
}

function collectScopedAssessmentAnalytics(args: {
  user: PortalUser;
  startDate: string;
  endDate: string;
  scopeType: ImpactReportScopeType;
  scopeSet: GeoScopeSet | null;
}): ScopedAssessmentAnalytics {
  const db = getDb();
  const canViewAll = canViewAllRecords(args.user);
  const assessmentModelVersion = ASSESSMENT_MODEL_VERSION_UG_MASTERY_ONETEST_STYLE_V1;
  const params = canViewAll
    ? {
      startDate: args.startDate,
      endDate: args.endDate,
      assessmentModelVersion,
    }
    : {
      startDate: args.startDate,
      endDate: args.endDate,
      currentUserId: args.user.id,
      assessmentModelVersion,
    };
  const recordFilter = canViewAll ? "" : "AND ar.created_by_user_id = @currentUserId";
  const sessionFilter = canViewAll ? "" : "AND s.assessor_user_id = @currentUserId";

  const sessionsCount = createAssessmentStageAccumulator();
  const metrics = createAssessmentMetricAccumulators();
  const schoolsImpacted = new Set<string>();
  const linkedPortalRecordIds = new Set<number>();
  let learnersAssessed = 0;

  const sessionRows = db
    .prepare(
      `
      SELECT
        s.assessment_type AS assessmentType,
        sd.name AS schoolName,
        sd.district AS district
      FROM assessment_sessions s
      JOIN schools_directory sd ON sd.id = s.school_id
      WHERE s.assessment_date >= @startDate
        AND s.assessment_date <= @endDate
        ${sessionFilter}
      `,
    )
    .all(params) as Array<{
      assessmentType: string;
      schoolName: string;
      district: string;
    }>;

  sessionRows
    .filter((row) =>
      scopeSetMatches(args.scopeType, args.scopeSet, row.district, row.schoolName),
    )
    .forEach((row) => {
      const stage = normalizeAssessmentType(row.assessmentType);
      sessionsCount[stage] += 1;
      const schoolKey = row.schoolName.trim().toLowerCase();
      if (schoolKey) {
        schoolsImpacted.add(schoolKey);
      }
    });

  const levelCounts = {
    baseline: { total: 0, nonReaders: 0 },
    progress: { total: 0, nonReaders: 0 },
    endline: { total: 0, nonReaders: 0 },
  } as Record<AssessmentStage, { total: number; nonReaders: number }>;
  const latestMasteryByLearner = new Map<
    string,
    {
      assessmentDate: string;
      modelVersion: string | null;
      benchmarkVersion: string | null;
      scoringProfileVersion: string | null;
      readingStageLabel: string | null;
      readingStageOrder: number | null;
      expectedVsActualStatus: string | null;
      statuses: Record<MasteryDomainKey, MasteryStatus>;
    }
  >();

  const learnerRowsByUid = new Map<
    string,
    Array<{ stage: AssessmentStage; date: string; levelBand: number }>
  >();

  const assessmentRows = db
    .prepare(
      `
      SELECT
        ar.source_portal_record_id AS sourcePortalRecordId,
        ar.learner_uid AS learnerUid,
        ar.assessment_type AS assessmentType,
        ar.assessment_date AS assessmentDate,
        ar.class_grade AS classGrade,
        ar.age AS age,
        ar.letter_identification_score AS letterIdentificationScore,
        ar.sound_identification_score AS soundIdentificationScore,
        ar.decodable_words_score AS decodableWordsScore,
        ar.undecodable_words_score AS undecodableWordsScore,
        ar.made_up_words_score AS madeUpWordsScore,
        ar.story_reading_score AS storyReadingScore,
        ar.fluency_accuracy_score AS fluencyAccuracyScore,
        ar.reading_comprehension_score AS readingComprehensionScore,
        ar.computed_level_band AS computedLevelBand,
        ar.model_version AS modelVersion,
        ar.benchmark_version AS benchmarkVersion,
        ar.scoring_profile_version AS scoringProfileVersion,
        ar.reading_stage_label AS readingStageLabel,
        ar.reading_stage_order AS readingStageOrder,
        ar.expected_vs_actual_status AS expectedVsActualStatus,
        ar.phonemic_awareness_mastery_status AS phonemicAwarenessMasteryStatus,
        ar.grapheme_phoneme_correspondence_mastery_status AS graphemePhonemeCorrespondenceMasteryStatus,
        ar.blending_decoding_mastery_status AS blendingDecodingMasteryStatus,
        ar.word_recognition_fluency_mastery_status AS wordRecognitionFluencyMasteryStatus,
        ar.sentence_paragraph_construction_mastery_status AS sentenceParagraphConstructionMasteryStatus,
        ar.comprehension_mastery_status AS comprehensionMasteryStatus,
        sd.name AS schoolName,
        sd.district AS district
      FROM assessment_records ar
      JOIN schools_directory sd ON sd.id = ar.school_id
      WHERE ar.assessment_date >= @startDate
        AND ar.assessment_date <= @endDate
        AND ar.model_version = @assessmentModelVersion
        ${recordFilter}
      `,
    )
    .all(params) as Array<{
      sourcePortalRecordId: number | null;
      learnerUid: string | null;
      assessmentType: string;
      assessmentDate: string;
      classGrade: string | null;
      age: number | null;
      letterIdentificationScore: number | null;
      soundIdentificationScore: number | null;
      decodableWordsScore: number | null;
      undecodableWordsScore: number | null;
      madeUpWordsScore: number | null;
      storyReadingScore: number | null;
      fluencyAccuracyScore: number | null;
      readingComprehensionScore: number | null;
      computedLevelBand: number | null;
      modelVersion: string | null;
      benchmarkVersion: string | null;
      scoringProfileVersion: string | null;
      readingStageLabel: string | null;
      readingStageOrder: number | null;
      expectedVsActualStatus: string | null;
      phonemicAwarenessMasteryStatus: string | null;
      graphemePhonemeCorrespondenceMasteryStatus: string | null;
      blendingDecodingMasteryStatus: string | null;
      wordRecognitionFluencyMasteryStatus: string | null;
      sentenceParagraphConstructionMasteryStatus: string | null;
      comprehensionMasteryStatus: string | null;
      schoolName: string;
      district: string;
    }>;

  assessmentRows
    .filter((row) =>
      scopeSetMatches(args.scopeType, args.scopeSet, row.district, row.schoolName),
    )
    .forEach((row) => {
      const stage = normalizeAssessmentType(row.assessmentType);
      const schoolKey = row.schoolName.trim().toLowerCase();
      if (schoolKey) {
        schoolsImpacted.add(schoolKey);
      }

      if (
        row.sourcePortalRecordId !== null &&
        Number.isInteger(Number(row.sourcePortalRecordId)) &&
        Number(row.sourcePortalRecordId) > 0
      ) {
        linkedPortalRecordIds.add(Number(row.sourcePortalRecordId));
      }

      learnersAssessed += 1;

      addAssessmentMetricValue(
        metrics.letterIdentification,
        stage,
        row.letterIdentificationScore === null ? null : Number(row.letterIdentificationScore),
      );
      addAssessmentMetricValue(
        metrics.soundIdentification,
        stage,
        row.soundIdentificationScore === null ? null : Number(row.soundIdentificationScore),
      );
      addAssessmentMetricValue(
        metrics.decodableWords,
        stage,
        row.decodableWordsScore === null ? null : Number(row.decodableWordsScore),
      );
      addAssessmentMetricValue(
        metrics.undecodableWords,
        stage,
        row.undecodableWordsScore === null ? null : Number(row.undecodableWordsScore),
      );
      addAssessmentMetricValue(
        metrics.madeUpWords,
        stage,
        row.madeUpWordsScore === null ? null : Number(row.madeUpWordsScore),
      );
      addAssessmentMetricValue(
        metrics.storyReading,
        stage,
        row.storyReadingScore === null ? null : Number(row.storyReadingScore),
      );
      addAssessmentMetricValue(
        metrics.readingComprehension,
        stage,
        row.readingComprehensionScore === null ? null : Number(row.readingComprehensionScore),
      );

      const levelBand =
        row.computedLevelBand === null ? null : Number(row.computedLevelBand);
      if (levelBand !== null && Number.isFinite(levelBand)) {
        levelCounts[stage].total += 1;
        if (levelBand <= 0) {
          levelCounts[stage].nonReaders += 1;
        }

        const learnerUid = String(row.learnerUid ?? "").trim();
        if (learnerUid) {
          const bucket = learnerRowsByUid.get(learnerUid) ?? [];
          bucket.push({
            stage,
            date: row.assessmentDate,
            levelBand,
          });
          learnerRowsByUid.set(learnerUid, bucket);
        }
      }

      const learnerUid = String(row.learnerUid ?? "").trim();
      if (learnerUid) {
        const rowStatuses: Partial<Record<MasteryDomainKey, MasteryStatus>> = {
          phonemic_awareness: normalizeMasteryStatus(row.phonemicAwarenessMasteryStatus) ?? undefined,
          grapheme_phoneme_correspondence:
            normalizeMasteryStatus(row.graphemePhonemeCorrespondenceMasteryStatus) ?? undefined,
          blending_decoding: normalizeMasteryStatus(row.blendingDecodingMasteryStatus) ?? undefined,
          word_recognition_fluency:
            normalizeMasteryStatus(row.wordRecognitionFluencyMasteryStatus) ?? undefined,
          sentence_paragraph_construction:
            normalizeMasteryStatus(row.sentenceParagraphConstructionMasteryStatus) ?? undefined,
          comprehension: normalizeMasteryStatus(row.comprehensionMasteryStatus) ?? undefined,
        };
        const statuses = {} as Record<MasteryDomainKey, MasteryStatus>;
        MASTERY_DOMAIN_SEQUENCE.forEach((domain) => {
          statuses[domain.key] = rowStatuses[domain.key] ?? "red";
        });
        const current = latestMasteryByLearner.get(learnerUid);
        if (!current || row.assessmentDate >= current.assessmentDate) {
          latestMasteryByLearner.set(learnerUid, {
            assessmentDate: row.assessmentDate,
            modelVersion: String(row.modelVersion ?? "").trim() || null,
            benchmarkVersion: String(row.benchmarkVersion ?? "").trim() || null,
            scoringProfileVersion: String(row.scoringProfileVersion ?? "").trim() || null,
            readingStageLabel: row.readingStageLabel?.trim() || "Pre-Reader",
            readingStageOrder: Number(row.readingStageOrder ?? 1) || 1,
            expectedVsActualStatus:
              row.expectedVsActualStatus?.trim() || "Data not available",
            statuses,
          });
        }
      }
    });

  let reductionInNonReadersPercent: number | null = null;
  const baselineLevels = levelCounts.baseline;
  const comparisonLevelStage =
    levelCounts.endline.total > 0
      ? levelCounts.endline
      : levelCounts.progress.total > 0
        ? levelCounts.progress
        : null;
  if (baselineLevels.total > 0 && comparisonLevelStage && comparisonLevelStage.total > 0) {
    const baselinePct = (baselineLevels.nonReaders / baselineLevels.total) * 100;
    const comparisonPct = (comparisonLevelStage.nonReaders / comparisonLevelStage.total) * 100;
    reductionInNonReadersPercent = Number((baselinePct - comparisonPct).toFixed(2));
  }

  let proficiencyBandMovementPercent: number | null = null;
  let comparedLearners = 0;
  let movedUpLearners = 0;
  learnerRowsByUid.forEach((rows) => {
    const baselineCandidates = rows
      .filter((row) => row.stage === "baseline")
      .sort((left, right) => left.date.localeCompare(right.date));
    const baseline = baselineCandidates[0];
    if (!baseline) {
      return;
    }

    const endlineCandidates = rows
      .filter((row) => row.stage === "endline" && row.date >= baseline.date)
      .sort((left, right) => right.date.localeCompare(left.date));
    const progressCandidates = rows
      .filter((row) => row.stage === "progress" && row.date >= baseline.date)
      .sort((left, right) => right.date.localeCompare(left.date));
    const comparison = endlineCandidates[0] ?? progressCandidates[0];

    if (!comparison) {
      return;
    }

    comparedLearners += 1;
    if (comparison.levelBand > baseline.levelBand) {
      movedUpLearners += 1;
    }
  });

  if (comparedLearners > 0) {
    proficiencyBandMovementPercent = Number(
      ((movedUpLearners / comparedLearners) * 100).toFixed(2),
    );
  }

  const masteryTallies = emptyDomainMasteryDistribution();
  const stageCounts = new Map<string, { order: number; count: number }>();
  const benchmarkCounts = {
    belowExpected: 0,
    atExpected: 0,
    aboveExpected: 0,
    n: 0,
  };
  const modelVersionCounts = new Map<string, number>();
  const benchmarkVersionCounts = new Map<string, number>();
  const scoringProfileCounts = new Map<string, number>();

  latestMasteryByLearner.forEach((entry) => {
    MASTERY_DOMAIN_SEQUENCE.forEach((domain) => {
      const status = entry.statuses[domain.key];
      masteryTallies[domain.key].n += 1;
      if (status === "green") masteryTallies[domain.key].green += 1;
      if (status === "amber") masteryTallies[domain.key].amber += 1;
      if (status === "red") masteryTallies[domain.key].red += 1;
    });

    const stageLabel = entry.readingStageLabel || "Pre-Reader";
    const stageOrder = Number(entry.readingStageOrder ?? 1) || 1;
    const stageBucket = stageCounts.get(stageLabel) ?? { order: stageOrder, count: 0 };
    stageBucket.order = stageOrder;
    stageBucket.count += 1;
    stageCounts.set(stageLabel, stageBucket);

    const expected = String(entry.expectedVsActualStatus ?? "").toLowerCase();
    if (expected.includes("below expected")) {
      benchmarkCounts.belowExpected += 1;
      benchmarkCounts.n += 1;
    } else if (expected.includes("above expected")) {
      benchmarkCounts.aboveExpected += 1;
      benchmarkCounts.n += 1;
    } else if (expected.includes("at expected")) {
      benchmarkCounts.atExpected += 1;
      benchmarkCounts.n += 1;
    }

    if (entry.modelVersion) {
      modelVersionCounts.set(
        entry.modelVersion,
        (modelVersionCounts.get(entry.modelVersion) ?? 0) + 1,
      );
    }
    if (entry.benchmarkVersion) {
      benchmarkVersionCounts.set(
        entry.benchmarkVersion,
        (benchmarkVersionCounts.get(entry.benchmarkVersion) ?? 0) + 1,
      );
    }
    if (entry.scoringProfileVersion) {
      scoringProfileCounts.set(
        entry.scoringProfileVersion,
        (scoringProfileCounts.get(entry.scoringProfileVersion) ?? 0) + 1,
      );
    }
  });

  const domainMasteryDistribution = MASTERY_DOMAIN_SEQUENCE.reduce((acc, domain) => {
    const tally = masteryTallies[domain.key];
    const total = Math.max(1, tally.n);
    acc[domain.key] = {
      green: {
        count: tally.green,
        percent: Number(((tally.green / total) * 100).toFixed(1)),
      },
      amber: {
        count: tally.amber,
        percent: Number(((tally.amber / total) * 100).toFixed(1)),
      },
      red: {
        count: tally.red,
        percent: Number(((tally.red / total) * 100).toFixed(1)),
      },
      n: tally.n,
    };
    return acc;
  }, {} as ScopedAssessmentAnalytics["domainMasteryDistribution"]);

  const readingStageDistribution = [...stageCounts.entries()]
    .map(([label, value]) => ({
      label,
      order: value.order,
      count: value.count,
      percent:
        latestMasteryByLearner.size > 0
          ? Number(((value.count / latestMasteryByLearner.size) * 100).toFixed(1))
          : 0,
    }))
    .sort((left, right) => left.order - right.order);

  const benchmarkStatus: ScopedAssessmentAnalytics["benchmarkStatus"] = {
    belowExpected: {
      count: benchmarkCounts.belowExpected,
      percent:
        benchmarkCounts.n > 0
          ? Number(((benchmarkCounts.belowExpected / benchmarkCounts.n) * 100).toFixed(1))
          : 0,
    },
    atExpected: {
      count: benchmarkCounts.atExpected,
      percent:
        benchmarkCounts.n > 0
          ? Number(((benchmarkCounts.atExpected / benchmarkCounts.n) * 100).toFixed(1))
          : 0,
    },
    aboveExpected: {
      count: benchmarkCounts.aboveExpected,
      percent:
        benchmarkCounts.n > 0
          ? Number(((benchmarkCounts.aboveExpected / benchmarkCounts.n) * 100).toFixed(1))
          : 0,
    },
    n: benchmarkCounts.n,
  };
  const pickMostCommon = (map: Map<string, number>) =>
    [...map.entries()].sort((left, right) => right[1] - left[1])[0]?.[0] ?? null;

  return {
    schoolsImpacted,
    linkedPortalRecordIds,
    learnersAssessed,
    sessionsCount,
    metrics,
    proficiencyBandMovementPercent,
    reductionInNonReadersPercent,
    domainMasteryDistribution,
    readingStageDistribution,
    benchmarkStatus,
    assessmentModelVersion: pickMostCommon(modelVersionCounts),
    benchmarkVersion: pickMostCommon(benchmarkVersionCounts),
    scoringProfileVersion: pickMostCommon(scoringProfileCounts),
  };
}

function shouldIncludeModule(programs: ImpactReportProgramType[], module: PortalRecordModule) {
  if (module === "training") return programs.includes("training");
  if (module === "visit") return programs.includes("visit");
  if (module === "assessment") return programs.includes("assessment");
  if (module === "story") return programs.includes("story");
  return true;
}

function listScopedPortalRows(
  user: PortalUser,
  startDate: string,
  endDate: string,
  scopeType: ImpactReportScopeType,
  scopeSet: GeoScopeSet | null,
  programs: ImpactReportProgramType[],
) {
  const db = getDb();
  const canViewAll = canViewAllRecords(user);
  const recordFilter = canViewAll ? "" : "AND pr.created_by_user_id = @currentUserId";
  const params = canViewAll
    ? { startDate, endDate }
    : { startDate, endDate, currentUserId: user.id };

  const rows = db
    .prepare(
      `
    SELECT
    pr.id,
      pr.module,
      pr.date,
      pr.district,
      pr.school_name AS schoolName,
        pr.status,
        pr.updated_at AS updatedAt,
        pr.payload_json AS payloadJson
      FROM portal_records pr
      WHERE pr.date >= @startDate
        AND pr.date <= @endDate
        ${recordFilter}
      ORDER BY pr.date ASC
      `,
    )
    .all(params) as Array<{
      id: number;
      module: PortalRecordModule;
      date: string;
      district: string;
      schoolName: string;
      status: PortalRecordStatus;
      updatedAt: string;
      payloadJson: string;
    }>;

  return rows
    .map((row) => ({
      id: row.id,
      module: row.module,
      date: row.date,
      district: row.district,
      schoolName: row.schoolName,
      status: row.status,
      updatedAt: row.updatedAt,
      payload: safeParseObject(row.payloadJson),
    }))
    .filter((row) => shouldIncludeModule(programs, row.module))
    .filter((row) => scopeSetMatches(scopeType, scopeSet, row.district, row.schoolName));
}

type ScopedActivityInsightEntry = ActivityInsightRecord & {
  recommendations: ActivityRecommendationRecord[];
  activityDate: string | null;
  district: string | null;
  schoolName: string | null;
  schoolId: number | null;
};

function listScopedActivityInsights(
  user: PortalUser,
  startDate: string,
  endDate: string,
  scopeType: ImpactReportScopeType,
  scopeSet: GeoScopeSet | null,
): ScopedActivityInsightEntry[] {
  const db = getDb();
  const canViewAll = canViewAllRecords(user);
  const filter = canViewAll ? "" : "AND pr.created_by_user_id = @currentUserId";
  const params = canViewAll ? {} : { currentUserId: user.id };

  const rows = db
    .prepare(
      `
      SELECT
        ai.insights_id AS insightsId,
        ai.activity_type AS activityType,
        ai.activity_id AS activityId,
        ai.scope_type AS scopeType,
        ai.scope_id AS scopeId,
        ai.key_findings AS keyFindings,
        ai.what_went_well AS whatWentWell,
        ai.challenges,
        ai.conclusions_next_steps AS conclusionsNextSteps,
        ai.created_by_user_id AS createdByUserId,
        ai.created_at AS createdAt,
        ai.updated_at AS updatedAt,
        pr.date AS activityDate,
        pr.district AS district,
        pr.school_name AS schoolName,
        pr.school_id AS schoolId
      FROM activity_insights ai
      LEFT JOIN portal_records pr
        ON pr.id = ai.activity_id
       AND (
         (ai.activity_type = 'training' AND pr.module = 'training')
         OR (ai.activity_type = 'visit' AND pr.module = 'visit')
         OR (ai.activity_type = 'assessment' AND pr.module = 'assessment')
         OR (ai.activity_type = 'story_activity' AND pr.module = 'story')
       )
      WHERE ai.activity_type IN ('training', 'visit', 'assessment', 'story_activity')
      ${filter}
      `,
    )
    .all(params) as Array<{
      insightsId: number;
      activityType: ActivityInsightRecord["activityType"];
      activityId: number;
      scopeType: ActivityInsightRecord["scopeType"];
      scopeId: string;
      keyFindings: string | null;
      whatWentWell: string | null;
      challenges: string | null;
      conclusionsNextSteps: string | null;
      createdByUserId: number | null;
      createdAt: string;
      updatedAt: string;
      activityDate: string | null;
      district: string | null;
      schoolName: string | null;
      schoolId: number | null;
    }>;

  const scopedRows = rows.filter((row) => {
    if (!isDateInWindow(row.activityDate, startDate, endDate)) {
      return false;
    }
    return scopeSetMatches(
      scopeType,
      scopeSet,
      row.district ?? "",
      row.schoolName ?? "",
    );
  });

  if (scopedRows.length === 0) {
    return [];
  }

  const insightIds = scopedRows.map((row) => row.insightsId);
  const { clause, params: inParams } = buildSqlInClause(insightIds, "insight");
  const recRows = db
    .prepare(
      `
      SELECT
        rec_link_id AS recLinkId,
        insights_id AS insightsId,
        rec_id AS recId,
        priority,
        notes
      FROM activity_recommendations
      WHERE insights_id IN ${clause}
      `,
    )
    .all(inParams) as ActivityRecommendationRecord[];

  const recByInsight = new Map<number, ActivityRecommendationRecord[]>();
  recRows.forEach((row) => {
    const bucket = recByInsight.get(row.insightsId) ?? [];
    bucket.push(row);
    recByInsight.set(row.insightsId, bucket);
  });

  return scopedRows.map((row) => ({
    insightsId: row.insightsId,
    activityType: row.activityType,
    activityId: row.activityId,
    scopeType: row.scopeType,
    scopeId: row.scopeId,
    keyFindings: row.keyFindings,
    whatWentWell: row.whatWentWell,
    challenges: row.challenges,
    conclusionsNextSteps: row.conclusionsNextSteps,
    createdByUserId: row.createdByUserId,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
    recommendations: recByInsight.get(row.insightsId) ?? [],
    activityDate: row.activityDate,
    district: row.district,
    schoolName: row.schoolName,
    schoolId: row.schoolId,
  }));
}

function summarizeScopedActivityInsights(
  entries: ScopedActivityInsightEntry[],
): {
  keyFindings: string[];
  whatWentWell: string[];
  challenges: string[];
  conclusionsNextSteps: string[];
  recommendations: InsightRecommendationWriteRow[];
} {
  const keyFindings = new Set<string>();
  const whatWentWell = new Set<string>();
  const challenges = new Set<string>();
  const conclusionsNextSteps = new Set<string>();
  const recommendationMap = new Map<string, InsightRecommendationWriteRow>();

  entries.forEach((entry) => {
    const finding = normalizeInsightText(entry.keyFindings);
    if (finding) {
      keyFindings.add(finding);
    }
    const well = normalizeInsightText(entry.whatWentWell);
    if (well) {
      whatWentWell.add(well);
    }
    const challenge = normalizeInsightText(entry.challenges);
    if (challenge) {
      challenges.add(challenge);
    }
    const nextStep = normalizeInsightText(entry.conclusionsNextSteps);
    if (nextStep) {
      conclusionsNextSteps.add(nextStep);
    }
    entry.recommendations.forEach((recommendation) => {
      const key = recommendation.recId.toUpperCase();
      const existing = recommendationMap.get(key);
      if (!existing) {
        recommendationMap.set(key, {
          recId: key,
          priority: recommendation.priority,
          notes: recommendation.notes ?? null,
        });
      }
    });
  });

  return {
    keyFindings: [...keyFindings],
    whatWentWell: [...whatWentWell],
    challenges: [...challenges],
    conclusionsNextSteps: [...conclusionsNextSteps],
    recommendations: [...recommendationMap.values()],
  };
}

function listScopedSchoolIds(scopeType: ImpactReportScopeType, scopeSet: GeoScopeSet | null): number[] {
  const rows = getDb()
    .prepare(
      `
      SELECT id, name, district
      FROM schools_directory
      `,
    )
    .all() as Array<{ id: number; name: string; district: string }>;
  return rows
    .filter((row) => scopeSetMatches(scopeType, scopeSet, row.district, row.name))
    .map((row) => row.id);
}

function latestAssessmentToolVersionForScope(args: {
  user: PortalUser;
  startDate: string;
  endDate: string;
  scopeType: ImpactReportScopeType;
  scopeSet: GeoScopeSet | null;
}): string {
  const db = getDb();
  const canViewAll = canViewAllRecords(args.user);
  const filter = canViewAll ? "" : "AND ass.assessor_user_id = @currentUserId";
  const params = canViewAll
    ? { startDate: args.startDate, endDate: args.endDate }
    : { startDate: args.startDate, endDate: args.endDate, currentUserId: args.user.id };
  const rows = db
    .prepare(
      `
      SELECT
        ass.tool_version AS toolVersion,
        ass.assessment_date AS assessmentDate,
        sd.district AS district,
        sd.name AS schoolName
      FROM assessment_sessions ass
      JOIN schools_directory sd ON sd.id = ass.school_id
      WHERE ass.assessment_date >= @startDate
        AND ass.assessment_date <= @endDate
        ${filter}
      ORDER BY ass.assessment_date DESC, ass.id DESC
      LIMIT 400
      `,
    )
    .all(params) as Array<{
      toolVersion: string | null;
      assessmentDate: string;
      district: string;
      schoolName: string;
    }>;
  const scoped = rows.find((row) =>
    scopeSetMatches(args.scopeType, args.scopeSet, row.district, row.schoolName),
  );
  return scoped?.toolVersion?.trim() || "Data not available";
}

export function getSchoolInsightsRollup(schoolId: number): SchoolInsightsRollupRecord | null {
  const row = getDb()
    .prepare(
      `
      SELECT
        school_id AS schoolId,
        last_updated AS lastUpdated,
        latest_findings AS latestFindings,
        open_actions AS openActions,
        recommendation_ids AS recommendationIds
      FROM school_insights_rollup
      WHERE school_id = @schoolId
      LIMIT 1
      `,
    )
    .get({ schoolId }) as
    | {
      schoolId: number;
      lastUpdated: string | null;
      latestFindings: string | null;
      openActions: string | null;
      recommendationIds: string | null;
    }
    | undefined;
  if (!row) {
    return null;
  }
  return {
    schoolId: row.schoolId,
    lastUpdated: row.lastUpdated,
    latestFindings: row.latestFindings ?? "",
    openActions: row.openActions ?? "",
    recommendationIds: String(row.recommendationIds ?? "")
      .split(",")
      .map((entry) => entry.trim())
      .filter(Boolean),
  };
}

