export function getImpactReportFilterFacets() {
  const db = getDb();
  const hasSchoolsDirectory = hasTable(db, "schools_directory");
  const hasRegionColumn = hasSchoolsDirectory && hasColumn(db, "schools_directory", "region");
  const hasSubRegionColumn = hasSchoolsDirectory && hasColumn(db, "schools_directory", "sub_region");
  const hasDistrictColumn = hasSchoolsDirectory && hasColumn(db, "schools_directory", "district");
  const hasReportCategory = hasColumn(db, "impact_reports", "report_category");
  const hasPeriodType = hasColumn(db, "impact_reports", "period_type");
  const hasAudience = hasColumn(db, "impact_reports", "audience");
  const hasOutput = hasColumn(db, "impact_reports", "output");

  const reportRows = db
    .prepare(
      `
      SELECT
        report_type AS reportType,
        ${hasReportCategory ? "report_category" : "NULL"} AS reportCategory,
        scope_type AS scopeType,
        scope_value AS scopeValue,
        ${hasPeriodType ? "period_type" : "'FY'"} AS periodType,
        ${hasAudience ? "audience" : "CASE WHEN is_public = 1 THEN 'Public-safe' ELSE 'Staff-only' END"} AS audience,
        ${hasOutput ? "output" : "'PDF'"} AS output,
        substr(generated_at, 1, 4) AS year
      FROM impact_reports
      WHERE is_public = 1
      ORDER BY generated_at DESC
    `,
    )
    .all() as Array<{
      reportType: ImpactReportType;
      reportCategory: ReportCategory | null;
      scopeType: ImpactReportScopeType;
      scopeValue: string;
      periodType: ImpactReportPeriodType | null;
      audience: ImpactReportAudience | null;
      output: ImpactReportOutput | null;
      year: string;
    }>;

  const reportTypes = [...new Set(reportRows.map((row) => row.reportType))];
  const reportCategories = [
    ...new Set(
      reportRows
        .map((row) => row.reportCategory)
        .filter((value): value is ReportCategory => Boolean(value && isReportCategory(value))),
    ),
  ];
  const periodTypes = [
    ...new Set(
      reportRows
        .map((row) => row.periodType)
        .filter((value): value is ImpactReportPeriodType => Boolean(value)),
    ),
  ];
  const audiences = [
    ...new Set(
      reportRows
        .map((row) => row.audience)
        .filter((value): value is ImpactReportAudience => Boolean(value)),
    ),
  ];
  const outputs = [
    ...new Set(
      reportRows
        .map((row) => row.output)
        .filter((value): value is ImpactReportOutput => Boolean(value)),
    ),
  ];
  const scopeTypes = [...new Set(reportRows.map((row) => row.scopeType))];
  const dataYears = [...new Set(reportRows.map((row) => row.year))].sort((left, right) => left.localeCompare(right));
  const years = Array.from({ length: 2050 - 2025 + 1 }, (_, index) => String(2025 + index));
  const scopeValues = [...new Set(reportRows.map((row) => row.scopeValue))];

  const pushIfPresent = (set: Set<string>, raw: unknown) => {
    const value = String(raw ?? "").trim();
    if (value) {
      set.add(value);
    }
  };

  // Geographic facets should cover the full Uganda hierarchy, not only schools that currently
  // have records in schools_directory.
  const regionSet = new Set<string>();
  const subRegionSet = new Set<string>();
  const districtSet = new Set<string>();

  listGeoRegions().forEach((row) => pushIfPresent(regionSet, row.name));
  listGeoSubregions().forEach((row) => pushIfPresent(subRegionSet, row.name));
  listGeoDistricts().forEach((row) => pushIfPresent(districtSet, row.name));

  ugandaRegions.forEach((region) => {
    pushIfPresent(regionSet, region.region);
    region.subRegions.forEach((subRegion) => {
      pushIfPresent(subRegionSet, subRegion.subRegion);
      subRegion.districts.forEach((district) => pushIfPresent(districtSet, district));
    });
  });

  const schoolGeoRows = hasSchoolsDirectory
    ? (db
      .prepare(
        `
        SELECT DISTINCT
          ${hasRegionColumn ? "region" : "NULL"} AS region,
          ${hasSubRegionColumn ? "sub_region" : "NULL"} AS subRegion,
          ${hasDistrictColumn ? "district" : "NULL"} AS district
        FROM schools_directory
      `,
      )
      .all() as Array<{
        region: string | null;
        subRegion: string | null;
        district: string | null;
      }>)
    : [];
  schoolGeoRows.forEach((row) => {
    pushIfPresent(regionSet, row.region);
    pushIfPresent(subRegionSet, row.subRegion);
    pushIfPresent(districtSet, row.district);
  });

  reportRows.forEach((row) => {
    if (row.scopeType === "Region") {
      pushIfPresent(regionSet, row.scopeValue);
    }
    if (row.scopeType === "Sub-region") {
      pushIfPresent(subRegionSet, row.scopeValue);
    }
    if (row.scopeType === "District") {
      pushIfPresent(districtSet, row.scopeValue);
    }
  });

  const regions = [...regionSet].sort((a, b) => a.localeCompare(b));
  const subRegions = [...subRegionSet].sort((a, b) => a.localeCompare(b));
  const districts = [...districtSet].sort((a, b) => a.localeCompare(b));
  const schools = hasSchoolsDirectory && hasDistrictColumn
    ? (db
      .prepare(`SELECT id, name, district FROM schools_directory WHERE name IS NOT NULL ORDER BY name`)
      .all() as Array<{ id: number; name: string; district: string }>)
    : [];

  return {
    reportTypes,
    reportCategories: [...new Set([...REPORT_CATEGORIES, ...reportCategories])],
    periodTypes: [...new Set(["FY", "Term", "Quarter", "Custom", ...periodTypes])],
    audiences: [...new Set(["Public-safe", "Staff-only", ...audiences])],
    outputs: [...new Set(["PDF", "HTML preview", ...outputs])],
    scopeTypes,
    years,
    dataYears,
    scopeValues,
    regions,
    subRegions,
    districts,
    schools,
  };
}

/**
 * Per-learner mastery analysis for a specific school.
 * Returns rubric-aligned traffic-light statuses, stage, benchmark interpretation,
 * and recommended next action per learner row.
 */
export function getSchoolLearnerAnalysis(schoolId: number, assessmentType?: string) {
  const db = getDb();
  const assessmentModelVersion = ASSESSMENT_MODEL_VERSION_UG_MASTERY_ONETEST_STYLE_V1;
  const typeCond = assessmentType ? "AND ar.assessment_type = @assessmentType" : "";
  const params: Record<string, string | number> = {
    schoolId,
    assessmentModelVersion,
  };
  if (assessmentType) params.assessmentType = assessmentType;

  const rows = db
    .prepare(
      `
      SELECT
        ar.learner_uid AS learnerUid,
        COALESCE(lr.full_name, ar.child_name) AS learnerName,
        COALESCE(lr.gender, ar.gender) AS gender,
        COALESCE(lr.class_grade, ar.class_grade) AS classGrade,
        ar.assessment_type AS assessmentType,
        ar.assessment_date AS assessmentDate,
        ar.reading_stage_label AS readingStageLabel,
        ar.benchmark_grade_level AS benchmarkGradeLevel,
        ar.expected_vs_actual_status AS expectedVsActualStatus,
        ar.stage_reason_summary AS stageReasonSummary,
        ar.phonemic_awareness_mastery_status AS phonemicAwarenessStatus,
        ar.grapheme_phoneme_correspondence_mastery_status AS graphemePhonemeCorrespondenceStatus,
        ar.blending_decoding_mastery_status AS blendingDecodingStatus,
        ar.word_recognition_fluency_mastery_status AS wordRecognitionFluencyStatus,
        ar.sentence_paragraph_construction_mastery_status AS sentenceParagraphConstructionStatus,
        ar.comprehension_mastery_status AS comprehensionStatus
      FROM assessment_records ar
      LEFT JOIN learner_roster lr
        ON lr.learner_uid = ar.learner_uid
      WHERE ar.school_id = @schoolId
        AND ar.model_version = @assessmentModelVersion
        ${typeCond}
      ORDER BY COALESCE(lr.full_name, ar.child_name), ar.assessment_date DESC
    `,
    )
    .all(params) as Array<{
      learnerUid: string;
      learnerName: string;
      gender: string;
      classGrade: string;
      assessmentType: string;
      assessmentDate: string;
      readingStageLabel: string | null;
      benchmarkGradeLevel: string | null;
      expectedVsActualStatus: string | null;
      stageReasonSummary: string | null;
      phonemicAwarenessStatus: string | null;
      graphemePhonemeCorrespondenceStatus: string | null;
      blendingDecodingStatus: string | null;
      wordRecognitionFluencyStatus: string | null;
      sentenceParagraphConstructionStatus: string | null;
      comprehensionStatus: string | null;
    }>;

  return rows.map((row) => {
    const statuses = {
      phonemic_awareness: normalizeMasteryStatus(row.phonemicAwarenessStatus) ?? undefined,
      grapheme_phoneme_correspondence:
        normalizeMasteryStatus(row.graphemePhonemeCorrespondenceStatus) ?? undefined,
      blending_decoding: normalizeMasteryStatus(row.blendingDecodingStatus) ?? undefined,
      word_recognition_fluency:
        normalizeMasteryStatus(row.wordRecognitionFluencyStatus) ?? undefined,
      sentence_paragraph_construction:
        normalizeMasteryStatus(row.sentenceParagraphConstructionStatus) ?? undefined,
      comprehension: normalizeMasteryStatus(row.comprehensionStatus) ?? undefined,
    };
    const domainStatuses = {
      phonemicAwareness:
        statuses.phonemic_awareness ?? "red",
      graphemePhonemeCorrespondence:
        statuses.grapheme_phoneme_correspondence ?? "red",
      blendingDecoding:
        statuses.blending_decoding ?? "red",
      wordRecognitionFluency:
        statuses.word_recognition_fluency ?? "red",
      sentenceParagraphConstruction:
        statuses.sentence_paragraph_construction ?? "red",
      comprehension:
        statuses.comprehension ?? "red",
    };

    const readingStageLabel = String(row.readingStageLabel ?? "").trim() || "Pre-Reader";
    const benchmarkGradeLevel = String(row.benchmarkGradeLevel ?? "").trim() || "Data not available";
    const expectedVsActualStatus =
      String(row.expectedVsActualStatus ?? "").trim() || "Data not available";
    const stageReasonSummary = String(row.stageReasonSummary ?? "").trim() || "Data not available";

    let recommendedNextAction = "Continue progression and monitor developing domains.";
    if (
      domainStatuses.phonemicAwareness === "red" ||
      domainStatuses.graphemePhonemeCorrespondence === "red" ||
      domainStatuses.blendingDecoding === "red"
    ) {
      recommendedNextAction = "Urgent foundational intervention (phonemic/phonics/decoding catch-up).";
    } else if (domainStatuses.wordRecognitionFluency === "amber") {
      recommendedNextAction = "Fluency strengthening (speed and automaticity practice).";
    } else if (
      domainStatuses.blendingDecoding === "green" &&
      domainStatuses.comprehension !== "green"
    ) {
      recommendedNextAction = "Comprehension instruction focus (meaning-making and recall).";
    } else if (
      domainStatuses.phonemicAwareness === "green" &&
      domainStatuses.graphemePhonemeCorrespondence === "green" &&
      domainStatuses.blendingDecoding === "green" &&
      domainStatuses.comprehension === "green"
    ) {
      recommendedNextAction = "Progressing / Graduation prep support.";
    }

    return {
      learnerUid: row.learnerUid,
      learnerName: row.learnerName,
      gender: row.gender,
      classGrade: row.classGrade,
      assessmentType: row.assessmentType,
      assessmentDate: row.assessmentDate,
      readingStageLabel,
      benchmarkGradeLevel,
      expectedVsActualStatus,
      stageReasonSummary,
      recommendedNextAction,
      ...domainStatuses,
    };
  });
}

