export function logAuditEvent(
  userId: number,
  userName: string,
  action: string,
  targetTable: string,
  targetId: number | string | null = null,
  payloadBefore: string | null = null,
  payloadAfter: string | null = null,
  detail: string | null = null,
  ipAddress: string | null = null,
): AuditLogEntry {
  const result = getDb()
    .prepare(
      `INSERT INTO audit_logs (user_id, user_name, action, target_table, target_id, payload_before, payload_after, detail, ip_address)
       VALUES (@userId, @userName, @action, @targetTable, @targetId, @payloadBefore, @payloadAfter, @detail, @ipAddress)`,
    )
    .run({
      userId,
      userName,
      action,
      targetTable,
      targetId,
      payloadBefore,
      payloadAfter,
      detail,
      ipAddress,
    });

  return {
    id: Number(result.lastInsertRowid),
    userId,
    userName,
    action,
    targetTable,
    targetId,
    payloadBefore,
    payloadAfter,
    detail,
    ipAddress,
    timestamp: new Date().toISOString(),
  };
}

export function listAuditLogs(options?: {
  userId?: number;
  targetTable?: string;
  limit?: number;
}): AuditLogEntry[] {
  const conditions: string[] = [];
  const params: Record<string, unknown> = {};

  if (options?.userId) {
    conditions.push("user_id = @userId");
    params.userId = options.userId;
  }
  if (options?.targetTable) {
    conditions.push("target_table = @targetTable");
    params.targetTable = options.targetTable;
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
  const limit = Math.min(options?.limit ?? 100, 500);

  return getDb()
    .prepare(
      `SELECT id, user_id AS userId, user_name AS userName, action, target_table AS targetTable,
              target_id AS targetId, detail, ip_address AS ipAddress, created_at AS timestamp
       FROM audit_logs ${where}
       ORDER BY created_at DESC
       LIMIT ${limit}`,
    )
    .all(params) as AuditLogEntry[];
}

